// NURS 1000 Exam 3 — 500 Question Bank
// Sections: DC=Dosage Calc, GS=General Survey, PS=Preventive Screenings,
// HE=HEENT, NE=Neuro/CN, CV=Cardiovascular, RE=Respiratory,
// MS=Musculoskeletal, GI=GI/GU, IN=Integumentary

const S={DC:"Dosage Calculation",GS:"General Survey & Health History",PS:"Preventive Screenings",HE:"HEENT",NE:"Neurological & Cranial Nerves",CV:"Cardiovascular",RE:"Respiratory",MS:"Musculoskeletal",GI:"GI/GU",IN:"Integumentary"};

const R=[
// === DOSAGE CALCULATION (1-35) ===
{id:1,s:"DC",t:"mc",q:"A patient weighs 176 lbs. The order reads 'Give 5 mg/kg IV once.' How many mg should the nurse administer?",o:["880 mg","400 mg","193.6 mg","1,936 mg"],c:[1],e:"176 lbs ÷ 2.2 = 80 kg × 5 mg/kg = 400 mg. Option A multiplies lbs × 5 without converting — a critical error. Always convert lbs→kg first by dividing by 2.2.",a:"B) 400 mg",r:"Sec 1: Weight/Mass Conversions"},
{id:2,s:"DC",t:"mc",q:"A physician orders 2 teaspoons of liquid amoxicillin PO q8h. How many mL per dose?",o:["15 mL","30 mL","5 mL","10 mL"],c:[3],e:"1 tsp = 5 mL, so 2 tsp = 10 mL. Option A (15 mL) is 1 Tbsp — common tsp/Tbsp confusion. Option B (30 mL) = 1 oz. Option C = only 1 tsp.",a:"D) 10 mL",r:"Sec 1: Volume/Liquid"},
{id:3,s:"DC",t:"fib",q:"A patient's oral temp reads 101.3°F. Convert to Celsius (round to one decimal).",o:[],c:["38.5"],e:"(101.3 − 32) × 5/9 = 69.3 × 0.5556 = 38.5°C. Normal oral = 98.6°F/37°C. This patient has a low-grade fever.",a:"38.5°C",r:"Sec 1: Temperature"},
{id:4,s:"DC",t:"mc",q:"An order reads 0.25 mg PO daily. How many micrograms (mcg)?",o:["25 mcg","2,500 mcg","250 mcg","0.025 mcg"],c:[2],e:"1 mg = 1,000 mcg. 0.25 mg × 1,000 = 250 mcg. Option B is a 10-fold error. RED FLAG: mcg vs mg confusion causes 10-fold dosing errors.",a:"C) 250 mcg",r:"Sec 1: Weight/Mass"},
{id:5,s:"DC",t:"mc",q:"A patient drinks 1.5 cups of water with medications. Document intake as how many mL?",o:["180 mL","240 mL","360 mL","473 mL"],c:[2],e:"1 cup = 240 mL. 1.5 × 240 = 360 mL. Option D = 1 pint (473 mL). Accurate I&O requires knowing volume conversions.",a:"C) 360 mL",r:"Sec 1: Volume/Liquid"},
{id:6,s:"DC",t:"tf",q:"True or False: Dimensional analysis requires writing the desired unit on top, canceling units systematically, and double-checking the answer.",o:["True","False"],c:[0],e:"True. Dimensional analysis is the safest calculation method — systematic unit cancellation reduces errors. Strongly recommended for NCLEX.",a:"True",r:"Sec 1: Dimensional Analysis"},
{id:7,s:"DC",t:"mc",q:"A neonate weighs 3.2 kg. Medication: 10 mg/kg/day divided into 2 doses. How many mg per dose?",o:["32 mg","16 mg","64 mg","6.4 mg"],c:[1],e:"3.2 kg × 10 mg/kg/day = 32 mg/day ÷ 2 doses = 16 mg per dose. Option A is total daily dose, not per dose.",a:"B) 16 mg",r:"Sec 1: Weight-Based Dosing"},
{id:8,s:"DC",t:"mc",q:"Convert 2 Tablespoons to mL.",o:["10 mL","15 mL","30 mL","60 mL"],c:[2],e:"1 Tbsp = 15 mL. 2 Tbsp = 30 mL. Option A confuses tsp math. Option B = 1 Tbsp. 1 Tbsp = 3 tsp = 15 mL.",a:"C) 30 mL",r:"Sec 1: Volume/Liquid"},
{id:9,s:"DC",t:"mc",q:"A patient weighs 220 lbs. What is this in kg?",o:["100 kg","110 kg","48.4 kg","484 kg"],c:[0],e:"220 ÷ 2.2 = 100 kg. Option B adds instead of dividing. Option C divides lbs by an incorrect factor. Always divide lbs by 2.2 to get kg.",a:"A) 100 kg",r:"Sec 1: Weight/Mass"},
{id:10,s:"DC",t:"mc",q:"An order reads: give 500 mg. Available: tablets labeled 250 mg each. How many tablets?",o:["0.5 tablet","1 tablet","2 tablets","4 tablets"],c:[2],e:"500 mg ÷ 250 mg/tab = 2 tablets. Simple desired-over-have calculation. Always verify that splitting tablets is appropriate when the answer is less than 1.",a:"C) 2 tablets",r:"Sec 1: Dosage Calc"},
{id:11,s:"DC",t:"mc",q:"1 grain (gr) is approximately equal to how many milligrams?",o:["10 mg","30 mg","60-65 mg","100 mg"],c:[2],e:"1 grain = approximately 60–65 mg. This is a commonly tested conversion, especially for medications like aspirin (historically dosed in grains).",a:"C) 60-65 mg",r:"Sec 1: Weight/Mass"},
{id:12,s:"DC",t:"fib",q:"Convert 39°C to Fahrenheit (round to one decimal).",o:[],c:["102.2"],e:"°C × 9/5 + 32 = 39 × 1.8 + 32 = 70.2 + 32 = 102.2°F. This indicates a significant fever requiring intervention.",a:"102.2°F",r:"Sec 1: Temperature"},
{id:13,s:"DC",t:"mc",q:"A patient has an intake of 1 pint of juice plus 2 cups of water. Total intake in mL?",o:["713 mL","953 mL","480 mL","946 mL"],c:[1],e:"1 pint = 473 mL + 2 cups (2 × 240 = 480 mL) = 953 mL. Option D is 1 quart. Accurate I&O tracking is critical for fluid balance assessment.",a:"B) 953 mL",r:"Sec 1: Volume/Liquid"},
{id:14,s:"DC",t:"mc",q:"A child weighs 44 lbs. The provider orders 15 mg/kg/day in 3 divided doses. What is each dose?",o:["100 mg","220 mg","300 mg","660 mg"],c:[0],e:"44 lbs ÷ 2.2 = 20 kg. 20 × 15 = 300 mg/day. 300 ÷ 3 = 100 mg per dose. Option C is the total daily dose. Always convert lbs→kg first.",a:"A) 100 mg",r:"Sec 1: Weight-Based Dosing"},
{id:15,s:"DC",t:"mc",q:"The nurse needs to give 750 mcg. Available: 0.5 mg tablets. How many tablets?",o:["0.5 tablet","1 tablet","1.5 tablets","2 tablets"],c:[2],e:"First convert: 750 mcg = 0.75 mg. Then 0.75 mg ÷ 0.5 mg/tab = 1.5 tablets. Must convert mcg→mg before calculating. RED FLAG: unit mismatch errors.",a:"C) 1.5 tablets",r:"Sec 1: Weight/Mass + Dosage Calc"},
{id:16,s:"DC",t:"mc",q:"1 quart equals approximately how many mL?",o:["240 mL","473 mL","946 mL","1,000 mL"],c:[2],e:"1 quart = 946 mL. 1 cup = 240 mL, 1 pint = 473 mL, 1 quart = 946 mL, 1 liter = 1,000 mL. Option D is 1 liter, which is close but not exactly equal to 1 quart.",a:"C) 946 mL",r:"Sec 1: Volume/Liquid"},
{id:17,s:"DC",t:"mc",q:"A patient requires 1,500 mg of a medication. The pharmacy supplies 500 mg/5 mL suspension. How many mL should the nurse give?",o:["5 mL","10 mL","15 mL","30 mL"],c:[2],e:"1,500 mg ÷ 500 mg × 5 mL = 15 mL. Using dimensional analysis: (1500 mg)(5 mL/500 mg) = 15 mL. Always cancel units to verify.",a:"C) 15 mL",r:"Sec 1: Dimensional Analysis"},
{id:18,s:"DC",t:"tf",q:"True or False: A 10-fold dosing error can result from confusing milligrams (mg) with micrograms (mcg).",o:["True","False"],c:[0],e:"True. Since 1 mg = 1,000 mcg, confusing the two can result in giving 1,000 times too much or too little. This is flagged as a RED FLAG in the study guide and is a leading cause of medication errors.",a:"True",r:"Sec 1: RED FLAG — mcg vs mg"},
{id:19,s:"DC",t:"mc",q:"An IV is infusing at 125 mL/hr. How many mL will infuse over 8 hours?",o:["500 mL","750 mL","1,000 mL","1,500 mL"],c:[2],e:"125 mL/hr × 8 hr = 1,000 mL. Simple rate × time calculation. This is essential for I&O monitoring and fluid balance assessment.",a:"C) 1,000 mL",r:"Sec 1: Dosage Calc"},
{id:20,s:"DC",t:"mc",q:"A patient takes 3 teaspoons of Maalox. How many mL is this?",o:["5 mL","10 mL","15 mL","30 mL"],c:[2],e:"1 tsp = 5 mL. 3 × 5 = 15 mL. Note: 15 mL also equals 1 Tablespoon (3 tsp = 1 Tbsp = 15 mL). This conversion is frequently tested.",a:"C) 15 mL",r:"Sec 1: Volume/Liquid"},
{id:21,s:"DC",t:"mc",q:"A nurse must give 0.5 g of cephalexin PO. Available: 250 mg capsules. How many capsules?",o:["0.5 capsule","1 capsule","2 capsules","5 capsules"],c:[2],e:"First convert: 0.5 g = 500 mg (1 g = 1,000 mg). Then 500 mg ÷ 250 mg/cap = 2 capsules. Always convert to the same unit before calculating.",a:"C) 2 capsules",r:"Sec 1: Weight/Mass + Dosage Calc"},
{id:22,s:"DC",t:"mc",q:"A patient's weight is recorded as 91 kg. Convert to pounds.",o:["200.2 lbs","182 lbs","41.4 lbs","202 lbs"],c:[0],e:"91 kg × 2.2 = 200.2 lbs. To convert kg→lbs, multiply by 2.2. To convert lbs→kg, divide by 2.2. Option C divides instead of multiplying.",a:"A) 200.2 lbs",r:"Sec 1: Weight/Mass"},
{id:23,s:"DC",t:"mc",q:"An order reads: morphine 4 mg IV push. Available: 10 mg/mL. How many mL?",o:["0.4 mL","2.5 mL","4 mL","10 mL"],c:[0],e:"4 mg ÷ 10 mg/mL = 0.4 mL. Always double-check high-alert medication doses. Morphine is a controlled substance requiring witness verification at many facilities.",a:"A) 0.4 mL",r:"Sec 1: Dosage Calc"},
{id:24,s:"DC",t:"mc",q:"A patient's temp is 100.4°F. What is this in Celsius?",o:["36.0°C","37.0°C","38.0°C","39.0°C"],c:[2],e:"(100.4 − 32) × 5/9 = 68.4 × 0.5556 = 38.0°C. 100.4°F (38°C) is the threshold commonly used to define a fever in clinical practice.",a:"C) 38.0°C",r:"Sec 1: Temperature"},
{id:25,s:"DC",t:"mc",q:"How many ounces are in 240 mL?",o:["4 oz","6 oz","8 oz","10 oz"],c:[2],e:"1 oz = 30 mL. 240 ÷ 30 = 8 oz. 8 oz also = 1 cup = 240 mL. These are all equivalent measures tested frequently on exams.",a:"C) 8 oz",r:"Sec 1: Volume/Liquid"},
{id:26,s:"DC",t:"mc",q:"A child weighs 22 lbs. The safe dose range is 10-15 mg/kg/day. What is the maximum safe daily dose?",o:["150 mg","220 mg","330 mg","100 mg"],c:[0],e:"22 lbs ÷ 2.2 = 10 kg. Maximum: 10 kg × 15 mg/kg = 150 mg/day. Always calculate both ends of a safe dose range and verify the ordered dose falls within it.",a:"A) 150 mg",r:"Sec 1: Weight-Based Dosing"},
{id:27,s:"DC",t:"mc",q:"The nurse is to administer heparin 8,000 units subQ. Available: 10,000 units/mL. How many mL?",o:["0.8 mL","1.25 mL","8 mL","0.08 mL"],c:[0],e:"8,000 units ÷ 10,000 units/mL = 0.8 mL. Heparin is a high-alert medication. Many facilities require independent double-checks for heparin dosing.",a:"A) 0.8 mL",r:"Sec 1: Dosage Calc"},
{id:28,s:"DC",t:"fib",q:"Convert 95°F to Celsius (round to one decimal).",o:[],c:["35.0"],e:"(95 − 32) × 5/9 = 63 × 0.5556 = 35.0°C. This is below normal (37°C), indicating hypothermia. Normal range is 36.1–37.2°C (97–99°F).",a:"35.0°C",r:"Sec 1: Temperature"},
{id:29,s:"DC",t:"mc",q:"A medication order reads 'give 30 mL PO.' This is equivalent to how many tablespoons?",o:["1 Tbsp","2 Tbsp","3 Tbsp","6 Tbsp"],c:[1],e:"1 Tbsp = 15 mL. 30 mL ÷ 15 mL = 2 Tbsp. Also equivalent to 1 oz or 6 tsp. Patient teaching should include household measurement equivalents.",a:"B) 2 Tbsp",r:"Sec 1: Volume/Liquid"},
{id:30,s:"DC",t:"mc",q:"A patient is prescribed 0.125 mg of digoxin. The pharmacy sends 125 mcg tablets. The nurse should administer:",o:["0.5 tablet","1 tablet","2 tablets","Call pharmacy — dose mismatch"],c:[1],e:"0.125 mg = 125 mcg (multiply by 1,000). The doses are identical, just expressed in different units. This is a common NCLEX trap testing unit conversion knowledge.",a:"B) 1 tablet",r:"Sec 1: Weight/Mass — mcg/mg"},
{id:31,s:"DC",t:"mc",q:"A nurse calculates a dose and gets an answer of 15 tablets. What should the nurse do FIRST?",o:["Give 15 tablets as calculated","Recalculate — 15 tablets is an unusually high number","Call the pharmacy to verify","Crush and mix with applesauce"],c:[1],e:"Any answer that seems unreasonably high (or low) should trigger recalculation. Giving more than 3 tablets typically warrants verification. Critical thinking and dose reasonableness checks prevent errors.",a:"B) Recalculate",r:"Sec 1: Dimensional Analysis"},
{id:32,s:"DC",t:"mc",q:"Convert 2.5 L to mL.",o:["250 mL","2,500 mL","25 mL","25,000 mL"],c:[1],e:"1 L = 1,000 mL. 2.5 × 1,000 = 2,500 mL. This conversion is essential for IV fluid calculations and I&O documentation.",a:"B) 2,500 mL",r:"Sec 1: Volume/Liquid"},
{id:33,s:"DC",t:"mc",q:"A patient weighs 154 lbs. A drug is dosed at 2 mg/kg. The correct dose is:",o:["70 mg","140 mg","154 mg","308 mg"],c:[1],e:"154 lbs ÷ 2.2 = 70 kg. 70 kg × 2 mg/kg = 140 mg. Option C uses lbs instead of kg. Option D multiplies lbs × 2 without converting.",a:"B) 140 mg",r:"Sec 1: Weight-Based Dosing"},
{id:34,s:"DC",t:"mc",q:"Which is the LARGER dose: 500 mcg or 0.25 mg?",o:["500 mcg","0.25 mg","They are equal","Cannot be determined"],c:[0],e:"Convert to same units: 500 mcg = 0.5 mg. 0.5 mg > 0.25 mg. Therefore 500 mcg is the larger dose. Always convert to the same unit before comparing.",a:"A) 500 mcg",r:"Sec 1: Weight/Mass"},
{id:35,s:"DC",t:"mc",q:"A provider orders 1 oz of Milk of Magnesia. The nurse should give:",o:["5 mL","15 mL","30 mL","60 mL"],c:[2],e:"1 oz = 30 mL. This is a fundamental liquid conversion. 1 oz = 2 Tbsp = 6 tsp = 30 mL.",a:"C) 30 mL",r:"Sec 1: Volume/Liquid"},
// === GENERAL SURVEY & HEALTH HISTORY (36-110) ===
{id:36,s:"GS",t:"sata",q:"Which observations are part of the general survey? (Select All That Apply)",o:["Auscultating heart sounds","Noting apparent age vs stated age","Observing fruity breath odor","Assessing gait","Percussing the abdomen"],c:[1,2,3],e:"General survey is done BEFORE touching — visual/olfactory only. It includes apparent age (B), body odors (C), and gait (D). Auscultation (A) and percussion (E) require instruments and contact.",a:"B, C, D",r:"Sec 2: General Survey"},
{id:37,s:"GS",t:"mc",q:"A patient says 'I've been dizzy lately.' The BEST therapeutic response is:",o:["\"Don't worry, dizziness is common.\"","\"Why do you think you're dizzy?\"","\"Can you describe what you mean by dizzy — spinning or lightheaded?\"","\"You should stop your BP medication.\""],c:[2],e:"Option C uses clarification — asking the patient to define vague terms. A = false reassurance. B = 'why' question (judgmental). D = giving unwanted medical advice.",a:"C",r:"Sec 2: Therapeutic Communication"},
{id:38,s:"GS",t:"mc",q:"Which task can the nurse delegate to a CNA?",o:["Assess skin integrity of a new pressure ulcer","Obtain vital signs on a stable post-op patient","Determine if Foley output is adequate","Evaluate response to pain medication"],c:[1],e:"Obtaining VS on a stable patient is routine with predictable outcomes. All other options require nursing ASSESSMENT and clinical judgment. CNAs cannot assess, interpret, or evaluate.",a:"B",r:"Sec 2: Delegation Rules"},
{id:39,s:"GS",t:"mc",q:"An 82-year-old with pneumonia has no fever but is acutely confused. The BEST interpretation is:",o:["Expected confusion in elderly","Likely sundowning","Acute confusion may be the primary sign of infection in older adults — escalate","Reorient and reassess in 4 hours"],c:[2],e:"Older adults often present atypically. Infection may NOT produce fever — confusion or acute functional decline may be the presenting sign. This is a RED FLAG requiring immediate escalation.",a:"C",r:"Sec 2: Older Adults"},
{id:40,s:"GS",t:"mc",q:"A patient's primary language is Mandarin. The daughter offers to interpret. The nurse should:",o:["Accept — she knows the patient best","Speak slowly and loudly","Request a certified medical interpreter","Use hand gestures"],c:[2],e:"A certified medical interpreter is required. Family members may filter, omit, or alter sensitive information. Speaking loudly doesn't overcome a language barrier.",a:"C",r:"Sec 2: Cultural Sensitivity"},
{id:41,s:"GS",t:"order",q:"Place comprehensive physical assessment techniques in correct order.",o:["Auscultation","Palpation","Inspection","Percussion","Olfaction"],c:[2,1,3,0,4],e:"Inspection → Palpation → Percussion → Auscultation → Olfaction. Mnemonic: 'I Palpate Patients Always Openly.' Inspection is always first (noninvasive). Exception: abdomen — auscultate before percuss/palpate.",a:"Inspection→Palpation→Percussion→Auscultation→Olfaction",r:"Sec 2: Assessment Order"},
{id:42,s:"GS",t:"mc",q:"An ammonia-like odor from a patient during general survey is MOST consistent with:",o:["DKA","Pseudomonas infection","Renal failure","Infected cast"],c:[2],e:"Ammonia = renal failure (urea→ammonia). Sweet/fruity = DKA. Heavy sweet wound = Pseudomonas. Musky under cast = cast infection. Body odor assessment provides critical clinical clues.",a:"C) Renal failure",r:"Sec 2: General Survey — Body Odor"},
{id:43,s:"GS",t:"mc",q:"Which health history component should be collected FIRST?",o:["Chief complaint","Family history","Biographical data","Present illness"],c:[2],e:"Biographical data is ALWAYS first — name, DOB, address, emergency contact, PCP, advanced directives. It establishes identity and information source before exploring the chief complaint.",a:"C) Biographical data",r:"Sec 2: Health History Components"},
{id:44,s:"GS",t:"mc",q:"A patient says 'I'm scared about surgery tomorrow.' The BEST empathetic response is:",o:["\"Everything will be fine.\"","\"You shouldn't be scared.\"","\"It's understandable to feel scared. This must be stressful.\"","\"Why are you scared?\""],c:[2],e:"Empathy acknowledges emotions without judgment. A = false reassurance. B = dismissive. D = 'why' question. Empathetic responses validate experience and build rapport.",a:"C",r:"Sec 2: Therapeutic Communication — Empathy"},
{id:45,s:"GS",t:"tf",q:"True or False: For abdominal assessment, auscultate BEFORE palpating to avoid altering bowel sounds.",o:["True","False"],c:[0],e:"True. Abdominal order: Inspect→Auscultate→Percuss→Palpate. Palpation stimulates bowel activity, altering auscultation accuracy. This is the ONE exception to standard order.",a:"True",r:"Sec 2: Abdominal Assessment Exception"},
{id:46,s:"GS",t:"mc",q:"Which hand surface is BEST for assessing skin temperature?",o:["Fingertips","Palm","Pads of fingers","Dorsum (back) of hand"],c:[3],e:"The dorsum has thinner skin, making it most sensitive to temperature. Finger pads are best for pulses. Fingertips for percussion. This is a commonly tested distinction.",a:"D) Dorsum",r:"Sec 2: Palpation"},
{id:47,s:"GS",t:"mc",q:"'Patient reports headaches for 2 weeks, worse in the morning.' This belongs in which history section?",o:["Biographical data","Chief complaint","Family history","Psychosocial history"],c:[1],e:"The chief complaint documents the reason for seeking care — patient's words, symptom onset, and impact on daily life. Biographical data = demographics. Family hx = hereditary conditions.",a:"B) Chief complaint",r:"Sec 2: Health History — Chief Complaint"},
{id:48,s:"GS",t:"sata",q:"Which are therapeutic communication techniques to USE? (SATA)",o:["Silence","Leading questions","Reflection","Confrontation","Giving personal advice"],c:[0,2,3],e:"Silence (time to think), Reflection (repeating key words), and Confrontation (pointing out discrepancies gently) are all approved techniques. Leading questions and personal advice should be AVOIDED.",a:"A, C, D",r:"Sec 2: Therapeutic Communication"},
{id:49,s:"GS",t:"mc",q:"A patient appears anxious and wrings their hands. This observation relates to which general survey component?",o:["Level of consciousness","Affect and mood","Gait assessment","Body type"],c:[1],e:"Affect and mood includes observing anxiety, flat affect, tearfulness, or agitation. Hand-wringing = behavioral anxiety indicator. LOC = alertness/orientation. Gait = walking patterns.",a:"B) Affect and mood",r:"Sec 2: General Survey"},
{id:50,s:"GS",t:"mc",q:"A patient becomes defensive about tobacco/alcohol questions. The BEST action is:",o:["Skip the questions","Tell them they must answer for legal reasons","Create a non-judgmental space and explain clinical importance","Ask a family member instead"],c:[2],e:"Substance use data is essential for safe care (drug interactions, anesthesia risks). Create a safe environment and explain why. Never skip, demand, or violate confidentiality by asking family.",a:"C",r:"Sec 2: Functional Assessment — Substance Use"},
{id:51,s:"GS",t:"mc",q:"The nurse starts an interview by saying 'Hi, I'm Sarah, I'll be your nurse today.' What should the nurse do NEXT?",o:["Begin the physical exam","Explain what will be done, why, and what to expect","Ask the chief complaint immediately","Review the chart out loud"],c:[1],e:"After introducing yourself with name AND role, explain what you're doing, why, and what the patient can expect. Then confirm the patient can hear and understand before proceeding.",a:"B",r:"Sec 2: Interviewing Technique"},
{id:52,s:"GS",t:"mc",q:"A patient's LOC is described as 'alert and oriented ×4.' This means the patient is oriented to:",o:["Person, place, time","Person, place, time, situation","Name, date, location","Person, time, event, diagnosis"],c:[1],e:"Oriented ×4 = Person, Place, Time, Situation. ×3 = person, place, time. ×2 = person, place. ×1 = person only. Always document the specific level of orientation.",a:"B) Person, place, time, situation",r:"Sec 2: General Survey — LOC"},
{id:53,s:"GS",t:"mc",q:"Which nursing action during assessment demonstrates efficiency and patient-centered care?",o:["Complete all assessments before providing any care","Assess skin integrity while giving a bath","Wait for the provider to order all assessments","Delegate all assessments to the CNA"],c:[1],e:"Pairing routine nursing care with assessments (checking skin during bath, assessing gait during ambulation) is efficient and patient-centered. It minimizes disruption while gathering data.",a:"B",r:"Sec 2: NOTE — Pair routine care with assessment"},
{id:54,s:"GS",t:"mc",q:"When documenting allergies, the nurse should record:",o:["Only medication allergies","The allergen name only","The allergen and the type of reaction (hives vs anaphylaxis)","Allergies only if they're life-threatening"],c:[2],e:"Document the allergen AND the reaction type. Distinguishing between hives (mild) and anaphylaxis (life-threatening) determines the severity level and guides future treatment decisions.",a:"C",r:"Sec 2: Health History — Allergies"},
{id:55,s:"GS",t:"mc",q:"The nurse is using confrontation during an interview: 'You say you don't smoke, but your chart shows a pack-per-day history.' This technique is used to:",o:["Punish the patient for lying","Gently point out discrepancies in information","Force the patient to comply","Document non-compliance"],c:[1],e:"Confrontation in therapeutic communication means gently pointing out inconsistencies — not punishment or aggression. It opens dialogue about discrepancies to get accurate information.",a:"B",r:"Sec 2: Therapeutic Communication — Confrontation"},
{id:56,s:"GS",t:"mc",q:"An advanced directive document such as a DNR should be collected during which part of the health history?",o:["Chief complaint","Biographical data","Family history","Psychosocial history"],c:[1],e:"Advanced directives (DNR, healthcare proxy) are collected during biographical data — ALWAYS the first section. This ensures end-of-life wishes are documented before any clinical assessment.",a:"B) Biographical data",r:"Sec 2: Health History — Biographical Data"},
{id:57,s:"GS",t:"tf",q:"True or False: CNAs and UAPs can interpret vital signs and determine their clinical significance.",o:["True","False"],c:[1],e:"False. CNAs/UAPs can REPORT vital signs but CANNOT interpret them or determine clinical significance. A CNA cannot determine if a BP is dangerously high — that requires nursing assessment and judgment.",a:"False",r:"Sec 2: RED FLAG — Delegation"},
{id:58,s:"GS",t:"mc",q:"The BEST position for the nurse during a patient interview is:",o:["Standing over the patient","At eye level, 2-4 feet from the patient","Behind a desk with the computer","At the foot of the bed"],c:[1],e:"Position at eye level, 2-4 feet from the patient, in a private/comfortable/quiet setting. Standing over the patient is intimidating. A desk creates a barrier. The foot of the bed is too far.",a:"B",r:"Sec 2: Interviewing Technique"},
{id:59,s:"GS",t:"mc",q:"When assessing an older adult, the nurse should plan the exam to:",o:["Move quickly to prevent fatigue","Keep position changes to a minimum considering energy level","Skip the mental status exam since confusion is expected","Use medical jargon to be efficient"],c:[1],e:"Allow extra time, be patient and unhurried, and minimize position changes to conserve energy. Never assume confusion is normal — always include mental status review. Avoid jargon with all patients.",a:"B",r:"Sec 2: Older Adults"},
{id:60,s:"GS",t:"mc",q:"A Jehovah's Witness patient is admitted. The nurse should anticipate that this patient may:",o:["Refuse all medications","Refuse blood transfusions","Refuse surgery of any kind","Refuse to speak with healthcare providers"],c:[1],e:"Jehovah's Witnesses may refuse blood transfusions based on religious beliefs. Always document and communicate to the care team. They generally accept other medical treatments. Avoid stereotyping.",a:"B) Refuse blood transfusions",r:"Sec 2: Cultural Sensitivity"},
{id:61,s:"GS",t:"mc",q:"Which assessment technique uses the stethoscope diaphragm?",o:["Low-pitched heart murmurs","Vascular bruits","High-pitched sounds like bowel and lung sounds","Temperature assessment"],c:[2],e:"Diaphragm = high-pitched sounds (bowel sounds, lung sounds, normal heart sounds). Bell = low-pitched sounds (murmurs, bruits). Always place stethoscope on BARE SKIN, never over clothing.",a:"C) High-pitched sounds",r:"Sec 2: Auscultation"},
{id:62,s:"GS",t:"mc",q:"The nurse notes sweet/fruity breath during the general survey. This is MOST consistent with:",o:["Renal failure","Pseudomonas infection","Diabetic ketoacidosis (DKA)","GERD"],c:[2],e:"Sweet/fruity breath = DKA. The body produces ketones when it cannot use glucose, and these are exhaled. Associated with Kussmaul respirations. Ammonia = renal failure. Heavy sweet wound = Pseudomonas.",a:"C) DKA",r:"Sec 2: General Survey — Body Odor"},
{id:63,s:"GS",t:"mc",q:"In an acute/emergency setting, the nurse should:",o:["Complete a full comprehensive assessment before any treatment","Focus assessment on the affected body system, then comprehensive once stabilized","Skip the assessment and begin treatment immediately","Only assess vital signs"],c:[1],e:"In acute/emergency settings, focus on the affected system first. Once the patient is stabilized, complete the full comprehensive assessment. NCLEX TIP: Prioritize the immediate threat.",a:"B",r:"Sec 2: NCLEX TIP — Acute Assessment"},
{id:64,s:"GS",t:"mc",q:"The nurse asks a summary question: 'So today you reported chest pain that started 3 days ago and is worse with activity. Is that correct?' This technique is:",o:["Clarification","Facilitation","Summary","Interpretation"],c:[2],e:"Summary recaps the information gathered at the end of the interview to verify accuracy. Clarification asks for meaning. Facilitation encourages continued talking. Interpretation shares your understanding.",a:"C) Summary",r:"Sec 2: Therapeutic Communication — Summary"},
{id:65,s:"GS",t:"mc",q:"Which question should the nurse AVOID during an interview?",o:["'What led you to come to the hospital today?'","'Why did you stop taking your medication?'","'Can you tell me more about your symptoms?'","'When did the pain begin?'"],c:[1],e:"'Why' questions sound judgmental and put patients on the defensive. Rephrase as 'What led you to stop your medication?' to gather the same information without judgment.",a:"B) 'Why' question",r:"Sec 2: Techniques to AVOID"},
{id:66,s:"GS",t:"mc",q:"During palpation, the nurse uses light palpation first, then deep palpation. Deep palpation is used primarily for:",o:["Assessing skin temperature","Organ assessment","Pulse detection","Skin turgor"],c:[1],e:"Deep palpation assesses organ size, location, and tenderness. Light palpation comes first to detect surface abnormalities and tenderness before going deeper. Never start with deep palpation.",a:"B) Organ assessment",r:"Sec 2: Palpation"},
{id:67,s:"GS",t:"mc",q:"An older adult with an MI may NOT report chest pain. Instead, they may present with:",o:["Classic crushing chest pain radiating to the left arm","Fatigue or shortness of breath only","Fever and chills","Nausea and projectile vomiting"],c:[1],e:"Older adults often present atypically. An MI may present as fatigue, SOB, or confusion — NOT classic chest pain. This is a RED FLAG example of blunted/absent classic symptoms in the elderly.",a:"B) Fatigue or SOB",r:"Sec 2: Older Adults — Atypical Presentation"},
{id:68,s:"GS",t:"mc",q:"Which percussion finding over the lungs would indicate pneumonia?",o:["Resonance","Hyperresonance","Dullness","Flatness"],c:[2],e:"Resonance = normal lung sound. Dullness indicates fluid/consolidation (pneumonia, pleural effusion). Hyperresonance = excess air (pneumothorax, emphysema). Flatness = solid tissue (bone, muscle).",a:"C) Dullness",r:"Sec 2: Percussion"},
{id:69,s:"GS",t:"mc",q:"The nurse is assessing a patient who uses a hearing aid. Before beginning the interview, the nurse should:",o:["Remove the hearing aid for the assessment","Confirm the hearing aid is functioning and the patient can hear","Speak directly into the bad ear","Document hearing loss and skip the interview"],c:[1],e:"Always confirm the patient can hear and understand you. Check that hearing aids are in and batteries are working. RED FLAG: Don't confuse hearing difficulty with confusion — check hearing aids first.",a:"B",r:"Sec 2: Interviewing Technique"},
{id:70,s:"GS",t:"sata",q:"Which are components of biographical data? (SATA)",o:["Full name and address","Chief complaint","Advanced directives","Emergency contact","Current medications"],c:[0,2,3],e:"Biographical data includes: name, address, phone, age, DOB, gender, marital status, religion, nationality, emergency contact, PCP, and advanced directives. Chief complaint and medications are separate sections.",a:"A, C, D",r:"Sec 2: Health History — Biographical Data"},
{id:71,s:"GS",t:"mc",q:"The purpose of a health assessment includes all EXCEPT:",o:["Establish baseline health status","Identify nursing diagnoses","Make medical diagnoses","Evaluate outcomes of nursing care"],c:[2],e:"Health assessment identifies NURSING diagnoses, not medical diagnoses. Medical diagnoses are made by physicians/providers. The assessment establishes baselines, confirms nursing diagnoses, and evaluates care outcomes.",a:"C) Make medical diagnoses",r:"Sec 2: Purpose of Health Assessment"},
{id:72,s:"GS",t:"mc",q:"A task CAN be delegated to a CNA if all conditions are met EXCEPT:",o:["The patient is medically stable","The task has a predictable outcome","The task requires nursing judgment","The delegatee knows agency policies"],c:[2],e:"A task requiring nursing judgment CANNOT be delegated. Delegation criteria: nurse assessed first, task is routine with predictable outcome, patient is stable, no substantial scientific knowledge needed, and the delegatee is competent.",a:"C",r:"Sec 2: Delegation Rules"},
{id:73,s:"GS",t:"mc",q:"The nurse nods and says 'go on, tell me more' while a patient describes symptoms. This technique is:",o:["Empathy","Facilitation","Confrontation","Clarification"],c:[1],e:"Facilitation includes nodding, 'go on,' 'tell me more,' 'uh-huh' — encourages the patient to continue talking without interrupting their thought process.",a:"B) Facilitation",r:"Sec 2: Therapeutic Communication — Facilitation"},
{id:74,s:"GS",t:"mc",q:"A patient uses herbal supplements. The nurse should:",o:["Tell the patient to stop all herbs immediately","Document the supplements and assess for drug interactions","Ignore herbs since they are natural and safe","Report the patient to the provider for non-compliance"],c:[1],e:"Document all herbal/dietary supplements and assess for potential drug interactions. Many herbs interact with medications (e.g., St. John's wort with SSRIs, garlic with anticoagulants). Never dismiss or ignore them.",a:"B",r:"Sec 2: Cultural Sensitivity — Alternative Medicine"},
{id:75,s:"GS",t:"mc",q:"Family history is important because it identifies risk for hereditary conditions. Which conditions should be screened? (Select the BEST answer)",o:["Only cancer","Heart disease, diabetes, HTN, cancer, sickle cell, hemophilia, glaucoma, cataracts","Only conditions the patient asks about","Conditions that have a cure"],c:[1],e:"Family history should screen for all hereditary conditions including heart disease, diabetes, HTN, cancer, sickle cell anemia, hemophilia, glaucoma, and cataracts. Document parents and siblings — alive/deceased with cause of death.",a:"B",r:"Sec 2: Health History — Family History"},
{id:76,s:"GS",t:"mc",q:"A nurse says to a patient: 'It sounds like the pain is worse at night.' This is an example of:",o:["Reflection","Interpretation","Summary","Confrontation"],c:[1],e:"Interpretation shares the nurse's understanding of what the patient said. Reflection repeats key words. Summary recaps the entire interview. Confrontation points out discrepancies.",a:"B) Interpretation",r:"Sec 2: Therapeutic Communication — Interpretation"},
{id:77,s:"GS",t:"mc",q:"During inspection, the nurse should ensure:",o:["The room is dimly lit for patient comfort","Adequate lighting to note size, symmetry, shape, color, and abnormalities","Only the anterior body is assessed","The patient remains fully clothed"],c:[1],e:"Adequate lighting is essential for inspection. Note size, symmetry, shape, color, position, and abnormalities. Always compare left to right side. Inspection is primarily visual and should precede all other techniques.",a:"B",r:"Sec 2: Inspection"},
{id:78,s:"GS",t:"mc",q:"Which statement about LPNs (PNs) and the nursing process is correct?",o:["LPNs can independently make nursing diagnoses","LPNs assist the RN with data collection; diagnosis and judgment remain with the RN","LPNs can delegate to RNs","LPNs function identically to RNs"],c:[1],e:"LPNs assist the RN by helping with data collection, but clinical judgment, nursing diagnosis, and care planning remain with the RN. LPNs work under RN supervision.",a:"B",r:"Sec 2: NOTE — PNs/LPNs"},
{id:79,s:"GS",t:"mc",q:"A musky odor detected under a patient's cast suggests:",o:["Normal perspiration","Infection under the cast","Renal failure","DKA"],c:[1],e:"Musky odor under a cast = infection. The cast creates a warm, moist environment conducive to bacterial growth. Report to HCP for further assessment — the cast may need to be windowed or removed.",a:"B) Infection under cast",r:"Sec 2: General Survey — Body Odor"},
{id:80,s:"GS",t:"mc",q:"The functional assessment/ADLs section of the health history includes all EXCEPT:",o:["Diet and nutritional habits","Sleep patterns","Parents' cause of death","Tobacco, alcohol, and drug use"],c:[2],e:"Parents' cause of death belongs in Family History, not Functional Assessment. ADLs cover diet, elimination, exercise, sleep, work, leisure, substance use, and religious observances.",a:"C) Parents' cause of death",r:"Sec 2: Functional Assessment vs Family History"},
{id:81,s:"GS",t:"mc",q:"'Everything will be fine' is an example of which communication technique to AVOID?",o:["Leading questions","False reassurance","Using authority","Empathy"],c:[1],e:"False reassurance sets unrealistic expectations and dismisses the patient's concerns. It is NOT therapeutic. Instead, use empathy to acknowledge feelings while providing honest information.",a:"B) False reassurance",r:"Sec 2: Techniques to AVOID"},
{id:82,s:"GS",t:"mc",q:"The stethoscope bell is BEST for hearing:",o:["Bowel sounds","Normal lung sounds","Low-pitched heart murmurs and vascular sounds","High-pitched wheezing"],c:[2],e:"Bell = low-pitched sounds (heart murmurs, bruits, vascular sounds). Diaphragm = high-pitched sounds (bowel, lung, S1/S2). Press the bell lightly — pressing too hard stretches the skin into a diaphragm.",a:"C) Low-pitched murmurs and vascular sounds",r:"Sec 2: Auscultation"},
{id:83,s:"GS",t:"mc",q:"The nurse pads of the fingers are most sensitive for detecting:",o:["Temperature","Pulses","Crepitus","Skin moisture"],c:[1],e:"Finger pads are most sensitive for palpating pulses and fine textures due to the high concentration of nerve endings. Dorsum of hand = temperature. Different surfaces serve different assessment purposes.",a:"B) Pulses",r:"Sec 2: Palpation"},
{id:84,s:"GS",t:"mc",q:"A comfortable pause during an interview that gives the patient time to think is called:",o:["Facilitation","Silence","Clarification","Empathy"],c:[1],e:"Silence is a therapeutic technique — a comfortable pause that gives the patient time to gather thoughts and reflect. Many nurses are uncomfortable with silence, but it is powerful and patient-centered.",a:"B) Silence",r:"Sec 2: Therapeutic Communication — Silence"},
{id:85,s:"GS",t:"tf",q:"True or False: The nurse should use family members as interpreters for medical history when a certified interpreter is unavailable.",o:["True","False"],c:[1],e:"False. NEVER use family members as interpreters for medical history. They may filter, omit, or alter information — especially sensitive topics. Always request a certified medical interpreter.",a:"False",r:"Sec 2: Cultural Sensitivity"},
{id:86,s:"GS",t:"mc",q:"When the nurse says 'You said the pain is sharp?' — repeating key words back — this technique is:",o:["Facilitation","Empathy","Reflection","Summary"],c:[2],e:"Reflection involves repeating key words back to the patient to show active listening and encourage elaboration. It validates the patient and helps clarify information.",a:"C) Reflection",r:"Sec 2: Therapeutic Communication — Reflection"},
{id:87,s:"GS",t:"mc",q:"Before delegating a task, the nurse must have done which of the following FIRST?",o:["Consulted the physician","Assessed the patient","Documented the plan","Obtained a physician order"],c:[1],e:"The nurse MUST assess the patient before delegation. You cannot safely delegate if you don't know the patient's current status. Assessment determines if the task is appropriate and the patient is stable enough.",a:"B) Assessed the patient",r:"Sec 2: Delegation Rules"},
{id:88,s:"GS",t:"mc",q:"A patient with diabetes, limited English, and cultural dietary restrictions is being assessed. Which is MOST important for accurate history-taking?",o:["Use a family interpreter to save time","Provide a certified medical interpreter and ask about dietary practices","Skip dietary questions to avoid cultural offense","Use only yes/no questions"],c:[1],e:"Use a certified interpreter AND ask about dietary restrictions respectfully. Cultural sensitivity means asking, not assuming or skipping. Halal, kosher, vegetarian, and other restrictions impact nutrition planning.",a:"B",r:"Sec 2: Cultural Sensitivity + Interviewing"},
{id:89,s:"GS",t:"mc",q:"Which gait characteristic is EXPECTED during the general survey?",o:["Wide-based and unsteady","Limping with right leg","Smooth, steady, and symmetrical","Shuffling with short steps"],c:[2],e:"Normal gait is smooth, steady, and symmetrical. Wide-based/unsteady = ataxia. Limping = musculoskeletal problem. Shuffling = Parkinson's or neurological issue. Always observe gait during ambulation.",a:"C) Smooth, steady, symmetrical",r:"Sec 2: General Survey — Gait"},
{id:90,s:"GS",t:"mc",q:"The nurse asks about the patient's self-perception, relationships, and stressors. This is part of:",o:["Biographical data","Chief complaint","Psychosocial history","Family history"],c:[2],e:"Psychosocial history includes self-perception, relationships (Maslow consideration), occupation, education, economic status, personal responsibilities, and stressors.",a:"C) Psychosocial history",r:"Sec 2: Psychosocial History"},
{id:91,s:"GS",t:"mc",q:"Assessment of the patient's understanding of their disease process is part of which purpose of health assessment?",o:["Establish a baseline","Identify nursing diagnoses","Make clinical judgments","Assess patient understanding of disease process"],c:[3],e:"One of the stated purposes is to assess the patient's understanding of their disease process. This guides patient education planning. Other purposes: establish baseline, identify diagnoses, make judgments, evaluate outcomes.",a:"D",r:"Sec 2: Purpose of Health Assessment"},
{id:92,s:"GS",t:"mc",q:"During a general survey, the nurse notes the patient is wearing a heavy coat on a warm day. This observation relates to:",o:["Body type assessment","Hygiene, grooming, and dress","Affect and mood","Level of consciousness"],c:[1],e:"Assessing whether clothing is appropriate for weather and setting is part of hygiene, grooming, and dress evaluation. Inappropriate dress may indicate cognitive impairment, psychiatric illness, or abuse.",a:"B) Hygiene, grooming, and dress",r:"Sec 2: General Survey"},
{id:93,s:"GS",t:"mc",q:"The nurse suspects patient abuse. During the general survey, which finding supports this concern?",o:["Clean, well-fitting clothing","Bruises in various stages of healing","Normal vital signs","Patient makes eye contact"],c:[1],e:"Bruises in various stages of healing (different colors = different ages) may indicate ongoing abuse. Signs of abuse include unexplained injuries, inconsistent stories, fearful behavior, and old/new injuries together.",a:"B) Bruises in various stages of healing",r:"Sec 2: General Survey — Signs of Abuse"},
{id:94,s:"GS",t:"mc",q:"When explaining a procedure to a patient, the nurse should use:",o:["Medical terminology for precision","Professional jargon","Plain language the patient can understand","Euphemisms to avoid scaring the patient"],c:[2],e:"Use plain language. Professional jargon and medical terminology may confuse the patient. Euphemisms obscure clinical meaning. Clear, honest communication in simple terms is the standard.",a:"C) Plain language",r:"Sec 2: Therapeutic Communication — Explanation"},
{id:95,s:"GS",t:"mc",q:"A patient reports taking ginkgo biloba and warfarin. The nurse is concerned because:",o:["Ginkgo has no effect on medications","Ginkgo may increase bleeding risk when combined with warfarin","Ginkgo will reduce warfarin's effectiveness","Herbal supplements are always safe"],c:[1],e:"Ginkgo biloba has antiplatelet properties that can increase bleeding risk when combined with anticoagulants like warfarin. Always document herbal supplements and assess for drug interactions.",a:"B",r:"Sec 2: Cultural Sensitivity — Alternative Medicine"},
{id:96,s:"GS",t:"mc",q:"The nurse is to assess a new patient. Which action reflects proper sequencing?",o:["Palpate the abdomen, then auscultate bowel sounds","Complete the health history interview before the physical exam","Begin with the physical exam to save time","Start with invasive procedures first"],c:[1],e:"The health history interview comes BEFORE the physical exam. The history provides context that guides the physical assessment. Always: History → Physical Assessment.",a:"B",r:"Sec 2: Assessment Flow"},
{id:97,s:"GS",t:"mc",q:"A nurse notes involuntary facial twitching during the general survey. This observation falls under:",o:["Gait assessment","Body movements","Level of consciousness","Hygiene assessment"],c:[1],e:"Body movements assessment includes noting any involuntary movements — twitching, tremors, tics, or unusual motor patterns. These may indicate neurological conditions requiring further assessment.",a:"B) Body movements",r:"Sec 2: General Survey — Body Movements"},
{id:98,s:"GS",t:"mc",q:"Which patient statement requires the nurse to document the reaction type for an allergy?",o:["'I'm allergic to penicillin — I get a rash.'","'I don't like the taste of amoxicillin.'","'Ibuprofen gives me a headache.'","'I prefer not to take aspirin.'"],c:[0],e:"'Rash' is a documented allergic reaction. The nurse must record both the allergen AND reaction type. A taste preference (B) is not an allergy. A headache (C) is a side effect, not an allergy. A preference (D) is a choice.",a:"A",r:"Sec 2: Allergies"},
{id:99,s:"GS",t:"tf",q:"True or False: Older adults should always be assessed with the assumption that illness and disability are present due to age.",o:["True","False"],c:[1],e:"False. Do NOT assume older adults have illness or disability based on age alone. Each patient is assessed individually. Ageism in healthcare leads to missed diagnoses and inadequate care.",a:"False",r:"Sec 2: Older Adults"},
{id:100,s:"GS",t:"mc",q:"A religious patient requests dietary accommodations. The BEST nursing response is:",o:["Tell them the hospital only serves standard meals","Document dietary restrictions and coordinate with nutrition services","Suggest they bring food from home","Ignore the request — it's not medically relevant"],c:[1],e:"Dietary restrictions (halal, kosher, vegetarian) affect nutrition planning. Document and coordinate with nutrition services. Religious observances can affect diet, dress, and health practices.",a:"B",r:"Sec 2: Cultural Sensitivity — Dietary"},
{id:101,s:"GS",t:"mc",q:"The nurse is interviewing a patient who keeps going off-topic. The BEST technique is:",o:["Interrupt and redirect firmly","Allow unlimited talking time","Use focused questions to gently redirect while remaining respectful","End the interview early"],c:[2],e:"Use focused, specific questions to redirect without being rude. The interview is patient-centered, but the nurse must gather necessary information efficiently. Never interrupt mid-sentence.",a:"C",r:"Sec 2: Interviewing Technique"},
{id:102,s:"GS",t:"mc",q:"Which vital sign abnormality should the nurse expect if a patient has DKA based on general survey findings?",o:["Bradycardia","Hypothermia","Tachypnea with deep respirations","Hypertension"],c:[2],e:"DKA presents with Kussmaul respirations (deep, rapid breathing) as the body tries to compensate for metabolic acidosis by blowing off CO2. Also expect sweet/fruity breath odor.",a:"C) Tachypnea with deep respirations",r:"Sec 2: General Survey + Sec 7: Kussmaul"},
{id:103,s:"GS",t:"mc",q:"The nurse uses a tongue blade and penlight to inspect the throat. This is an example of:",o:["Palpation","Percussion","Inspection with instruments","Auscultation"],c:[2],e:"Inspection can be enhanced with instruments (penlight, otoscope, tongue blade) while remaining a visual assessment. It is still classified as inspection, not a separate technique.",a:"C) Inspection with instruments",r:"Sec 2: Inspection"},
{id:104,s:"GS",t:"mc",q:"A CNA reports to the nurse that a patient's BP is 210/120 mmHg. The nurse should:",o:["Thank the CNA and document it","Ask the CNA what they think about the reading","Assess the patient personally and determine clinical significance","Have the CNA recheck it"],c:[2],e:"The RN must interpret and determine clinical significance — CNAs report data but cannot assess. A BP of 210/120 is a hypertensive crisis requiring immediate nursing assessment and provider notification.",a:"C",r:"Sec 2: RED FLAG — Delegation"},
{id:105,s:"GS",t:"mc",q:"Which aspect of the health history covers smoking, alcohol, and recreational drug use?",o:["Present illness","Family history","Functional assessment/ADLs","Psychosocial history"],c:[2],e:"Substance use (tobacco, alcohol, drugs) falls under Functional Assessment/ADLs. Create a safe, non-judgmental space for honest answers. This data affects anesthesia risk, drug interactions, and treatment planning.",a:"C) Functional assessment",r:"Sec 2: Functional Assessment"},
{id:106,s:"GS",t:"mc",q:"The nurse discovers the patient has a healthcare proxy. This document:",o:["Designates someone to make medical decisions if the patient cannot","Is the same as a DNR order","Allows the nurse to make decisions for the patient","Is only valid during surgery"],c:[0],e:"A healthcare proxy designates a person to make medical decisions when the patient is unable. It's different from a DNR (which specifically addresses resuscitation). Documented during biographical data collection.",a:"A",r:"Sec 2: Biographical Data — Advanced Directives"},
{id:107,s:"GS",t:"mc",q:"During the physical exam, the nurse notes the patient has crepitus in the right knee. Crepitus is detected by:",o:["Auscultation","Palpation","Percussion","Inspection"],c:[1],e:"Crepitus (crackling/grinding sensation) is detected by palpation — feeling the grating of bone or cartilage during joint movement. It indicates degenerative joint changes or fracture fragments.",a:"B) Palpation",r:"Sec 2: Palpation"},
{id:108,s:"GS",t:"mc",q:"A patient's family structure includes same-sex parents and the grandmother as primary caregiver. The nurse should:",o:["Express disapproval","Ignore the family structure","Assess and document the family structure without stereotyping","Ask the patient why their family is different"],c:[2],e:"Family structures vary — same-sex parents, grandparents as guardians, extended family as decision-makers. Document without judgment. Every patient is an individual regardless of cultural or family background.",a:"C",r:"Sec 2: Cultural Sensitivity"},
{id:109,s:"GS",t:"mc",q:"The source of information for the health history should be documented as:",o:["Always the physician","The patient, family member, or chart — whoever provided the information","Only the patient — no other source is acceptable","The nursing textbook"],c:[1],e:"Document the source: patient, family member, chart, or other. If information comes from the patient, document 'patient states.' If from family, note the relationship. Source reliability affects care planning.",a:"B",r:"Sec 2: Biographical Data — Source of Information"},
{id:110,s:"GS",t:"mc",q:"An older patient with an infection presents with acute functional decline instead of fever. This is an example of:",o:["Expected aging","Atypical or blunted presentation in older adults","Malingering","Normal disease progression"],c:[1],e:"Older adults commonly present with atypical, blunted, or absent classic signs. Functional decline, confusion, or falls may be the ONLY signs of serious illness like infection, MI, or pneumonia.",a:"B",r:"Sec 2: Older Adults — RED FLAG"},
// === PREVENTIVE SCREENINGS (111-135) ===
{id:111,s:"PS",t:"mc",q:"A 45-year-old female with family history of diabetes and glaucoma asks about vision screening. The BEST recommendation is:",o:["Screen every 5-10 years","Wait until age 50","Obtain baseline eye exam now due to risk factors","Wait for symptoms"],c:[2],e:"Earlier baseline is indicated with family history of DM, HTN, glaucoma, or cataracts. Standard baseline is at age 40, but risk factors warrant earlier screening.",a:"C",r:"Sec 3: Vision"},
{id:112,s:"PS",t:"mc",q:"Breast self-exam should be performed when during the menstrual cycle?",o:["First day of period","4-7 days after onset","During ovulation","Last day of period"],c:[1],e:"4-7 days after onset — breasts are smallest and least congested, making it easier to detect abnormalities. Hormonal changes during menses and ovulation cause engorgement.",a:"B",r:"Sec 3: Breast/Mammography"},
{id:113,s:"PS",t:"mc",q:"A male patient scheduled for PSA testing should be instructed to:",o:["Fast 12 hours","Avoid red meat 48 hours","Refrain from ejaculating 48 hours","Stop all medications 24 hours"],c:[2],e:"Ejaculation can elevate PSA levels, causing false positives. Refrain 48 hours before the test. PSA detects prostate-specific protein; elevation may indicate cancer, infection, BPH, or recent ejaculation.",a:"C",r:"Sec 3: Prostate/PSA"},
{id:114,s:"PS",t:"mc",q:"A 75-year-old reports gradual bilateral difficulty hearing high-pitched sounds. This is:",o:["Tinnitus","Presbycusis","Meniere's disease","Otitis media"],c:[1],e:"Presbycusis = bilateral age-related hearing loss starting ~age 50, affecting high-pitched tones first. Expected in 75-year-old. Tinnitus = ringing. Meniere's = vertigo + hearing loss. Otitis media = infection.",a:"B) Presbycusis",r:"Sec 3: Hearing"},
{id:115,s:"PS",t:"tf",q:"True or False: Dental disease can exacerbate systemic illness such as heart disease and diabetes.",o:["True","False"],c:[0],e:"True. Periodontal disease is linked to worsening heart disease, diabetes, arthritis, and liver disease. Oral bacteria can enter the bloodstream. Patients with chronic disease may need more frequent dental care.",a:"True",r:"Sec 3: Dental"},
{id:116,s:"PS",t:"mc",q:"Routine mammography is recommended for ages:",o:["30-50, annually","40-65, annually","50-74, every 2 years","Only when symptoms develop"],c:[2],e:"Routine mammography: ages 50-74, every 2 years. Earlier or more frequent screening may be indicated based on family history or risk factors.",a:"C) 50-74, every 2 years",r:"Sec 3: Breast/Mammography"},
{id:117,s:"PS",t:"mc",q:"A Pap smear should be performed how frequently for sexually active females?",o:["Annually","Every 3 years","Every 5 years","Only once"],c:[1],e:"Pap smear every 3 years while sexually active. Annual pelvic exam is separate from the Pap schedule. Guidelines may vary by age and risk factors.",a:"B) Every 3 years",r:"Sec 3: Cervical/Gynecological"},
{id:118,s:"PS",t:"mc",q:"Adults under 40 with no risk factors should have vision screening every:",o:["1-2 years","3-5 years","5-10 years","Only when symptomatic"],c:[2],e:"Adults under 40: screen every 5-10 years for near and far vision deficiency. At age 40: baseline eye exam for eye disease. Earlier if family history of DM, HTN, glaucoma, or cataracts.",a:"C) 5-10 years",r:"Sec 3: Vision"},
{id:119,s:"PS",t:"mc",q:"A patient reports new onset nipple inversion. The nurse should:",o:["Document as normal variation","Recognize this as an unexpected finding and report","Reassess in 6 months","Ignore if the patient is post-menopausal"],c:[1],e:"NEW nipple inversion is unexpected and requires reporting. Nipple inversion since PUBERTY = expected variation. The timing of onset differentiates normal from pathological.",a:"B) Unexpected — report",r:"Sec 3: Breast + Sec 9: Female GU"},
{id:120,s:"PS",t:"mc",q:"The PSA test detects a protein made only by which gland?",o:["Thyroid","Adrenal","Prostate","Pituitary"],c:[2],e:"PSA (Prostate-Specific Antigen) is made exclusively by the prostate gland. Elevation can indicate cancer, infection, BPH, or recent ejaculation. It is NOT diagnostic of cancer alone.",a:"C) Prostate",r:"Sec 3: Prostate/PSA"},
{id:121,s:"PS",t:"mc",q:"Degenerative hearing changes typically begin around age:",o:["30","40","50","65"],c:[2],e:"Degenerative hearing changes (presbycusis) typically begin around age 50. Screen whenever the patient reports changes. High-pitched tones are lost first.",a:"C) 50",r:"Sec 3: Hearing"},
{id:122,s:"PS",t:"mc",q:"When chief complaint is lower abdominal pain in a female, the nurse's FIRST question should be:",o:["'Do you have nausea?'","'When was your last menstrual period?'","'Do you have a fever?'","'What did you eat today?'"],c:[1],e:"Always ask LMP first to differentiate gynecological from other causes. Pregnancy must be ruled out before many diagnostic tests (X-rays, CT with contrast, certain medications).",a:"B) When was your LMP?",r:"Sec 3: Cervical/Gynecological"},
{id:123,s:"PS",t:"mc",q:"A 42-year-old with no risk factors should have a baseline eye exam at what age?",o:["35","40","45","50"],c:[1],e:"At age 40: baseline eye exam to screen for eye disease. This applies to patients without risk factors. Those with family history of DM, HTN, glaucoma, or cataracts need earlier baseline.",a:"B) 40",r:"Sec 3: Vision"},
{id:124,s:"PS",t:"mc",q:"Oral health is recommended how often for adults?",o:["Brush once daily, dental exam every 5 years","Brush twice daily, floss daily, annual dental exam","Brush weekly, no dental exam needed","Brush once daily, dental exam only when symptomatic"],c:[1],e:"Brush twice daily, floss daily, and have an annual dental exam. Patients with chronic disease may need more frequent visits due to the connection between oral and systemic health.",a:"B",r:"Sec 3: Dental"},
{id:125,s:"PS",t:"mc",q:"Elevated PSA can indicate all of the following EXCEPT:",o:["Prostate cancer","Benign prostatic hyperplasia","Recent ejaculation","Vitamin D deficiency"],c:[3],e:"Elevated PSA may indicate cancer, infection, BPH, or recent ejaculation. Vitamin D deficiency does not affect PSA levels. This is why 48-hour ejaculation abstinence is important before testing.",a:"D) Vitamin D deficiency",r:"Sec 3: Prostate/PSA"},
{id:126,s:"PS",t:"mc",q:"A patient with heart disease should receive dental care:",o:["Less frequently to avoid stress","More frequently — dental disease exacerbates systemic illness","Only for emergencies","At the same interval as healthy adults"],c:[1],e:"Patients with heart disease, diabetes, arthritis, and liver disease may need more frequent dental visits. Oral bacteria from periodontal disease can enter the bloodstream and worsen cardiac conditions.",a:"B",r:"Sec 3: Dental"},
{id:127,s:"PS",t:"tf",q:"True or False: Hearing screening should only be performed at specific age milestones.",o:["True","False"],c:[1],e:"False. Screen whenever the patient reports changes in hearing ability. While degenerative changes typically begin around age 50, hearing loss can occur at any age from various causes.",a:"False",r:"Sec 3: Hearing"},
{id:128,s:"PS",t:"mc",q:"A 55-year-old woman asks about mammography. The correct recommendation is:",o:["Every year starting now","Every 2 years per guidelines (ages 50-74)","She's too old for screening","Only if she has symptoms"],c:[1],e:"At 55, she falls within the 50-74 age range for routine mammography every 2 years. This is the standard guideline. Individual risk factors may warrant more frequent screening.",a:"B) Every 2 years",r:"Sec 3: Breast/Mammography"},
{id:129,s:"PS",t:"mc",q:"An annual pelvic exam is recommended for:",o:["All women over 50","Sexually active females","Only women with symptoms","Post-menopausal women only"],c:[1],e:"Annual pelvic exam for sexually active females. This is separate from the Pap smear (every 3 years). The pelvic exam screens for reproductive health issues beyond cervical cancer.",a:"B) Sexually active females",r:"Sec 3: Cervical/Gynecological"},
{id:130,s:"PS",t:"mc",q:"Which visual change is an EXPECTED age-related finding?",o:["Sudden vision loss","Presbyopia (farsightedness)","Exophthalmos","Nystagmus"],c:[1],e:"Presbyopia = age-related farsightedness (difficulty seeing close objects). Expected finding. Sudden vision loss = emergency. Exophthalmos = Graves' disease. Nystagmus = neurological concern.",a:"B) Presbyopia",r:"Sec 3: Vision + Sec 4: Eyes"},
{id:131,s:"PS",t:"mc",q:"When should breast self-exam be performed in post-menopausal women?",o:["Same day every month","4-7 days after onset of menstruation","Only when symptoms develop","It is not recommended for post-menopausal women"],c:[0],e:"Post-menopausal women should perform BSE on the same day each month since they no longer menstruate. Choose a consistent date that's easy to remember.",a:"A) Same day every month",r:"Sec 3: Breast/Mammography"},
{id:132,s:"PS",t:"mc",q:"A patient with presbycusis will have the MOST difficulty hearing:",o:["Low-pitched male voices","High-pitched sounds like doorbells and alarms","Normal conversational speech","Music"],c:[1],e:"Presbycusis affects high-pitched tones first. Difficulty hearing doorbells, phone rings, smoke alarms, and consonant sounds (s, f, th) is common. This has safety implications (may not hear alarms).",a:"B) High-pitched sounds",r:"Sec 3: Hearing — Presbycusis"},
{id:133,s:"PS",t:"mc",q:"Nipple inversion present since puberty is classified as:",o:["Cancer indicator","Expected variation","Paget's disease","Always requires biopsy"],c:[1],e:"Nipple inversion since puberty = expected variation. Document and compare to baseline. NEW nipple inversion = unexpected finding requiring evaluation. Timing of onset is the key differentiator.",a:"B) Expected variation",r:"Sec 3: Breast/Mammography"},
{id:134,s:"PS",t:"mc",q:"The HPV vaccine is recommended at what age?",o:["Age 6","Age 12","Age 18","Age 25"],c:[1],e:"HPV vaccine is recommended at age 12. HPV causes genital warts and can progress to cancer. Early vaccination before potential exposure provides the best protection.",a:"B) Age 12",r:"Sec 3 + Sec 9: HPV"},
{id:135,s:"PS",t:"mc",q:"A patient asks why the doctor checks their PSA. The BEST explanation is:",o:["It tests for kidney function","It detects a prostate-specific protein that can indicate prostate disease","It screens for colon cancer","It measures testosterone levels"],c:[1],e:"PSA detects a protein made ONLY by the prostate gland. Elevation can indicate cancer, infection, BPH, or ejaculation. It's a screening tool, not diagnostic by itself.",a:"B",r:"Sec 3: Prostate/PSA"},
// === HEENT (136-200) ===
{id:136,s:"HE",t:"mc",q:"A trachea shifted to the left may indicate tension pneumothorax on which side?",o:["Left","Right","Both","Neither"],c:[1],e:"Trachea deviates AWAY from affected side. Right-sided tension pneumothorax pushes structures left. This is a medical emergency — absent breath sounds, hypoxia, tachycardia, hypotension.",a:"B) Right",r:"Sec 4: Neck — Tracheal Deviation"},
{id:137,s:"HE",t:"mc",q:"Significant facial asymmetry with inability to smile or close one eye suggests CN VII involvement, known as:",o:["Trigeminal neuralgia","Bell's Palsy","CN III palsy","Myasthenia gravis"],c:[1],e:"Bell's Palsy = CN VII (Facial) paralysis causing unilateral facial drooping, inability to close eye, smile, or raise eyebrow on the affected side. Can also indicate stroke — do rapid neuro assessment.",a:"B) Bell's Palsy",r:"Sec 4: Head"},
{id:138,s:"HE",t:"mc",q:"Exophthalmos (bulging eyes) is most commonly associated with:",o:["Hypothyroidism","Graves' disease (hyperthyroidism)","Glaucoma","CN III palsy"],c:[1],e:"Exophthalmos = orbital tissue inflammation in Graves' disease pushing eyeballs forward. Hypothyroidism = periorbital edema, not protrusion. Glaucoma = increased intraocular pressure.",a:"B) Graves' disease",r:"Sec 4: Eyes"},
{id:139,s:"HE",t:"mc",q:"20/40 vision means the patient:",o:["Sees at 40 ft what normal sees at 20 ft","Sees at 20 ft what normal sees at 40 ft","Has 40% vision loss","Has perfect vision"],c:[1],e:"The numerator = testing distance (20 ft). Denominator = distance at which a normal eye reads that line. 20/40 = reduced acuity. Higher denominator = worse vision.",a:"B",r:"Sec 4: Vision Testing"},
{id:140,s:"HE",t:"mc",q:"Yellow sclera indicates:",o:["Conjunctivitis","Subconjunctival hemorrhage","Liver disease or biliary obstruction","Allergic reaction"],c:[2],e:"Yellow sclera (jaundice) = elevated bilirubin from liver disease or biliary obstruction. Bile pigments deposit in tissues. Also check hard palate for yellow discoloration.",a:"C",r:"Sec 4: Eyes — Yellow Sclera"},
{id:141,s:"HE",t:"mc",q:"Bright red nasal mucosa with mucoid discharge suggests:",o:["Allergies","URI","Sinusitis","CSF leak"],c:[1],e:"Red mucosa + mucoid discharge = URI. Pale mucosa + clear = allergies. Yellow/green = sinusitis. Unilateral watery discharge after head injury = CSF leak (emergency).",a:"B) URI",r:"Sec 4: Nose"},
{id:142,s:"HE",t:"mc",q:"White scrapable plaques on the tongue in an HIV patient are most likely:",o:["Gingivitis","Oral candidiasis (thrush)","Canker sore","B12 deficiency"],c:[1],e:"Thrush (Candida) = white plaques on tongue/mucosa, typically in immunocompromised patients (HIV, chemo, prolonged antibiotics). Scrapable with raw tissue beneath.",a:"B) Thrush",r:"Sec 4: Throat & Mouth"},
{id:143,s:"HE",t:"mc",q:"Tongue deviation to the right when extended suggests damage to:",o:["CN IX","CN X","CN XII","CN VII"],c:[2],e:"CN XII (Hypoglossal) controls tongue movement. Tongue should be midline; deviation indicates damage — tongue deviates toward the lesion side.",a:"C) CN XII",r:"Sec 4: CN Testing"},
{id:144,s:"HE",t:"mc",q:"Ptosis could indicate all EXCEPT:",o:["CN III palsy","Horner syndrome","Myasthenia gravis","Presbyopia"],c:[3],e:"Ptosis (drooping eyelid) = CN III palsy, Horner syndrome, or myasthenia gravis. Presbyopia is age-related farsightedness — affects lens focus, not eyelid position.",a:"D) Presbyopia",r:"Sec 4: Eyes — Ptosis"},
{id:145,s:"HE",t:"mc",q:"Persistent ringing in ears after aspirin use is documented as:",o:["Presbycusis","Vertigo","Tinnitus","Nystagmus"],c:[2],e:"Tinnitus = high-pitched ringing from ototoxic meds (aspirin, aminoglycosides), noise exposure, or Meniere's disease. Presbycusis = age-related loss. Nystagmus = eye movement, not auditory.",a:"C) Tinnitus",r:"Sec 4: Ears"},
{id:146,s:"HE",t:"mc",q:"Expected tympanic membrane appearance on otoscope is:",o:["Bright red, bulging","Translucent, pearly grey with light reflex","Dull yellow with fluid","White and opaque"],c:[1],e:"Normal TM: translucent, pearly grey, with visible light reflex (cone of light). Red/bulging = otitis media. Dull yellow = serous otitis. White/opaque = scarring.",a:"B",r:"Sec 4: Ears — Expected"},
{id:147,s:"HE",t:"mc",q:"A smooth, beefy red tongue indicates deficiency of:",o:["Vitamin C","Iron","Vitamin B12","Calcium"],c:[2],e:"Smooth, beefy red, swollen tongue = B12 deficiency (pernicious anemia). Tongue loses normal papillae. Vitamin C = scurvy. Iron = pale mucosa.",a:"C) Vitamin B12",r:"Sec 4: Throat & Mouth"},
{id:148,s:"HE",t:"mc",q:"Hirsutism (coarse facial hair) in a female may indicate:",o:["Hypothyroidism","PCOS or adrenal hyperplasia","Vitamin D deficiency","Normal aging"],c:[1],e:"Hirsutism in females suggests hormonal/endocrine disorder — PCOS, adrenal hyperplasia. Not normal or age-related. Hypothyroidism causes hair thinning, not excess growth.",a:"B) PCOS/endocrine disorder",r:"Sec 4: Head — Hirsutism"},
{id:149,s:"HE",t:"mc",q:"PERRLA stands for:",o:["Pulses Equal, Round, Reactive to Light Alternately","Pupils Equal, Round, Reactive to Light and Accommodation","Pressure Equal, Regular, Responsive to Light Always","Pupils Even, Rounded, Reflective to Light Accurately"],c:[1],e:"PERRLA = Pupils Equal, Round, Reactive to Light and Accommodation. This is the standard expected finding for pupil assessment and tests CN III (Oculomotor).",a:"B",r:"Sec 4: Eyes — Expected"},
{id:150,s:"HE",t:"mc",q:"The Snellen chart tests vision at what distance?",o:["10 feet","14 inches","20 feet","40 feet"],c:[2],e:"Snellen chart tests FAR/distant visual acuity at 20 feet. Rosenbaum/Jaeger card tests NEAR vision at 14 inches. Both should be documented in the chart.",a:"C) 20 feet",r:"Sec 4: Vision Testing"},
{id:151,s:"HE",t:"mc",q:"Yellow discoloration of the HARD PALATE indicates:",o:["Poor oral hygiene","Liver disorder (jaundice)","Vitamin C deficiency","Normal finding"],c:[1],e:"Yellow hard palate = jaundice/liver disorder. Bile pigments deposit in tissues. Check sclera as well — yellow sclera is often the first visible sign of jaundice.",a:"B) Liver disorder",r:"Sec 4: Throat & Mouth"},
{id:152,s:"HE",t:"mc",q:"A canker sore (aphthous ulcer) appears as:",o:["White plaque that can be scraped","Painful round ulcer with white base and red halo","Vesicular cluster along a dermatome","Beefy red smooth area"],c:[1],e:"Canker sore = painful round ulcer on mucosa/lip with white base and red halo. Different from thrush (scrapable plaques), shingles (dermatomal vesicles), or B12 deficiency (smooth red tongue).",a:"B",r:"Sec 4: Throat & Mouth"},
{id:153,s:"HE",t:"mc",q:"Difficulty swallowing (dysphagia) may indicate:",o:["Sinus infection only","Infection or CNS disorder","Normal aging","Dental caries"],c:[1],e:"Dysphagia can indicate infection or CNS disorder — assess for neurological causes. It affects CN IX (Glossopharyngeal) and CN X (Vagus) function and requires prompt evaluation.",a:"B) Infection or CNS disorder",r:"Sec 4: Neck"},
{id:154,s:"HE",t:"mc",q:"Swelling on the anterior neck suggests disorder of which gland?",o:["Pituitary","Adrenal","Thyroid","Parathyroid"],c:[2],e:"Anterior neck swelling = thyroid gland disorder. Assess for hyper or hypothyroidism signs. The thyroid is palpable on the anterior neck — visible enlargement (goiter) is always abnormal.",a:"C) Thyroid",r:"Sec 4: Neck"},
{id:155,s:"HE",t:"mc",q:"Visible lymph nodes on inspection suggest:",o:["Normal finding in thin patients","Cancer or infection","Dehydration","Allergic reaction"],c:[1],e:"Lymph nodes should NOT be visually apparent. Visible nodes suggest cancer or significant infection causing lymphadenopathy. Palpable nodes can be normal; visible ones are not.",a:"B) Cancer or infection",r:"Sec 4: Neck"},
{id:156,s:"HE",t:"mc",q:"The Rosenbaum/Jaeger card tests near vision at what distance?",o:["10 inches","14 inches","20 feet","6 inches"],c:[1],e:"Rosenbaum/Jaeger = near vision at 14 inches. Snellen = far vision at 20 feet. These are two different tests assessing different visual capabilities.",a:"B) 14 inches",r:"Sec 4: Vision Testing"},
{id:157,s:"HE",t:"mc",q:"Myopia means the patient:",o:["Can see far, not close","Can see close, not far","Has lost peripheral vision","Has double vision"],c:[1],e:"Myopia = nearsightedness (can see close, not far). Presbyopia = farsightedness in elderly (can see far, not close). These are opposite conditions.",a:"B) Can see close, not far",r:"Sec 4: Eyes"},
{id:158,s:"HE",t:"mc",q:"Strabismus refers to:",o:["Clouding of the lens","Abnormal eye alignment","Rapid involuntary eye movement","Drooping eyelid"],c:[1],e:"Strabismus = abnormal eye alignment. Eyes may deviate toward ear (exotropia) or nose (esotropia). Different from nystagmus (involuntary movement), cataracts (lens clouding), or ptosis (drooping lid).",a:"B) Abnormal eye alignment",r:"Sec 4: Eyes"},
{id:159,s:"HE",t:"mc",q:"A patient had a subconjunctival hemorrhage after a coughing fit. The nurse should:",o:["Call the HCP immediately","Recognize this as an expected finding after coughing/straining","Apply cold compresses and elevate HOB","Prepare for emergency eye surgery"],c:[1],e:"Subconjunctival hemorrhage (blood collection on sclera) is EXPECTED after coughing, vomiting, or straining. No need to report unless recurrent or unexplained. It resolves on its own.",a:"B) Expected finding",r:"Sec 4: Eyes — Subconjunctival Hemorrhage"},
{id:160,s:"HE",t:"mc",q:"Yellow/green nasal discharge from ONE nare may indicate:",o:["Allergies","URI","Foreign body in the nose","CSF leak"],c:[2],e:"Bilateral yellow/green = sinusitis. ONE nare only = possible foreign body. Unilateral watery discharge after head injury = CSF leak. Always differentiate unilateral vs bilateral.",a:"C) Foreign body",r:"Sec 4: Nose"},
{id:161,s:"HE",t:"mc",q:"Sinus congestion relief measures include all EXCEPT:",o:["Humidifying the air","Warm compresses over face","Elevating HOB","Applying ice packs to sinuses"],c:[3],e:"WARM compresses (not cold/ice) relieve sinus pain and congestion. Also humidify air and elevate HOB. Cold would constrict vessels and worsen congestion.",a:"D) Ice packs",r:"Sec 4: Sinus Relief"},
{id:162,s:"HE",t:"mc",q:"Entropion refers to:",o:["Eyelid rolling outward","Eyelid rolling inward, irritating the cornea","Protruding eyeball","Double vision"],c:[1],e:"Entropion = eyelid rolls INWARD — eyelashes irritate conjunctiva and cornea, causing pain and potential corneal damage. Requires ophthalmologic referral.",a:"B) Eyelid rolling inward",r:"Sec 4: Eyes"},
{id:163,s:"HE",t:"mc",q:"Red, edematous uvula with yellow exudate on tonsillar pillars suggests:",o:["Normal finding","Pharyngitis — may indicate strep throat","Oral cancer","Thrush"],c:[1],e:"Red, edematous uvula/tonsillar pillars with yellow exudate = pharyngitis, possibly strep throat. Requires throat culture to confirm. Thrush presents with white plaques, not exudate on tonsils.",a:"B) Pharyngitis/strep",r:"Sec 4: Throat"},
{id:164,s:"HE",t:"mc",q:"Nystagmus (rapid involuntary eye movement) can be caused by all EXCEPT:",o:["Inner ear disorders","CNS lesions","Vertigo","Presbyopia"],c:[3],e:"Nystagmus is caused by inner ear disorders, CNS lesions, or vertigo. Presbyopia is age-related farsightedness affecting lens accommodation — it does not cause eye movement abnormalities.",a:"D) Presbyopia",r:"Sec 4: Eyes — Nystagmus"},
{id:165,s:"HE",t:"mc",q:"Amblyopia (lazy eye) is defined as:",o:["Rapid involuntary eye movement","Reduced vision in one eye due to abnormal visual development","Clouding of the lens","Abnormal eye alignment"],c:[1],e:"Amblyopia = reduced vision in one eye from abnormal development. Different from strabismus (misalignment, which can cause amblyopia), cataracts (lens clouding), or nystagmus (involuntary movement).",a:"B",r:"Sec 4: Eyes — Amblyopia"},
{id:166,s:"HE",t:"mc",q:"Signs of hearing deficit include all EXCEPT:",o:["Asking for questions to be repeated","Turning 'good ear' toward speaker","Watching speaker's lips instead of eyes","Maintaining normal conversational volume"],c:[3],e:"Hearing deficit signs: repeated questions, turning head, lip-reading, speaking UNUSUALLY LOUD or monotone. Normal volume suggests hearing is intact. RED FLAG: Don't confuse hearing loss with confusion.",a:"D) Normal volume",r:"Sec 4: Ears — Hearing Deficit Signs"},
{id:167,s:"HE",t:"mc",q:"A patient has limited neck movement and pain on movement. This may indicate:",o:["Normal stiffness from sleeping position","Systemic spine infection or musculoskeletal disorder","Thyroid disorder","Expected aging change"],c:[1],e:"Limited/painful neck movement suggests spine infection or musculoskeletal disorder. While mild stiffness can occur from positioning, significant limitation with pain warrants further assessment.",a:"B",r:"Sec 4: Neck"},
{id:168,s:"HE",t:"mc",q:"Cataracts cause:",o:["Bulging eyes","Blurred, hazy vision from lens clouding","Sharp stabbing eye pain","Peripheral vision loss"],c:[1],e:"Cataracts = clouding of the lens causing blurred, hazy vision. Expected in older adults. Treated surgically. Not painful. Glaucoma causes peripheral vision loss. Exophthalmos = bulging.",a:"B) Blurred, hazy vision",r:"Sec 4: Eyes — Cataracts"},
{id:169,s:"HE",t:"sata",q:"Which eye findings are EXPECTED/normal? (SATA)",o:["PERRLA","Pink, moist conjunctiva","White sclera","Nystagmus","Symmetric eye movement through 6 cardinal fields"],c:[0,1,2,4],e:"Normal: PERRLA, pink/moist conjunctiva, white sclera, symmetric movement through all 6 fields. Nystagmus is ALWAYS unexpected — indicates inner ear, CNS, or vestibular pathology.",a:"A, B, C, E",r:"Sec 4: Eyes — Expected"},
{id:170,s:"HE",t:"mc",q:"Head lice appear as:",o:["Red bumps on the scalp","Small oval white nits firmly attached to hair strands","Large black insects crawling on the skin","Dandruff flakes that fall easily"],c:[1],e:"Nits = small oval white particles FIRMLY attached to hair strands (not easily removed like dandruff). Mobile lice may also be seen. Key distinction: dandruff flakes off easily; nits do not.",a:"B) White nits firmly attached",r:"Sec 4: Head — Lice"},
{id:171,s:"HE",t:"mc",q:"Unilateral watery nasal discharge after a head injury may indicate:",o:["Allergies","Common cold","Skull fracture with CSF leak","Sinusitis"],c:[2],e:"Unilateral watery discharge post-head trauma = possible CSF (cerebrospinal fluid) leak from skull fracture. REPORT IMMEDIATELY. This is a medical emergency requiring urgent evaluation.",a:"C) Skull fracture/CSF leak",r:"Sec 4: Nose — RED FLAG"},
{id:172,s:"HE",t:"mc",q:"Petechiae on the hard/soft palate indicate:",o:["Normal finding","Infection","Vitamin C excess","Dehydration"],c:[1],e:"Petechiae, lesions, edema, or drainage on the palate indicate infection. Petechiae elsewhere may indicate bleeding disorder or meningitis — always report to HCP.",a:"B) Infection",r:"Sec 4: Throat & Mouth"},
{id:173,s:"HE",t:"mc",q:"Any new bony or soft protrusion on the head may indicate:",o:["Normal bone growth","Recent head trauma — report to HCP","Expected aging change","Vitamin deficiency"],c:[1],e:"New protrusions on the head may indicate recent head trauma — always report to HCP for further evaluation. Could indicate hematoma, fracture, or other injury.",a:"B) Recent head trauma",r:"Sec 4: Head — Protrusions"},
{id:174,s:"HE",t:"mc",q:"The confrontation test assesses:",o:["Visual acuity","Visual fields","Pupil reactivity","Color vision"],c:[1],e:"Confrontation test = visual fields (peripheral vision) testing for CN II (Optic). Snellen = acuity. PERRLA = pupil reactivity. Ishihara plates = color vision.",a:"B) Visual fields",r:"Sec 4: Vision Testing + Sec 5: CN II"},
{id:175,s:"HE",t:"mc",q:"Pale nasal mucosa with clear discharge is MOST consistent with:",o:["URI","Allergies","Sinusitis","Foreign body"],c:[1],e:"Pale mucosa + clear discharge = allergies. Red mucosa + mucoid = URI. Yellow/green = sinusitis. The color of mucosa AND discharge type together determine the likely cause.",a:"B) Allergies",r:"Sec 4: Nose"},
{id:176,s:"HE",t:"tf",q:"True or False: Tracheal deviation from midline is a medical emergency if caused by tension pneumothorax.",o:["True","False"],c:[0],e:"True. Tension pneumothorax causes tracheal deviation (away from affected side), absent breath sounds, hypoxia, tachycardia, and hypotension. Call HCP immediately — this is life-threatening.",a:"True",r:"Sec 4: Neck — RED FLAG"},
{id:177,s:"HE",t:"mc",q:"Conjunctivitis (pink eye) involves inflammation of the:",o:["Cornea","Conjunctiva","Sclera","Iris"],c:[1],e:"Conjunctivitis = inflammation of the conjunctiva (mucous membrane lining the eyelid). Can be bacterial, viral, or allergic. Bacterial and viral forms are highly contagious.",a:"B) Conjunctiva",r:"Sec 4: Eyes"},
{id:178,s:"HE",t:"mc",q:"A patient with Meniere's disease would experience:",o:["Only hearing loss","Vertigo, tinnitus, and fluctuating hearing loss","Bilateral conductive hearing loss","Visual disturbances"],c:[1],e:"Meniere's disease = triad of vertigo, tinnitus, and fluctuating hearing loss. Inner ear fluid imbalance causes episodic attacks. Different from presbycusis (gradual, bilateral, non-episodic).",a:"B",r:"Sec 4: Ears"},
{id:179,s:"HE",t:"mc",q:"Which finding differentiates hearing deficit from cognitive deficit in an unresponsive patient?",o:["Check GCS score","Check pupil reactivity","Check hearing aid batteries first","Perform a CT scan"],c:[2],e:"RED FLAG: Don't confuse confusion with hearing difficulty. A non-responsive patient may simply not have heard you. Check hearing aids and batteries FIRST before assuming cognitive impairment.",a:"C",r:"Sec 4: RED FLAG — Hearing vs Confusion"},
{id:180,s:"HE",t:"mc",q:"The six cardinal fields of gaze test which cranial nerves?",o:["CN I, II, III","CN III, IV, VI","CN V, VII, XII","CN II, VII, VIII"],c:[1],e:"CN III (Oculomotor), CN IV (Trochlear), and CN VI (Abducens) control eye movements tested through the 6 cardinal fields of gaze. CN II is optic (visual acuity).",a:"B) CN III, IV, VI",r:"Sec 4: Eyes + Sec 5: Cranial Nerves"},
{id:181,s:"HE",t:"mc",q:"Gingivitis presents as:",o:["White plaques on gums","Swelling of gums with redness and bleeding","Smooth, beefy red tongue","Yellow exudate on tonsils"],c:[1],e:"Gingivitis = swollen gums with redness and bleeding. It's an early stage of periodontal disease and can be reversed with proper oral hygiene.",a:"B",r:"Sec 4: Throat & Mouth — Gingivitis"},
{id:182,s:"HE",t:"mc",q:"Expected cerumen (earwax) in the ear canal is:",o:["Always abnormal — ears should be completely clean","Normal — small amounts are expected","Indicates infection","Requires immediate irrigation"],c:[1],e:"Small amounts of cerumen are NORMAL and protective. Excessive cerumen can impair hearing but moderate amounts are expected. Never aggressively clean the ear canal.",a:"B) Normal",r:"Sec 4: Ears — Expected"},
{id:183,s:"HE",t:"mc",q:"A patient cannot abduct their right eye (look laterally). This indicates CN ___ palsy.",o:["CN III","CN IV","CN VI","CN II"],c:[2],e:"CN VI (Abducens) controls lateral rectus = lateral eye movement. Inability to look outward = CN VI palsy. CN III = most eye movements. CN IV = downward/inward.",a:"C) CN VI",r:"Sec 4 + Sec 5: CN VI"},
{id:184,s:"HE",t:"mc",q:"Ototoxic medications include:",o:["Acetaminophen and ibuprofen","Aspirin and aminoglycosides","Metformin and lisinopril","Omeprazole and famotidine"],c:[1],e:"Aspirin and aminoglycosides (gentamicin, tobramycin) are classic ototoxic medications causing tinnitus and potential hearing loss. Monitor hearing in patients on these drugs.",a:"B) Aspirin and aminoglycosides",r:"Sec 4: Ears — Tinnitus"},
{id:185,s:"HE",t:"mc",q:"Strabismus where the eye deviates toward the nose is called:",o:["Exotropia","Esotropia","Exophthalmos","Amblyopia"],c:[1],e:"Esotropia = eye turns inward toward nose. Exotropia = eye turns outward toward ear. Both are forms of strabismus. Exophthalmos = protruding eye (Graves'). Amblyopia = lazy eye.",a:"B) Esotropia",r:"Sec 4: Eyes — Strabismus"},
{id:186,s:"HE",t:"mc",q:"A nurse suspects a patient may have strep throat. Expected findings include:",o:["White scrapable plaques on tongue","Red, edematous tonsillar pillars with yellow exudate","Smooth beefy red tongue","Pale mucosa with clear discharge"],c:[1],e:"Red/edematous uvula/tonsillar pillars with yellow exudate = pharyngitis/possible strep. Requires culture for confirmation. White plaques = thrush. Smooth red tongue = B12 deficiency.",a:"B",r:"Sec 4: Throat"},
{id:187,s:"HE",t:"mc",q:"Normal visual acuity is expressed as:",o:["20/20","20/40","20/100","10/10"],c:[0],e:"20/20 is normal visual acuity — can see at 20 feet what a person with normal vision sees at 20 feet. Any number higher than 20 in the denominator indicates reduced acuity.",a:"A) 20/20",r:"Sec 4: Vision Testing"},
{id:188,s:"HE",t:"mc",q:"Testing facial sensation with a cotton ball across three areas tests which cranial nerve?",o:["CN V (Trigeminal) — sensory component","CN VII (Facial)","CN II (Optic)","CN X (Vagus)"],c:[0],e:"CN V (Trigeminal) has three sensory branches covering the face (ophthalmic, maxillary, mandibular). Light touch with cotton ball tests the sensory component. Motor component = jaw clenching.",a:"A) CN V sensory",r:"Sec 4 + Sec 5: CN V"},
{id:189,s:"HE",t:"mc",q:"A patient with Bell's Palsy would have difficulty with which action?",o:["Shrugging shoulders","Smiling symmetrically","Extending the tongue","Looking upward"],c:[1],e:"Bell's Palsy (CN VII) affects facial expression — inability to smile, frown, raise eyebrows, puff cheeks, or close eyes on the affected side. Shoulders = CN XI. Tongue = CN XII.",a:"B) Smiling symmetrically",r:"Sec 4: Head — Bell's Palsy"},
{id:190,s:"HE",t:"mc",q:"The Weber test involves placing a tuning fork on:",o:["The mastoid bone","Top of the skull (vertex)","In front of the ear","The tragus"],c:[1],e:"Weber test: tuning fork on top of skull — sound should be equal bilaterally. If lateralized (louder on one side), indicates conductive or sensorineural hearing loss. Tests CN VIII.",a:"B) Top of skull",r:"Sec 4 + Sec 5: CN VIII"},
{id:191,s:"HE",t:"mc",q:"The Rinne test compares:",o:["Near vision vs far vision","Air conduction vs bone conduction","Left ear vs right ear","Hearing with and without hearing aids"],c:[1],e:"Rinne test: tuning fork on mastoid (bone conduction), then held near ear (air conduction). Normal: air > bone. If bone > air = conductive hearing loss.",a:"B) Air vs bone conduction",r:"Sec 4 + Sec 5: CN VIII"},
{id:192,s:"HE",t:"mc",q:"Presbyopia in elderly patients means:",o:["Cannot see far objects","Cannot see near objects (farsightedness)","Total blindness","Color blindness"],c:[1],e:"Presbyopia = age-related farsightedness — difficulty seeing close objects due to loss of lens elasticity. Expected change. Myopia = nearsightedness (opposite). Not total vision loss.",a:"B) Cannot see near objects",r:"Sec 4: Eyes — Presbyopia"},
{id:193,s:"HE",t:"mc",q:"A patient with hoarseness of voice may have damage to:",o:["CN V","CN VII","CN X (Vagus)","CN XII"],c:[2],e:"CN X (Vagus) controls voice production via the recurrent laryngeal nerve. Hoarseness may indicate CN X damage. Also test gag reflex and swallowing for CN X function.",a:"C) CN X",r:"Sec 4 + Sec 5: CN X"},
{id:194,s:"HE",t:"sata",q:"Which are signs of sinusitis? (SATA)",o:["Yellow/green discharge","Pale mucosa","Clear discharge","Sinus pain/tenderness","Nasal congestion"],c:[0,3,4],e:"Sinusitis: yellow/green discharge + sinus pain/tenderness + congestion. Pale mucosa + clear discharge = allergies. The color and consistency of discharge differentiates causes.",a:"A, D, E",r:"Sec 4: Nose"},
{id:195,s:"HE",t:"mc",q:"The whisper test assesses:",o:["CN I (Olfactory)","CN VIII (Vestibulocochlear) — hearing","CN II (Optic)","CN X (Vagus)"],c:[1],e:"Whisper test = basic hearing screen for CN VIII. Stand 1-2 feet away, occlude one ear, whisper a word — can the patient repeat it? Also: finger-rub test and tuning fork tests.",a:"B) CN VIII — hearing",r:"Sec 4 + Sec 5: CN VIII"},
{id:196,s:"HE",t:"mc",q:"A patient has an ulcerated area on the penis with yellow serous discharge. This is consistent with:",o:["Gonorrhea","Secondary syphilis","HPV","UTI"],c:[1],e:"Syphilis: starts as small painless chancre, can progress to ulcerated area with yellow serous discharge. Gonorrhea = yellow discharge from meatus with dysuria. HPV = warts.",a:"B) Syphilis",r:"Sec 4 + Sec 9: STIs"},
{id:197,s:"HE",t:"mc",q:"Expected conjunctiva color is:",o:["Bright red","Pink and moist","Pale white","Yellow"],c:[1],e:"Normal conjunctiva = pink and moist. Bright red = conjunctivitis/infection. Pale = anemia or poor perfusion. Yellow = jaundice.",a:"B) Pink and moist",r:"Sec 4: Eyes — Expected"},
{id:198,s:"HE",t:"mc",q:"A patient with vertigo may also exhibit which eye finding?",o:["Ptosis","Exophthalmos","Nystagmus","Amblyopia"],c:[2],e:"Nystagmus (rapid involuntary eye movement) is associated with inner ear disorders causing vertigo. The vestibular system links balance and eye movement through CN VIII.",a:"C) Nystagmus",r:"Sec 4: Eyes — Nystagmus"},
{id:199,s:"HE",t:"mc",q:"An oral assessment reveals bleeding from the nipple of a 55-year-old female. This is:",o:["Expected during menopause","An unexpected finding requiring reporting","Normal if she's on blood thinners","Related to diet"],c:[1],e:"Bleeding/discharge from nipple = unexpected finding requiring investigation. May indicate ductal carcinoma or other pathology. Unexpected breast findings also include new nipple inversion and excoriation.",a:"B) Unexpected — report",r:"Sec 4 + Sec 9: Female GU"},
{id:200,s:"HE",t:"mc",q:"Thrush is most common in which patient populations?",o:["Athletes","Immunocompromised patients (HIV, chemo, prolonged antibiotics)","Post-menopausal women","Neonates only"],c:[1],e:"Thrush (oral Candida) = immunocompromised patients — HIV, prolonged antibiotics, chemotherapy. Can also occur in neonates and debilitated elderly, but immunocompromised is the classic association.",a:"B) Immunocompromised",r:"Sec 4: Throat — Thrush"},
// === NEUROLOGICAL & CRANIAL NERVES (201-270) ===
{id:201,s:"NE",t:"mc",q:"Positive Babinski sign in an adult indicates:",o:["Normal plantar reflex","Upper motor neuron (CNS) lesion","Peripheral neuropathy","Expected finding"],c:[1],e:"Adults: big toe should curl DOWN (negative Babinski). Upward extension + toe fanning = positive Babinski = upper motor neuron damage. Only NORMAL in infants <2 years.",a:"B) Upper motor neuron lesion",r:"Sec 5: Reflexes — Babinski"},
{id:202,s:"NE",t:"mc",q:"GCS score of 7 indicates:",o:["Mild injury","Moderate injury","Severe brain injury — intubation likely","Normal"],c:[2],e:"GCS ≤8 = severe (intubation indicated). 9-12 = moderate. 13-15 = mild. Range: 3 (unresponsive) to 15 (fully alert). Score of 7 is critical.",a:"C) Severe",r:"Sec 5: GCS"},
{id:203,s:"NE",t:"mc",q:"To test CN I (Olfactory), the nurse should:",o:["Use a Snellen chart","Have patient identify familiar scents with one nostril occluded","Touch face with cotton ball","Ask patient to shrug shoulders"],c:[1],e:"CN I = smell. Occlude one nostril, present familiar scents (coffee, mint, vanilla). CN II = Snellen. CN V = cotton ball. CN XI = shrug.",a:"B",r:"Sec 5: CN I"},
{id:204,s:"NE",t:"sata",q:"Which CNs are tested by saying 'Ah' and watching uvula rise? (SATA)",o:["CN VII","CN IX","CN X","CN XII","CN V"],c:[1,2],e:"CN IX (Glossopharyngeal) and CN X (Vagus) are tested together — watch for symmetric uvula/soft palate rise. They're clinically paired for swallowing and gag reflex assessment.",a:"B, C",r:"Sec 5: CN IX, X"},
{id:205,s:"NE",t:"mc",q:"Patient sways when standing with eyes closed, feet together. This is:",o:["Positive Romberg","Negative Romberg","Ataxic gait","Fasciculation"],c:[0],e:"Positive Romberg = swaying/loss of balance with eyes closed. Indicates cerebellar dysfunction or proprioceptive deficit. Negative (maintaining balance) is expected.",a:"A) Positive Romberg",r:"Sec 5: Cerebellar Function"},
{id:206,s:"NE",t:"mc",q:"DTR score of 2 indicates:",o:["Absent","Diminished","Normal","Hyperactive with clonus"],c:[2],e:"DTR scale: 0=absent, 1=diminished, 2=normal, 3=brisk, 4=hyperactive/clonus. 2 is expected normal finding.",a:"C) Normal",r:"Sec 5: Reflexes — DTR"},
{id:207,s:"NE",t:"mc",q:"Jaw clenching against a tongue blade tests which CN function?",o:["CN V sensory","CN V motor (mastication)","CN VII motor","CN XII motor"],c:[1],e:"CN V motor = mastication (chewing/clenching). Palpate masseter and temporalis for strength/symmetry. CN V sensory = facial sensation (cotton ball). CN VII = facial expression. CN XII = tongue.",a:"B) CN V motor",r:"Sec 5: CN V"},
{id:208,s:"NE",t:"mc",q:"Tuning fork on top of skull with sound louder in right ear is called:",o:["Rinne test","Weber test","Whisper test","Romberg test"],c:[1],e:"Weber test = tuning fork on vertex. Should be equal bilaterally. Lateralization (louder on one side) = conductive or sensorineural loss. Rinne = air vs bone conduction.",a:"B) Weber test",r:"Sec 5: CN VIII"},
{id:209,s:"NE",t:"mc",q:"Best screening test for diabetic peripheral neuropathy on soles of feet:",o:["Tuning fork vibration","Monofilament testing","Sharp/dull discrimination","Romberg test"],c:[1],e:"Monofilament testing = standard for loss of protective sensation in diabetic feet. Detects neuropathy before ulceration. Essential preventive screening.",a:"B) Monofilament",r:"Sec 5: Sensation Testing"},
{id:210,s:"NE",t:"mc",q:"GCS: Eyes open to voice (3), confused verbal (4), localizes pain (5). Total score:",o:["10","12","14","8"],c:[1],e:"3 + 4 + 5 = 12. Moderate brain injury (9-12). Know each category's scoring: Eye (1-4), Verbal (1-5), Motor (1-6). Maximum = 15.",a:"B) 12",r:"Sec 5: GCS"},
{id:211,s:"NE",t:"mc",q:"CN XI (Spinal Accessory) is tested by:",o:["Extending tongue","Identifying scents","Shrugging shoulders and turning head against resistance","Tracking finger through visual fields"],c:[2],e:"CN XI = motor nerve for SCM (head turning) and trapezius (shoulder shrugging). Test against resistance bilaterally and compare strength.",a:"C",r:"Sec 5: CN XI"},
{id:212,s:"NE",t:"mc",q:"Inability to look laterally with left eye indicates damage to:",o:["CN III","CN IV","CN VI","CN II"],c:[2],e:"CN VI (Abducens) = lateral rectus = lateral eye movement. CN III = most eye movements (up, in, down-in). CN IV = downward/inward. CN II = visual acuity only.",a:"C) CN VI",r:"Sec 5: CN VI"},
{id:213,s:"NE",t:"tf",q:"True or False: CN X (Vagus) innervates heart, lungs, and GI tract; hoarseness may indicate CN X damage.",o:["True","False"],c:[0],e:"True. Vagus has widest cranial nerve distribution — heart, lungs, GI. Controls gag reflex, swallowing, voice. Hoarseness = recurrent laryngeal nerve involvement.",a:"True",r:"Sec 5: CN X"},
{id:214,s:"NE",t:"mc",q:"Continuous rapid muscle twitching at rest in the calf indicates:",o:["Myoclonus","Fasciculation","Tremor","Spasticity"],c:[1],e:"Fasciculation = continuous rapid twitching at rest = lower motor neuron disease (ALS). Myoclonus = sudden brief jerk. Tremor = rhythmic oscillation. Spasticity = increased tone (upper motor neuron).",a:"B) Fasciculation",r:"Sec 5: Involuntary Movements"},
{id:215,s:"NE",t:"mc",q:"The finger-to-nose test assesses:",o:["Visual acuity","Cerebellar coordination","Peripheral sensation","DTR"],c:[1],e:"Finger-to-nose = cerebellar coordination. Patient alternates touching own nose and nurse's finger rapidly. Assess for dysmetria (over/undershooting) and intention tremor.",a:"B) Cerebellar coordination",r:"Sec 5: Cerebellar Function"},
{id:216,s:"NE",t:"mc",q:"Heel-to-shin test: patient slides heel smoothly up opposite shin. This tests:",o:["Lower extremity sensation","Cerebellar coordination","Deep tendon reflexes","Muscle strength"],c:[1],e:"Heel-to-shin = cerebellar coordination of lower extremities. Inability to perform smoothly = cerebellar dysfunction. Pairs with finger-to-nose for upper extremities.",a:"B) Cerebellar coordination",r:"Sec 5: Cerebellar Function"},
{id:217,s:"NE",t:"mc",q:"Paresthesia (pins-and-needles) indicates:",o:["Normal sensation","Nerve involvement","Cerebellar dysfunction","Muscle weakness"],c:[1],e:"Paresthesia = tingling/pins-and-needles indicating nerve involvement. Can occur in peripheral neuropathy, nerve compression, or spinal cord lesions.",a:"B) Nerve involvement",r:"Sec 5: Sensation Testing"},
{id:218,s:"NE",t:"mc",q:"The biceps reflex is tested by striking the thumb placed over the biceps tendon in the:",o:["Popliteal fossa","Antecubital fossa","Achilles tendon area","Wrist"],c:[1],e:"Biceps reflex: strike thumb on biceps tendon in antecubital fossa → forearm flexion. Patellar reflex: below patella → leg extension. Achilles: above heel → plantar flexion.",a:"B) Antecubital fossa",r:"Sec 5: Reflexes"},
{id:219,s:"NE",t:"mc",q:"GCS Eye Opening: spontaneous = ___",o:["1","2","3","4"],c:[3],e:"Eye: Spontaneous=4, To voice=3, To pain=2, None=1. This is the highest score in the Eye category. Total GCS ranges 3-15.",a:"D) 4",r:"Sec 5: GCS"},
{id:220,s:"NE",t:"mc",q:"GCS Motor: obeys commands = ___",o:["4","5","6","3"],c:[2],e:"Motor: Obeys commands=6, Localizes pain=5, Withdraws=4, Abnormal flexion=3, Extension=2, None=1. Obeys commands is the highest motor score.",a:"C) 6",r:"Sec 5: GCS"},
{id:221,s:"NE",t:"mc",q:"The mnemonic 'Oh Oh Oh To Touch And Feel Very Green Velvet Absolutely Heavenly' helps remember:",o:["Assessment order","Cranial nerve names in order","Heart auscultation sites","Abdominal quadrants"],c:[1],e:"O=Olfactory, O=Optic, O=Oculomotor, T=Trochlear, T=Trigeminal, A=Abducens, F=Facial, V=Vestibulocochlear, G=Glossopharyngeal, V=Vagus, A=Accessory, H=Hypoglossal.",a:"B) CN names",r:"Sec 5: Mnemonic"},
{id:222,s:"NE",t:"mc",q:"'Some Say Marry Money But My Brother Says Big Brains Matter More' indicates cranial nerve types as:",o:["All sensory","All motor","S,S,M,M,B,M,B,S,B,B,M,M","S,M,S,M,B,S,B,M,B,B,S,M"],c:[2],e:"S=Sensory, S=Sensory, M=Motor, M=Motor, B=Both, M=Motor, B=Both, S=Sensory, B=Both, B=Both, M=Motor, M=Motor. Maps to CN I through XII.",a:"C",r:"Sec 5: Mnemonic — CN Types"},
{id:223,s:"NE",t:"mc",q:"CN III (Oculomotor) controls all EXCEPT:",o:["Pupil constriction","Upper eyelid elevation","Lateral eye movement","Upward eye movement"],c:[2],e:"CN III controls pupil constriction/dilation, eyelid elevation, and most eye movements (up, in, down-in). LATERAL eye movement = CN VI (Abducens). This distinction is heavily tested.",a:"C) Lateral eye movement",r:"Sec 5: CN III"},
{id:224,s:"NE",t:"mc",q:"CN IV (Trochlear) moves the eye:",o:["Laterally","Upward","Downward and inward","In all directions"],c:[2],e:"CN IV = superior oblique muscle = downward and inward eye movement. Dysfunction causes diplopia (double vision) on downward gaze, such as when reading or going down stairs.",a:"C) Downward and inward",r:"Sec 5: CN IV"},
{id:225,s:"NE",t:"mc",q:"CN VII (Facial) has both motor and sensory functions. The sensory component controls:",o:["Facial sensation in three branches","Taste on anterior 2/3 of tongue","Hearing","Smell"],c:[1],e:"CN VII sensory = taste on anterior 2/3 of tongue. Motor = facial expression. CN V = facial sensation. CN IX = taste on posterior 1/3. CN VIII = hearing. CN I = smell.",a:"B) Taste on anterior 2/3 of tongue",r:"Sec 5: CN VII"},
{id:226,s:"NE",t:"mc",q:"To test rapid lingual movements (CN XII), ask the patient to say:",o:["'Ah'","'99'","'You can't teach an old dog new tricks'","Their full name"],c:[2],e:"'You can't teach an old dog new tricks' requires rapid tongue movements, testing CN XII (Hypoglossal). 'Ah' tests CN IX/X. '99' tests fremitus. This tests articulation speed.",a:"C",r:"Sec 5: CN XII"},
{id:227,s:"NE",t:"mc",q:"A positive Babinski is NORMAL in which population?",o:["Adults over 65","Infants under 2 years","Pregnant women","Athletes"],c:[1],e:"Positive Babinski (upgoing toe, fanning) is NORMAL in infants <2 due to immature CNS. In adults, it's ALWAYS abnormal = upper motor neuron damage. Important age distinction.",a:"B) Infants under 2",r:"Sec 5: Reflexes — Babinski"},
{id:228,s:"NE",t:"mc",q:"The patellar reflex tests the reflex arc at which level?",o:["Cervical spine","Thoracic spine","Lumbar spine (L3-L4)","Sacral spine"],c:[2],e:"Patellar (knee-jerk) reflex = L3-L4 level. Striking the patellar tendon causes quadriceps contraction and leg extension. Absent patellar reflex may indicate L3-L4 nerve root involvement.",a:"C) Lumbar (L3-L4)",r:"Sec 5: Reflexes"},
{id:229,s:"NE",t:"mc",q:"Ataxia is characterized by:",o:["Increased muscle tone with resistance","Unsteady, wide-based, uncoordinated gait","Rapid rhythmic tremor at rest","Sudden brief muscle jerk"],c:[1],e:"Ataxia = unsteady, broad-based gait indicating cerebellar dysfunction or intoxication. Spasticity = increased tone. Resting tremor = Parkinson's. Myoclonus = sudden jerk.",a:"B) Unsteady, wide-based gait",r:"Sec 5: Cerebellar + Sec 8: Gait"},
{id:230,s:"NE",t:"mc",q:"Sharp vs dull discrimination is tested with:",o:["Tuning fork","Monofilament","Pointed end vs eraser of a pencil","Cotton ball"],c:[2],e:"Sharp/dull test: alternate pointed end (sharp) and eraser (dull) of a pencil on skin — patient identifies which they feel. Tests different sensory nerve fibers (spinothalamic tract).",a:"C) Pencil point vs eraser",r:"Sec 5: Sensation Testing"},
{id:231,s:"NE",t:"mc",q:"Vibration sensation is tested with a tuning fork applied to:",o:["Soft tissue areas","Bony prominences","Lymph nodes","Pulse points"],c:[1],e:"Vibration test: tuning fork on bony prominences (malleoli, knuckles, sternum). Tests posterior column/medial lemniscal pathway. Often diminished in peripheral neuropathy.",a:"B) Bony prominences",r:"Sec 5: Sensation Testing"},
{id:232,s:"NE",t:"mc",q:"A patient has a GCS of 15. This indicates:",o:["Severe brain injury","Moderate brain injury","Mild brain injury","Fully alert and oriented"],c:[3],e:"GCS 15 = maximum score = fully alert. Eye(4) + Verbal(5) + Motor(6) = 15. Patient opens eyes spontaneously, is oriented, and obeys commands. 13-15 = mild. ≤8 = severe.",a:"D) Fully alert",r:"Sec 5: GCS"},
{id:233,s:"NE",t:"mc",q:"The Achilles reflex tests by striking above the heel, expecting:",o:["Leg extension","Forearm flexion","Plantar flexion of the foot","Dorsiflexion of the foot"],c:[2],e:"Achilles reflex: support foot in dorsiflexion, strike Achilles tendon → plantar flexion (foot points down). Tests S1-S2 nerve roots. Absent in Achilles tendon rupture or S1 radiculopathy.",a:"C) Plantar flexion",r:"Sec 5: Reflexes"},
{id:234,s:"NE",t:"mc",q:"A patient with DTR score of 4 and clonus has:",o:["Normal reflexes","Diminished reflexes","Hyperactive reflexes suggesting upper motor neuron damage","Absent reflexes"],c:[2],e:"DTR 4 = hyperactive with clonus (rhythmic oscillating movements). Suggests upper motor neuron lesion. 0=absent (lower motor neuron), 2=normal, 4=hyperactive (upper motor neuron).",a:"C) Hyperactive — upper motor neuron",r:"Sec 5: DTR Scale"},
{id:235,s:"NE",t:"mc",q:"CN IX (Glossopharyngeal) controls taste on which portion of the tongue?",o:["Entire tongue","Anterior 2/3","Posterior 1/3","Tip only"],c:[2],e:"CN IX = taste on posterior 1/3. CN VII = taste on anterior 2/3. Together they provide taste sensation for the entire tongue but are distinct nerves with different distributions.",a:"C) Posterior 1/3",r:"Sec 5: CN IX"},
{id:236,s:"NE",t:"mc",q:"The gag reflex tests which cranial nerves?",o:["CN V and VII","CN IX and X","CN XI and XII","CN II and III"],c:[1],e:"Gag reflex = CN IX (Glossopharyngeal) and CN X (Vagus). Touch posterior pharynx — should elicit gagging. Absent gag = CN IX/X dysfunction. Risk for aspiration.",a:"B) CN IX and X",r:"Sec 5: CN IX, X"},
{id:237,s:"NE",t:"mc",q:"A tic is defined as:",o:["Continuous rapid twitching at rest","Involuntary repetitive movement of a muscle group","Rhythmic oscillating movement","Sudden brief muscle jerk"],c:[1],e:"Tic = involuntary, repetitive movement (neurological or psychogenic). Examples: grimaces, winks, shoulder shrugs. Fasciculation = continuous twitching. Tremor = rhythmic. Myoclonus = sudden jerk.",a:"B) Involuntary repetitive movement",r:"Sec 5: Involuntary Movements"},
{id:238,s:"NE",t:"mc",q:"Tremors that occur at rest are most associated with:",o:["Essential tremor","Cerebellar disorder","Parkinson's disease","Anxiety"],c:[2],e:"Resting tremors = Parkinson's disease (pill-rolling tremor). Intentional tremors (during movement) = essential tremor or cerebellar disorder. Rest vs action distinguishes the type.",a:"C) Parkinson's",r:"Sec 5: Involuntary Movements — Tremors"},
{id:239,s:"NE",t:"mc",q:"Myoclonus is a:",o:["Continuous rhythmic tremor","Sudden brief muscle jerk","Sustained involuntary contraction","Gradual muscle wasting"],c:[1],e:"Myoclonus = sudden, brief muscle jerk. Examples: hiccups, seizure activity, hypnic jerks (when falling asleep). Distinguishes from fasciculation (continuous) and tremor (rhythmic).",a:"B) Sudden brief muscle jerk",r:"Sec 5: Involuntary Movements"},
{id:240,s:"NE",t:"mc",q:"Spasticity indicates damage to:",o:["Lower motor neurons","Upper motor neurons","Peripheral nerves","Cerebellar pathways"],c:[1],e:"Spasticity = increased muscle tone with velocity-dependent resistance to passive extension = upper motor neuron damage (stroke, MS). Lower motor neuron = flaccidity and fasciculation.",a:"B) Upper motor neurons",r:"Sec 5: Involuntary Movements — Spasticity"},
{id:241,s:"NE",t:"mc",q:"Soft touch sensation is tested with:",o:["Tuning fork","Sharp pencil point","Cotton ball lightly applied to skin","Monofilament"],c:[2],e:"Cotton ball lightly applied = soft/light touch. Tests anterior spinothalamic tract. Sharp/dull = pencil. Vibration = tuning fork. Protective sensation = monofilament.",a:"C) Cotton ball",r:"Sec 5: Sensation Testing"},
{id:242,s:"NE",t:"mc",q:"GCS Verbal: 'inappropriate words' scores as:",o:["5","4","3","2"],c:[2],e:"Verbal: Oriented=5, Confused=4, Inappropriate words=3, Incomprehensible sounds=2, None=1. 'Inappropriate words' = recognizable words but not conversational or contextual.",a:"C) 3",r:"Sec 5: GCS"},
{id:243,s:"NE",t:"mc",q:"A patient can localize pain but does not follow commands. GCS Motor score:",o:["6","5","4","3"],c:[1],e:"Motor: Obeys commands=6, Localizes pain=5, Withdraws=4, Abnormal flexion=3, Extension=2, None=1. Localizing (reaching toward the pain stimulus purposefully) = 5.",a:"B) 5",r:"Sec 5: GCS"},
{id:244,s:"NE",t:"mc",q:"Rigidity with a ratchet-like quality ('cogwheel') is associated with:",o:["Stroke","Parkinson's disease","ALS","Multiple sclerosis"],c:[1],e:"Cogwheel rigidity = Parkinson's hallmark. 'Lead pipe' rigidity = uniform resistance. Both = resistance throughout full ROM. Different from spasticity (velocity-dependent, upper motor neuron).",a:"B) Parkinson's",r:"Sec 5/8: Rigidity"},
{id:245,s:"NE",t:"mc",q:"CN II (Optic) is tested with:",o:["Tuning fork","Snellen chart at 20 feet","Cotton ball on face","Tongue depressor"],c:[1],e:"CN II = Optic = vision. Snellen chart (distance, 20ft), Rosenbaum (near, 14in), confrontation (visual fields). It is purely sensory — no motor component.",a:"B) Snellen chart",r:"Sec 5: CN II"},
{id:246,s:"NE",t:"mc",q:"A new-onset confused patient has a GCS assessed at: Eyes open to pain (2), Incomprehensible sounds (2), Abnormal flexion (3). Total GCS:",o:["5","6","7","8"],c:[2],e:"2 + 2 + 3 = 7. GCS ≤8 = severe brain injury, intubation typically indicated. This patient is critically impaired and needs immediate intervention.",a:"C) 7",r:"Sec 5: GCS"},
{id:247,s:"NE",t:"mc",q:"The nurse has the patient push their tongue against each cheek. This tests:",o:["CN V","CN IX","CN XII","CN X"],c:[2],e:"Tongue push against cheek = CN XII (Hypoglossal) strength testing. Also: tongue extension to midline and rapid lingual movement assessment.",a:"C) CN XII",r:"Sec 5: CN XII"},
{id:248,s:"NE",t:"mc",q:"CN VIII (Vestibulocochlear) is classified as:",o:["Motor only","Sensory only","Both motor and sensory","Neither"],c:[1],e:"CN VIII = Sensory only. Controls hearing and balance/equilibrium. Tested with whisper test, finger-rub, Weber test, and Rinne test. Mnemonic: S in the type sequence.",a:"B) Sensory",r:"Sec 5: CN VIII"},
{id:249,s:"NE",t:"mc",q:"Which CN is BOTH sensory and motor, controlling facial expression and taste?",o:["CN V","CN VII","CN IX","CN XII"],c:[1],e:"CN VII (Facial) = Both. Motor: facial expression. Sensory: taste on anterior 2/3 of tongue. CN V = Both (sensation + mastication). CN XII = Motor only.",a:"B) CN VII",r:"Sec 5: CN VII"},
{id:250,s:"NE",t:"mc",q:"DTR score of 0 indicates:",o:["Normal reflex","Absent reflex","Hyperactive reflex","Brisk reflex"],c:[1],e:"0 = absent reflex. May indicate lower motor neuron damage, nerve root compression, or peripheral neuropathy. Always compare bilaterally and consider clinical context.",a:"B) Absent",r:"Sec 5: DTR"},
{id:251,s:"NE",t:"mc",q:"A patient with cerebellar dysfunction would demonstrate difficulty with:",o:["Remembering names","Coordinated rapid alternating movements","Hearing whispered words","Seeing distant objects"],c:[1],e:"Cerebellar dysfunction impairs coordination — difficulty with rapid alternating movements, finger-to-nose, heel-to-shin, and smooth gait. Positive Romberg may also be present.",a:"B) Coordinated movements",r:"Sec 5: Cerebellar Function"},
{id:252,s:"NE",t:"mc",q:"Testing CN V sensory involves touching the face with a cotton ball in how many areas?",o:["One","Two","Three (for three branches)","Six"],c:[2],e:"CN V has three sensory branches: ophthalmic (V1 — forehead), maxillary (V2 — cheek), mandibular (V3 — jaw). Touch each area bilaterally and compare sensation.",a:"C) Three",r:"Sec 5: CN V"},
{id:253,s:"NE",t:"mc",q:"CN XI is classified as:",o:["Sensory only","Motor only","Both","Neither"],c:[1],e:"CN XI (Spinal Accessory) = Motor only. Controls SCM (head turning) and trapezius (shoulder shrugging). Mnemonic position: 'M' in 'Some Say Marry Money But My Brother Says Big Brains Matter More.'",a:"B) Motor only",r:"Sec 5: CN XI"},
{id:254,s:"NE",t:"mc",q:"The nurse puffs out their cheeks. The patient is asked to do the same. This tests:",o:["CN V","CN VII","CN IX","CN XII"],c:[1],e:"Puffing cheeks = CN VII (Facial) motor function. Other CN VII tests: smile, frown, raise eyebrows, close eyes tightly. Observe for symmetry — asymmetry = Bell's Palsy or stroke.",a:"B) CN VII",r:"Sec 5: CN VII"},
{id:255,s:"NE",t:"mc",q:"A patient with CN III palsy would present with:",o:["Inability to shrug shoulders","Ptosis and dilated pupil on affected side","Tongue deviation","Loss of smell"],c:[1],e:"CN III palsy: ptosis (drooping eyelid), dilated pupil (loss of constriction), and impaired eye movement (up, in, down-in). Eye deviates 'down and out' due to unopposed CN IV and VI.",a:"B) Ptosis and dilated pupil",r:"Sec 5: CN III"},
{id:256,s:"NE",t:"tf",q:"True or False: Babinski sign in a 6-month-old infant is an abnormal finding requiring immediate evaluation.",o:["True","False"],c:[1],e:"False. Positive Babinski is NORMAL in infants under 2 years due to immature CNS myelination. It becomes abnormal after age 2 when the CNS is mature enough for normal plantar response.",a:"False",r:"Sec 5: Reflexes — Babinski"},
{id:257,s:"NE",t:"mc",q:"The Romberg test primarily assesses:",o:["Visual acuity","Balance and proprioception","Hearing","Muscle strength"],c:[1],e:"Romberg test = balance and proprioception. Patient stands feet together, arms at sides, eyes open then closed. Swaying/falling with eyes closed = positive = cerebellar or proprioceptive dysfunction.",a:"B) Balance and proprioception",r:"Sec 5: Cerebellar Function"},
{id:258,s:"NE",t:"mc",q:"A hypnic jerk when falling asleep is an example of:",o:["Fasciculation","Myoclonus","Tremor","Tic"],c:[1],e:"Hypnic jerk = myoclonus (sudden, brief muscle jerk). Other examples: hiccups, seizure activity. These are involuntary and typically benign when occurring during sleep onset.",a:"B) Myoclonus",r:"Sec 5: Involuntary Movements"},
{id:259,s:"NE",t:"mc",q:"The nurse assesses a patient and finds GCS ≤8. The priority nursing action is:",o:["Recheck in 30 minutes","Continue comprehensive assessment","Prepare for possible intubation and notify HCP immediately","Document and continue monitoring"],c:[2],e:"GCS ≤8 = severe brain injury. Intubation is typically indicated to protect the airway. This is a RED FLAG — immediate notification and preparation for advanced airway management.",a:"C",r:"Sec 5: GCS — RED FLAG"},
{id:260,s:"NE",t:"mc",q:"Decreased DTRs (score 1) may indicate:",o:["Upper motor neuron damage","Lower motor neuron damage","Normal aging","Cerebellar dysfunction"],c:[1],e:"Diminished reflexes (1) suggest lower motor neuron damage or peripheral neuropathy. Upper motor neuron damage causes HYPERactive reflexes (3-4). Different pathways produce opposite effects.",a:"B) Lower motor neuron damage",r:"Sec 5: DTR"},
{id:261,s:"NE",t:"mc",q:"Sudden facial asymmetry requires the nurse to differentiate between:",o:["Allergic reaction and infection","Bell's Palsy and stroke","Migraine and tension headache","Hearing loss and vision loss"],c:[1],e:"Sudden facial asymmetry = RED FLAG. Could be Bell's Palsy (CN VII, typically lower face) or stroke (can affect upper and lower face, with other neurological deficits). Perform rapid neuro assessment.",a:"B) Bell's Palsy vs stroke",r:"Sec 5: RED FLAG"},
{id:262,s:"NE",t:"mc",q:"CN XII (Hypoglossal) is classified as:",o:["Sensory","Motor","Both","Neither"],c:[1],e:"CN XII = Motor only. Controls tongue movement. Mnemonic: last 'M' in 'Some Say Marry Money But My Brother Says Big Brains Matter More.' Motor functions: tongue protrusion, lateral push, rapid speech.",a:"B) Motor",r:"Sec 5: CN XII"},
{id:263,s:"NE",t:"mc",q:"New-onset confusion or altered LOC in any patient is a:",o:["Normal finding if the patient is elderly","RED FLAG requiring immediate assessment","Expected post-meal finding","Sign of dehydration only"],c:[1],e:"New-onset confusion or altered LOC is ALWAYS a RED FLAG. It can indicate stroke, infection, metabolic emergency, head injury, or medication reaction. Never dismiss as 'normal.'",a:"B) RED FLAG",r:"Sec 5: RED FLAGS"},
{id:264,s:"NE",t:"mc",q:"The nurse performs a finger-rub test near the patient's ear. This screens for:",o:["CN I (smell)","CN VIII (hearing)","CN V (facial sensation)","CN VII (facial movement)"],c:[1],e:"Finger-rub test = basic hearing screen for CN VIII. Rub fingers near each ear — can the patient hear it? Quick bedside test before formal audiometry.",a:"B) CN VIII hearing",r:"Sec 5: CN VIII"},
{id:265,s:"NE",t:"mc",q:"Lead-pipe rigidity (uniform resistance throughout ROM) is associated with:",o:["Normal muscle tone","Parkinson's disease","Stroke","ALS"],c:[1],e:"Lead-pipe rigidity = uniform, constant resistance throughout ROM. Cogwheel rigidity = ratcheting resistance. Both are Parkinson's hallmarks. Different from spasticity (velocity-dependent).",a:"B) Parkinson's",r:"Sec 5: Rigidity"},
{id:266,s:"NE",t:"mc",q:"A patient with ALS would most likely exhibit:",o:["Spasticity","Fasciculations","Cogwheel rigidity","Ataxia"],c:[1],e:"ALS = lower motor neuron disease = fasciculations (continuous rapid twitching). ALS also involves upper motor neurons later, but fasciculation is the classic early finding.",a:"B) Fasciculations",r:"Sec 5: Involuntary Movements"},
{id:267,s:"NE",t:"mc",q:"CN I (Olfactory) is classified as:",o:["Motor only","Sensory only","Both","Neither"],c:[1],e:"CN I = Sensory only = smell. First 'S' in 'Some Say Marry Money...' Tested with familiar scents, one nostril occluded at a time.",a:"B) Sensory",r:"Sec 5: CN I"},
{id:268,s:"NE",t:"mc",q:"Testing the Achilles reflex, the nurse supports the foot in dorsiflexion and strikes:",o:["Below the patella","The biceps tendon","Above the heel on the Achilles tendon","The ball of the foot"],c:[2],e:"Achilles reflex: dorsiflex the foot, strike Achilles tendon above the heel → expected response is plantar flexion. Tests S1-S2 reflex arc.",a:"C) Above heel on Achilles",r:"Sec 5: Reflexes"},
{id:269,s:"NE",t:"mc",q:"GCS Motor: abnormal flexion (decorticate posturing) scores as:",o:["2","3","4","5"],c:[1],e:"Motor: Obeys=6, Localizes=5, Withdraws=4, Abnormal flexion (decorticate)=3, Extension (decerebrate)=2, None=1. Decorticate = arms flexed, legs extended.",a:"B) 3",r:"Sec 5: GCS"},
{id:270,s:"NE",t:"mc",q:"The Babinski reflex is performed by stroking the plantar surface of the foot from:",o:["Ball to heel","Heel to ball of foot","Side to side","Toe to toe"],c:[1],e:"Stroke from HEEL to BALL of foot along the lateral edge, then curve medially. Direction matters for proper technique. Response: normal adult = big toe curls down.",a:"B) Heel to ball",r:"Sec 5: Reflexes — Babinski"},
// === CARDIOVASCULAR (271-330) ===
{id:271,s:"CV",t:"mc",q:"Low-pitched sound after S2 in a 65-year-old with heart failure is likely:",o:["S1","S3 (ventricular gallop)","S4 (atrial gallop)","Split S2"],c:[1],e:"S3 follows S2 (early diastole) = rapid ventricular filling. In adults >40, S3 = unexpected = heart failure. Expected in children, young adults, pregnancy, athletes.",a:"B) S3",r:"Sec 6: Heart Sounds — S3"},
{id:272,s:"CV",t:"mc",q:"'All People Eat Too Much' — the Mitral site is at:",o:["Right 2nd ICS, RSB","Left 2nd ICS, LSB","Left 4th ICS, LSB","Left 5th ICS, MCL"],c:[3],e:"APETM: Aortic (R2ICS), Pulmonic (L2ICS), Erb's (L3ICS), Tricuspid (L4ICS), Mitral (L5ICS MCL). Mitral = apex = PMI = where S1 is best heard.",a:"D) Left 5th ICS, MCL",r:"Sec 6: Auscultation Landmarks"},
{id:273,s:"CV",t:"mc",q:"Apical pulse 88, radial pulse 72. This is:",o:["Tachycardia","Bradycardia","Pulse deficit","Bounding pulse"],c:[2],e:"Pulse deficit = apical > radial. Deficit of 16 beats. Indicates some beats too weak to reach periphery. Associated with atrial fibrillation. Report immediately.",a:"C) Pulse deficit",r:"Sec 6: Pulse Assessment"},
{id:274,s:"CV",t:"mc",q:"Correct BP cuff width is approximately what % of arm circumference?",o:["20%","30%","40%","50%"],c:[2],e:"Cuff width = ~40% of arm circumference. Too small = falsely HIGH. Too large = falsely LOW. Always measure arm and select appropriate cuff size.",a:"C) 40%",r:"Sec 6: BP Measurement"},
{id:275,s:"CV",t:"sata",q:"Which are correct for BP measurement? (SATA)",o:["Legs crossed","Arm at heart level","Deflate at 2 mmHg/sec","Use arm with active IV","Wait 1-2 min between readings"],c:[1,2,4],e:"Arm at heart level, deflate 2mmHg/sec, wait 1-2 min between readings. Legs UNCROSSED, feet flat. NEVER use arm with IV, surgical site, shunt, or lymph node dissection.",a:"B, C, E",r:"Sec 6: BP Measurement"},
{id:276,s:"CV",t:"mc",q:"JVD at 30-45 degrees indicates:",o:["Left-sided HF","Right-sided HF or fluid overload","Dehydration","Aortic stenosis"],c:[1],e:"JVD = right-sided heart failure or fluid overload. Right side can't pump forward → venous backup. Left-sided HF = pulmonary symptoms (crackles, dyspnea).",a:"B) Right-sided HF",r:"Sec 6: JVD"},
{id:277,s:"CV",t:"mc",q:"S1 ('Lub') is caused by closure of:",o:["Aortic and pulmonic valves","Mitral and tricuspid valves","Mitral and aortic valves","Tricuspid and pulmonic valves"],c:[1],e:"S1 = AV valve closure (mitral + tricuspid) = beginning of systole. S2 = semilunar valve closure (aortic + pulmonic) = beginning of diastole.",a:"B) Mitral and tricuspid",r:"Sec 6: S1"},
{id:278,s:"CV",t:"tf",q:"True or False: S4 is an expected finding in athletes and pregnancy.",o:["True","False"],c:[1],e:"False. S4 is ALWAYS abnormal. S3 is expected in children, athletes, pregnancy. S4 = stiff ventricle from HTN or hypertrophic cardiomyopathy. Never normal.",a:"False",r:"Sec 6: S4"},
{id:279,s:"CV",t:"mc",q:"Irregular pulse — nurse should:",o:["Document and continue","Count for 15 sec × 4","Count full 60 sec and assess apical and radial simultaneously","Reposition and retry"],c:[2],e:"Irregular rhythm → count full 60 seconds. Assess apical and radial simultaneously to detect pulse deficit. Pulse deficit = a-fib or other arrhythmia.",a:"C",r:"Sec 6: Pulse Assessment"},
{id:280,s:"CV",t:"mc",q:"Visible heave at PMI indicates:",o:["Normal","Ventricular hypertrophy/enlargement","Atrial fibrillation","Pericarditis"],c:[1],e:"PMI is normally felt, not seen. A VISIBLE heave/lift = ventricular hypertrophy or enlargement. Report to HCP. PMI location: 5th ICS, MCL (apex).",a:"B) Ventricular hypertrophy",r:"Sec 6: PMI"},
{id:281,s:"CV",t:"mc",q:"Nicotine affects the cardiovascular system by acting as a:",o:["Vasodilator","Vasoconstrictor","Anticoagulant","Diuretic"],c:[1],e:"Nicotine = vasoconstrictor → narrows vessels → increases resistance → heart works harder → elevated BP and HR. Include smoking cessation in ALL cardiac teaching.",a:"B) Vasoconstrictor",r:"Sec 6: Smoking/Nicotine"},
{id:282,s:"CV",t:"mc",q:"The bell of the stethoscope is for:",o:["High-pitched sounds","Low-pitched sounds like murmurs","Bowel sounds","Lung sounds"],c:[1],e:"Bell = low-pitched (murmurs, bruits). Diaphragm = high-pitched (S1/S2, bowel sounds, lung sounds). Always on bare skin, never over clothing.",a:"B) Low-pitched murmurs",r:"Sec 6: Auscultation"},
{id:283,s:"CV",t:"mc",q:"Normal BP is:",o:["130/90 mmHg","120/80 mmHg","Less than 120/80 mmHg","140/90 mmHg"],c:[2],e:"Normal = less than 120/80 mmHg. Elevated = 120-129/<80. Stage 1 HTN = 130-139/80-89. Stage 2 = ≥140/≥90.",a:"C) Less than 120/80",r:"Sec 6: BP"},
{id:284,s:"CV",t:"mc",q:"S2 ('Dub') is best heard at:",o:["Mitral area (apex)","Aortic area (R 2nd ICS)","Erb's point","Tricuspid area"],c:[1],e:"S2 = semilunar valve closure = beginning of diastole. Best at aortic area (R 2nd ICS, RSB). Higher-pitched than S1.",a:"B) Aortic area",r:"Sec 6: S2"},
{id:285,s:"CV",t:"mc",q:"S1 is best heard at the:",o:["Aortic area","Pulmonic area","Tricuspid area","Apex/Mitral area"],c:[3],e:"S1 = AV valve closure = beginning of systole. Best at the apex (Mitral area, 5th ICS, MCL). S1 is also where the PMI is located.",a:"D) Apex/Mitral",r:"Sec 6: S1"},
{id:286,s:"CV",t:"mc",q:"S3 is EXPECTED in all EXCEPT:",o:["Children","Young adults","Pregnancy","Adults over 40"],c:[3],e:"S3 is expected in children, young adults, pregnancy, and athletes. In adults >40, S3 = heart failure until proven otherwise. RED FLAG.",a:"D) Adults over 40",r:"Sec 6: S3"},
{id:287,s:"CV",t:"mc",q:"S4 is caused by atrial contraction against a stiff ventricle and is associated with:",o:["Normal aging","Hypertension and hypertrophic cardiomyopathy","Dehydration","Aortic regurgitation"],c:[1],e:"S4 = atrial gallop = stiff ventricle. Associated with HTN and hypertrophic cardiomyopathy. Heard late in diastole at the apex. ALWAYS abnormal.",a:"B) HTN and hypertrophic cardiomyopathy",r:"Sec 6: S4"},
{id:288,s:"CV",t:"mc",q:"The deflation rate when measuring BP should be:",o:["5 mmHg/sec","10 mmHg/sec","2 mmHg/sec","1 mmHg/sec"],c:[2],e:"Deflate at 2 mmHg per second. Too fast = miss the systolic/diastolic sounds. Too slow = venous congestion and falsely high reading. Standard technique.",a:"C) 2 mmHg/sec",r:"Sec 6: BP Measurement"},
{id:289,s:"CV",t:"mc",q:"Orthopnea is:",o:["Chest pain on exertion","SOB when lying flat","Fainting with position change","Rapid heart rate"],c:[1],e:"Orthopnea = dyspnea when lying flat. Ask: 'How many pillows do you need to sleep?' Document as 2-pillow, 3-pillow orthopnea. Sign of heart failure.",a:"B) SOB when lying flat",r:"Sec 6: Cardiac History"},
{id:290,s:"CV",t:"mc",q:"When taking BP, inflate the cuff to:",o:["200 mmHg always","30 mmHg above expected systolic","Just above where the pulse disappears","100 mmHg above expected systolic"],c:[1],e:"Inflate to 30 mmHg above expected systolic. Over-inflation causes patient discomfort. Under-inflation may miss the true systolic reading (auscultatory gap).",a:"B) 30 mmHg above expected systolic",r:"Sec 6: BP Measurement"},
{id:291,s:"CV",t:"mc",q:"Cyanosis of lips and nail beds indicates:",o:["Anemia","Hypoxia or poor perfusion","Jaundice","Normal in cold weather"],c:[1],e:"Cyanosis = bluish discoloration from deoxygenated hemoglobin. Late sign of hypoxia. Check lips, fingernails, nail beds. In dark-skinned patients, assess oral mucosa and nail beds.",a:"B) Hypoxia",r:"Sec 6: Cardiac History + Sec 7"},
{id:292,s:"CV",t:"mc",q:"A patient reports skipped heartbeats. The medical term is:",o:["Syncope","Palpitations","Murmur","Bruit"],c:[1],e:"Palpitations = awareness of heartbeat, often described as irregular, rapid, or skipped beats. May indicate arrhythmia. Syncope = fainting. Murmur = abnormal heart sound. Bruit = vascular sound.",a:"B) Palpitations",r:"Sec 6: Cardiac History"},
{id:293,s:"CV",t:"mc",q:"Assess radial pulse for ___ seconds × 2 for pulse rate.",o:["15","30","60","10"],c:[1],e:"Standard: radial pulse for 30 seconds × 2 = rate. If irregular, count full 60 seconds. Simultaneously check apical and radial if irregularity suspected.",a:"B) 30",r:"Sec 6: Pulse Assessment"},
{id:294,s:"CV",t:"mc",q:"Which is NOT an appropriate arm for BP measurement?",o:["Right arm of a healthy patient","Left arm with a healed fracture","Arm with a dialysis shunt","Non-dominant arm of a stroke patient"],c:[2],e:"NEVER take BP on arm with shunt, IV, surgical site, or lymph node dissection. A dialysis shunt is an arteriovenous access — compression could damage it. Healed fracture is generally OK.",a:"C) Arm with dialysis shunt",r:"Sec 6: BP Measurement"},
{id:295,s:"CV",t:"mc",q:"S1 is a high-pitched, dull sound best heard with the:",o:["Bell","Diaphragm","Either equally","Bare hand"],c:[1],e:"S1 (and S2) are high-pitched sounds heard with the DIAPHRAGM. Bell = low-pitched sounds (S3, S4, murmurs). Always on bare skin.",a:"B) Diaphragm",r:"Sec 6: S1"},
{id:296,s:"CV",t:"mc",q:"Erb's Point is at:",o:["R 2nd ICS, RSB","L 2nd ICS, LSB","L 3rd ICS, LSB","L 5th ICS, MCL"],c:[2],e:"Erb's Point = Left 3rd ICS, LSB. Best for hearing aortic and pulmonic murmurs. Third site in APETM mnemonic.",a:"C) L 3rd ICS, LSB",r:"Sec 6: Auscultation Landmarks"},
{id:297,s:"CV",t:"mc",q:"Time of day can affect BP — morning readings are typically:",o:["Lower","Higher","The same as evening","Irrelevant"],c:[1],e:"Morning BP readings tend to be higher due to the morning surge in cortisol and sympathetic activity. Always note when the reading was taken. NCLEX TIP.",a:"B) Higher",r:"Sec 6: NCLEX TIP"},
{id:298,s:"CV",t:"mc",q:"Bilateral lower extremity edema in a cardiac patient suggests:",o:["Peripheral arterial disease","Fluid overload or heart failure","Deep vein thrombosis","Normal finding"],c:[1],e:"Bilateral edema = systemic cause (HF, fluid overload, renal failure). Unilateral edema = local cause (DVT, venous insufficiency). Ask about onset, duration, and associated symptoms.",a:"B) Fluid overload/HF",r:"Sec 6: Cardiac History"},
{id:299,s:"CV",t:"mc",q:"Cardiac risk factors include all EXCEPT:",o:["Smoking","Sedentary lifestyle","Regular aerobic exercise","Family history of heart disease"],c:[2],e:"Regular exercise is PROTECTIVE — it reduces cardiac risk. Risk factors: smoking, alcohol, caffeine, sedentary lifestyle, high-fat diet, family history of heart disease, DM, HTN, high cholesterol.",a:"C) Regular exercise",r:"Sec 6: Cardiac History — Risk Factors"},
{id:300,s:"CV",t:"mc",q:"The PMI is normally located at:",o:["Right 2nd ICS","Left 2nd ICS","Left 5th ICS, MCL","Xiphoid process"],c:[2],e:"PMI = Point of Maximum Impulse = apex = Left 5th ICS, MCL. Same location as Mitral auscultation site. This is where S1 is best heard.",a:"C) Left 5th ICS, MCL",r:"Sec 6: PMI"},
{id:301,s:"CV",t:"mc",q:"S3 in a 25-year-old athlete is:",o:["Always abnormal","Expected/normal finding","Sign of heart failure","Requires immediate treatment"],c:[1],e:"S3 is EXPECTED in children, young adults, pregnancy, and well-trained athletes due to vigorous ventricular filling. Only abnormal in adults >40.",a:"B) Expected",r:"Sec 6: S3"},
{id:302,s:"CV",t:"mc",q:"Syncope is:",o:["Chest pain","Fainting or near-fainting episodes","Rapid heartbeat","Leg swelling"],c:[1],e:"Syncope = fainting/transient loss of consciousness. Near-syncope = feeling like you're about to faint. Can indicate arrhythmia, orthostatic hypotension, or cardiac output problem.",a:"B) Fainting",r:"Sec 6: Cardiac History"},
{id:303,s:"CV",t:"mc",q:"A patient with new onset palpitations, chest pain, and syncope — the nurse should:",o:["Reassess in 1 hour","Report to HCP immediately — RED FLAG","Document and continue assessment","Encourage rest and fluids"],c:[1],e:"New onset palpitations, chest pain, syncope, or cyanosis are all RED FLAGS requiring immediate HCP notification. These may indicate life-threatening cardiac conditions.",a:"B) Report immediately",r:"Sec 6: RED FLAGS"},
{id:304,s:"CV",t:"mc",q:"Rheumatic heart disease in the family history is important because:",o:["It is contagious","It can cause valvular damage affecting cardiac function","It only affects children","It is unrelated to cardiac assessment"],c:[1],e:"Rheumatic heart disease damages heart valves — it's an important family history finding. It follows rheumatic fever (group A strep). Valvular disease = murmurs, HF risk.",a:"B) Valvular damage",r:"Sec 6: Cardiac History — Family"},
{id:305,s:"CV",t:"mc",q:"Patient position for BP measurement should be:",o:["Standing with arms hanging","Seated or supine, feet flat, legs uncrossed, arm at heart level","Lying on left side","Seated with legs crossed for support"],c:[1],e:"Seated or supine, feet flat on floor, legs uncrossed, arm supported at heart level. Crossed legs can falsely elevate BP. Arm below heart = falsely high. Above = falsely low.",a:"B",r:"Sec 6: BP Measurement"},
{id:306,s:"CV",t:"mc",q:"The Tricuspid auscultation site is at:",o:["L 2nd ICS, LSB","L 3rd ICS, LSB","L 4th ICS, LSB","L 5th ICS, MCL"],c:[2],e:"Tricuspid = Left 4th ICS, LSB. Fourth site in APETM. Best for right-sided heart sounds.",a:"C) L 4th ICS, LSB",r:"Sec 6: Landmarks"},
{id:307,s:"CV",t:"mc",q:"A patient's BP cuff is too small. The reading will be:",o:["Falsely low","Falsely high","Accurate","Unreadable"],c:[1],e:"Cuff too SMALL = falsely HIGH reading. Cuff too LARGE = falsely LOW. Cuff width should be ~40% of arm circumference. Correct sizing is essential for accuracy.",a:"B) Falsely high",r:"Sec 6: BP Measurement"},
{id:308,s:"CV",t:"mc",q:"How long should the nurse wait between BP readings on the same arm?",o:["No wait needed","30 seconds","1-2 minutes","5 minutes"],c:[2],e:"Wait at least 1-2 minutes between readings on the same arm. Repeated inflation without rest causes venous congestion and falsely elevated readings.",a:"C) 1-2 minutes",r:"Sec 6: BP Measurement"},
{id:309,s:"CV",t:"mc",q:"S4 (atrial gallop) occurs:",o:["After S2 (early diastole)","Before S1 (late diastole)","During systole","Between S1 and S2"],c:[1],e:"S4 occurs BEFORE S1 (late diastole) — atrial contraction forces blood into a stiff ventricle. S3 occurs AFTER S2 (early diastole) — rapid ventricular filling. Timing differentiates them.",a:"B) Before S1",r:"Sec 6: S4"},
{id:310,s:"CV",t:"mc",q:"Excess fatigue with minimal activity in a cardiac patient may indicate:",o:["Normal aging","Decreased cardiac output","Depression only","Poor nutrition"],c:[1],e:"Excess fatigue with minimal activity = decreased cardiac output. The heart cannot meet the body's metabolic demands. Important cardiac history question to ask.",a:"B) Decreased cardiac output",r:"Sec 6: Cardiac History"},
{id:311,s:"CV",t:"mc",q:"Aortic auscultation site is at:",o:["Right 2nd ICS, RSB","Left 2nd ICS, LSB","Left 3rd ICS, LSB","Left 5th ICS, MCL"],c:[0],e:"Aortic = Right 2nd ICS, RSB. First site in APETM. Best for S2 (aortic component). All sites should be auscultated systematically.",a:"A) R 2nd ICS, RSB",r:"Sec 6: Landmarks"},
{id:312,s:"CV",t:"mc",q:"S2 is caused by closure of:",o:["Mitral and tricuspid","Aortic and pulmonic","Mitral and aortic","Tricuspid and pulmonic"],c:[1],e:"S2 = semilunar valve closure (aortic + pulmonic) = beginning of diastole. S1 = AV valve closure (mitral + tricuspid) = beginning of systole.",a:"B) Aortic and pulmonic",r:"Sec 6: S2"},
{id:313,s:"CV",t:"mc",q:"A persistent cough in a cardiac patient may indicate:",o:["Allergies","Heart failure with pulmonary congestion","Medication non-compliance","Normal finding"],c:[1],e:"Persistent cough or dyspnea can indicate heart failure with pulmonary congestion (fluid backup into lungs). Important to differentiate from respiratory causes.",a:"B) HF with pulmonary congestion",r:"Sec 6: Cardiac History"},
{id:314,s:"CV",t:"mc",q:"The Pulmonic auscultation site is at:",o:["R 2nd ICS, RSB","L 2nd ICS, LSB","L 4th ICS, LSB","L 5th ICS, MCL"],c:[1],e:"Pulmonic = Left 2nd ICS, LSB. Second site in APETM. Best for S2 (pulmonic component).",a:"B) L 2nd ICS, LSB",r:"Sec 6: Landmarks"},
{id:315,s:"CV",t:"mc",q:"A patient with bilateral JVD, 3+ pitting edema, and S3 heart sound most likely has:",o:["Pneumonia","Heart failure","Pulmonary embolism","Aortic aneurysm"],c:[1],e:"JVD + peripheral edema + S3 = classic heart failure triad. JVD = right-sided backup. Edema = fluid retention. S3 = volume overload. Report all findings.",a:"B) Heart failure",r:"Sec 6: Multiple findings"},
{id:316,s:"CV",t:"mc",q:"Caffeine, smoking, and alcohol are important to assess because they:",o:["Have no cardiac effects","Are cardiac risk factors that affect heart rate and blood pressure","Only affect the liver","Are only social concerns"],c:[1],e:"All three are cardiac risk factors. Caffeine = stimulant (increases HR, BP). Nicotine = vasoconstrictor. Alcohol = can cause cardiomyopathy, arrhythmias. Include in cardiac history.",a:"B) Cardiac risk factors",r:"Sec 6: Cardiac History — Risk Factors"},
{id:317,s:"CV",t:"mc",q:"S3 is a _____-pitched sound heard with the _____.",o:["High, diaphragm","Low, bell","High, bell","Low, diaphragm"],c:[1],e:"S3 and S4 are LOW-pitched sounds heard best with the BELL. S1 and S2 are HIGH-pitched heard with the DIAPHRAGM. Pressing the bell lightly is key — too hard converts it to a diaphragm.",a:"B) Low, bell",r:"Sec 6: Heart Sounds"},
{id:318,s:"CV",t:"sata",q:"Which cardiac findings are RED FLAGS to report? (SATA)",o:["Pulse deficit","JVD present","S3 in a 20-year-old","S4 at any age","Visible heave at PMI"],c:[0,1,3,4],e:"Pulse deficit, JVD, S4 (always abnormal), and visible PMI heave are all RED FLAGS. S3 in a 20-year-old is EXPECTED (young adult) and not a red flag.",a:"A, B, D, E",r:"Sec 6: RED FLAGS"},
{id:319,s:"CV",t:"mc",q:"A stethoscope should NEVER be placed over:",o:["Bare skin","The patient's gown or clothing","The apex of the heart","The right sternal border"],c:[1],e:"ALWAYS place on bare skin. Clothing dampens and distorts sounds, leading to inaccurate assessment. This applies to all auscultation — cardiac, respiratory, and abdominal.",a:"B) Clothing",r:"Sec 6 + Sec 2: Auscultation"},
{id:320,s:"CV",t:"mc",q:"Unilateral lower extremity edema is more concerning for:",o:["Heart failure","DVT (deep vein thrombosis) or venous insufficiency","Kidney disease","Liver disease"],c:[1],e:"Unilateral edema = local cause — DVT, venous insufficiency, lymphatic obstruction. Bilateral = systemic cause (HF, renal, hepatic). DVT requires urgent assessment (risk of PE).",a:"B) DVT",r:"Sec 6: Cardiac History — Edema"},
{id:321,s:"CV",t:"mc",q:"To assess for JVD, position the patient at:",o:["Supine flat","30-45 degrees","90 degrees (sitting straight up)","Prone"],c:[1],e:"Assess JVD at 30-45 degrees. Flat = JVD can be normal (gravity fills veins). Upright = veins should be flat. 30-45 degrees is the standard assessment position.",a:"B) 30-45 degrees",r:"Sec 6: JVD"},
{id:322,s:"CV",t:"mc",q:"The nurse asks 'How many pillows do you need to sleep?' This assesses for:",o:["Comfort preference","Orthopnea","Back pain","GERD"],c:[1],e:"Number of pillows = orthopnea severity. 2-pillow orthopnea means the patient needs 2 pillows to avoid SOB when lying down. Sign of heart failure.",a:"B) Orthopnea",r:"Sec 6: Cardiac History"},
{id:323,s:"CV",t:"mc",q:"S1 marks the beginning of:",o:["Diastole","Systole","Atrial contraction","Ventricular relaxation"],c:[1],e:"S1 (AV valve closure) = beginning of SYSTOLE (ventricular contraction). S2 (semilunar valve closure) = beginning of DIASTOLE (ventricular relaxation).",a:"B) Systole",r:"Sec 6: S1"},
{id:324,s:"CV",t:"mc",q:"Family history of stroke (CVA) is relevant to cardiac assessment because:",o:["Stroke only affects the brain","Stroke and heart disease share many risk factors","Stroke is not a cardiovascular condition","Only hemorrhagic strokes are relevant"],c:[1],e:"Stroke and heart disease share risk factors: HTN, DM, high cholesterol, smoking, a-fib. Family history of CVA increases the patient's cardiovascular risk profile.",a:"B) Shared risk factors",r:"Sec 6: Family History"},
{id:325,s:"CV",t:"mc",q:"The stethoscope diaphragm is BEST for:",o:["Heart murmurs","S3 and S4","High-pitched sounds (S1, S2, bowel, lung)","Vascular bruits"],c:[2],e:"Diaphragm = high-pitched sounds: S1, S2, bowel sounds, lung sounds. Bell = low-pitched: murmurs, S3, S4, bruits. Match the tool to the sound frequency.",a:"C) High-pitched sounds",r:"Sec 6: Auscultation"},
{id:326,s:"CV",t:"mc",q:"A patient with a-fib would most likely have:",o:["Regular pulse","Pulse deficit (apical > radial)","Bradycardia","Bounding pulses"],c:[1],e:"A-fib causes irregular, often rapid ventricular response. Some beats are too weak to transmit peripherally → pulse deficit (apical > radial). This is a classic a-fib finding.",a:"B) Pulse deficit",r:"Sec 6: Pulse Assessment"},
{id:327,s:"CV",t:"mc",q:"Recreational drug use is assessed in cardiac history because:",o:["For legal documentation only","Stimulants like cocaine can cause MI, arrhythmias, and hypertensive crisis","Only IV drugs matter for cardiac assessment","It's not relevant to cardiac assessment"],c:[1],e:"Cocaine = potent vasoconstrictor and sympathomimetic → MI, arrhythmias, hypertensive crisis. Methamphetamine = cardiomyopathy. All recreational drugs affect the cardiovascular system.",a:"B) Stimulants cause MI, arrhythmias",r:"Sec 6: Cardiac History — Drugs"},
{id:328,s:"CV",t:"mc",q:"High cholesterol in family history is important because:",o:["It is always inherited","It contributes to atherosclerosis and coronary artery disease","It only matters after age 65","Cholesterol has no cardiac effects"],c:[1],e:"Hyperlipidemia contributes to atherosclerosis → coronary artery disease, MI, stroke. Family history of high cholesterol increases the patient's risk and guides screening and prevention.",a:"B) Contributes to atherosclerosis",r:"Sec 6: Family History"},
{id:329,s:"CV",t:"mc",q:"During cardiac auscultation, the nurse should listen at each site for:",o:["1-2 seconds","At least one complete cardiac cycle (S1 and S2)","30 seconds each","Only if abnormality is suspected"],c:[1],e:"Listen at each site for at least one complete cardiac cycle to hear both S1 and S2. Listen for rate, rhythm, extra sounds, and murmurs. Use both diaphragm and bell at each site.",a:"B) At least one complete cycle",r:"Sec 6: Auscultation"},
{id:330,s:"CV",t:"mc",q:"A patient with diabetes, HTN, and high cholesterol has which level of cardiac risk?",o:["No risk","Low risk","Moderate risk","High risk — multiple modifiable and non-modifiable factors"],c:[3],e:"Multiple comorbidities (DM, HTN, hyperlipidemia) = high cardiac risk. These are modifiable risk factors that synergistically increase cardiovascular disease risk. Aggressive management indicated.",a:"D) High risk",r:"Sec 6: Cardiac History — Risk Factors"},
// === RESPIRATORY (331-390) ===
{id:331,s:"RE",t:"mc",q:"High-pitched crowing sound on INSPIRATION with throat clutching indicates:",o:["Wheezing","Rhonchi","Stridor","Pleural friction rub"],c:[2],e:"Stridor = upper airway obstruction (foreign body, croup, epiglottitis). MEDICAL EMERGENCY. Position upright, call HCP, prepare for emergency airway management.",a:"C) Stridor",r:"Sec 7: Stridor"},
{id:332,s:"RE",t:"mc",q:"COPD patient SpO2 89%. Best action:",o:["High-flow O2 at 10L via non-rebreather","Recognize within acceptable COPD range (88-92%) and monitor","Call code blue","Position supine"],c:[1],e:"COPD target: 88-92%. High-flow O2 can suppress hypoxic drive → respiratory depression. 89% is acceptable for COPD. Normal SpO2: 95-100% for non-COPD.",a:"B) Within COPD range",r:"Sec 7: COPD — Hypoxic Drive"},
{id:333,s:"RE",t:"mc",q:"RAT BED — early hypoxia signs are:",o:["Bradycardia, Extreme restlessness, Dyspnea","Restlessness, Anxiety, Tachycardia/Tachypnea","Rapid pulse, Apnea, Tremors","Bradypnea, Elevated BP, Diaphoresis"],c:[1],e:"RAT = Early: Restlessness, Anxiety, Tachycardia/Tachypnea. BED = Late: Bradycardia, Extreme Restlessness, Dyspnea (severe). Early recognition saves lives.",a:"B) RAT",r:"Sec 7: Hypoxia — RAT BED"},
{id:334,s:"RE",t:"mc",q:"Snoring-like sounds in larger airways partially cleared by coughing:",o:["Fine crackles","Wheezing","Rhonchi","Stridor"],c:[2],e:"Rhonchi = snoring sounds from fluid/mucus in LARGER airways. May clear with coughing. Crackles = smaller airways, NOT cleared. Wheezing = musical, narrowed airways.",a:"C) Rhonchi",r:"Sec 7: Rhonchi"},
{id:335,s:"RE",t:"mc",q:"Gradually increasing then decreasing depth/rate followed by apnea is:",o:["Kussmaul","Cheyne-Stokes","Biot's","Hyperventilation"],c:[1],e:"Cheyne-Stokes = crescendo-decrescendo + apnea. Associated with dying, severe HF, brain injury. Kussmaul = deep/rapid without apnea (DKA). Biot's = random/irregular + apnea.",a:"B) Cheyne-Stokes",r:"Sec 7: Breathing Patterns"},
{id:336,s:"RE",t:"mc",q:"AP diameter equals lateral diameter (rounded chest) in COPD is:",o:["Kyphosis","Barrel chest","Funnel chest","Pigeon chest"],c:[1],e:"Barrel chest = AP = lateral diameter from chronic air trapping in COPD. Key physical assessment finding. Normal chest has lateral > AP diameter.",a:"B) Barrel chest",r:"Sec 7: Unexpected Findings"},
{id:337,s:"RE",t:"mc",q:"Increased tactile fremitus on right lower lobe suggests:",o:["Pleural effusion","Pneumothorax","Consolidation (pneumonia)","Normal"],c:[2],e:"Increased fremitus = consolidation (solid/fluid transmits vibrations better). Decreased = air/fluid in pleural space (pneumothorax, effusion). Normal = moderate, symmetric.",a:"C) Consolidation",r:"Sec 7: Fremitus"},
{id:338,s:"RE",t:"mc",q:"Tripod position (leaning forward, hands on knees) indicates:",o:["Comfort preference","Respiratory insufficiency","Abdominal pain","Anxiety"],c:[1],e:"Tripod = accessory muscle use for breathing. If default position, indicates respiratory insufficiency. Patient is working hard to breathe. Assess O2 saturation.",a:"B) Respiratory insufficiency",r:"Sec 7: Tripod Position"},
{id:339,s:"RE",t:"mc",q:"Most commonly heard normal lung sound, soft and low-pitched like wind through trees:",o:["Tracheal","Bronchial","Bronchovesicular","Vesicular"],c:[3],e:"Vesicular = most common, heard over peripheral lung fields. Soft, low-pitched. Inspiration > expiration. Tracheal = loud, over trachea. Bronchial = loud, neck/sternum.",a:"D) Vesicular",r:"Sec 7: Normal Lung Sounds"},
{id:340,s:"RE",t:"mc",q:"Deep rapid labored breathing + fruity breath in a diabetic =",o:["Cheyne-Stokes","Biot's","Kussmaul with DKA","Hyperventilation from anxiety"],c:[2],e:"Kussmaul = deep rapid breathing without apnea = metabolic acidosis compensation. Fruity breath = ketones from DKA. This combination = DKA until proven otherwise.",a:"C) Kussmaul + DKA",r:"Sec 7: Kussmaul"},
{id:341,s:"RE",t:"sata",q:"Chronic hypoxia signs include: (SATA)",o:["Clubbing of fingernails","Barrel chest","Pursed-lip breathing","Fine crackles","Eupnea"],c:[0,1],e:"Clubbing and barrel chest = CHRONIC hypoxia (COPD, cyanotic heart disease). Pursed-lip breathing = compensatory technique. Crackles = acute fluid. Eupnea = normal breathing.",a:"A, B",r:"Sec 7: Chronic Hypoxia"},
{id:342,s:"RE",t:"mc",q:"Lung auscultation technique: always on bare skin, systematically:",o:["Anterior only, top to bottom","Side to side, comparing right to left","One lung completely, then the other","Only where abnormality is suspected"],c:[1],e:"Auscultate side-to-side, comparing right to left at each level, then move down. Posterior essential — never listen only anteriorly. Always bare skin. Systematic comparison detects asymmetry.",a:"B) Side to side, right vs left",r:"Sec 7: Auscultation Technique"},
{id:343,s:"RE",t:"mc",q:"Normal adult respiratory rate is:",o:["8-12 breaths/min","12-20 breaths/min","20-30 breaths/min","30-60 breaths/min"],c:[1],e:"Adult: 12-20. Adolescent: 12-20. Infant/child: 18-30. Newborn: 30-60. Eupnea = normal, even, unlabored breathing.",a:"B) 12-20",r:"Sec 7: Normal RR"},
{id:344,s:"RE",t:"mc",q:"Newborn normal respiratory rate is:",o:["12-20","18-30","20-30","30-60"],c:[3],e:"Newborn (<28 days): 30-60 breaths/min. Significantly higher than adults. Rapid RR in newborns is normal — don't mistake it for tachypnea.",a:"D) 30-60",r:"Sec 7: Normal RR by Age"},
{id:345,s:"RE",t:"mc",q:"Pleural friction rub sounds like:",o:["Musical whistling","Snoring","Two pieces of leather rubbing together","Popping bubbles"],c:[2],e:"Pleural friction rub = dry, grating, rubbing (leather-on-leather). From inflamed pleural surfaces. Heard on both inspiration AND expiration. Painful to breathe.",a:"C) Leather rubbing",r:"Sec 7: Pleural Friction Rub"},
{id:346,s:"RE",t:"mc",q:"Wheezing is associated with all EXCEPT:",o:["Asthma","Anaphylaxis","COPD exacerbation","Pneumothorax"],c:[3],e:"Wheezing = high-pitched musical sound from narrowed airways. Asthma, anaphylaxis, COPD exacerbation. Pneumothorax presents with absent breath sounds, not wheezing.",a:"D) Pneumothorax",r:"Sec 7: Wheezing"},
{id:347,s:"RE",t:"mc",q:"Fine crackles are caused by:",o:["Mucus in large airways","Air passing through fluid or re-expanding collapsed alveoli","Upper airway obstruction","Inflamed pleural surfaces"],c:[1],e:"Fine crackles = soft, high-pitched crackling from fluid in small airways or collapsed alveoli re-expanding. NOT cleared by coughing. Heard in pneumonia, pulmonary edema, HF.",a:"B) Air through fluid/collapsed alveoli",r:"Sec 7: Crackles"},
{id:348,s:"RE",t:"mc",q:"Wheezing is primarily heard on:",o:["Inspiration","Expiration","Both equally","Neither"],c:[1],e:"Wheezing is primarily expiratory — narrowed airways create the musical sound as air is forced out. Can be heard on inspiration in severe cases. Stridor is primarily inspiratory.",a:"B) Expiration",r:"Sec 7: Wheezing"},
{id:349,s:"RE",t:"mc",q:"Biot's (ataxic) breathing indicates:",o:["Metabolic acidosis","Medullary damage","Heart failure","Anxiety"],c:[1],e:"Biot's = irregular, random deep/shallow breaths + apnea = medullary (brainstem) damage. Cheyne-Stokes = crescendo-decrescendo (dying, HF). Kussmaul = deep/rapid (DKA).",a:"B) Medullary damage",r:"Sec 7: Biot's"},
{id:350,s:"RE",t:"mc",q:"Normal diaphragmatic excursion should be:",o:["1-2 cm","4-5 cm","8-10 cm","10-12 cm"],c:[1],e:"Diaphragmatic excursion = 4-5 cm difference between full inspiration and full expiration percussion points. Decreased excursion = COPD, diaphragm paralysis.",a:"B) 4-5 cm",r:"Sec 7: Diaphragmatic Excursion"},
{id:351,s:"RE",t:"mc",q:"Posterior lung expansion is assessed by placing hands on the back with thumbs at:",o:["Shoulder blades","The spine","Hip bones","Ribs laterally"],c:[1],e:"Place both hands on back, thumbs at the spine. Patient breathes deeply — thumbs should separate symmetrically. Asymmetric expansion = unilateral lung pathology.",a:"B) The spine",r:"Sec 7: Posterior Lung Expansion"},
{id:352,s:"RE",t:"mc",q:"Pursed-lip breathing in COPD patients serves to:",o:["Increase oxygen intake","Increase expiratory pressure and prevent airway collapse","Reduce anxiety","Clear mucus from airways"],c:[1],e:"Pursed-lip breathing increases positive end-expiratory pressure (auto-PEEP), preventing premature airway collapse during expiration. It's a self-taught compensatory mechanism in COPD.",a:"B) Prevent airway collapse",r:"Sec 7: Pursed-Lip Breathing"},
{id:353,s:"RE",t:"mc",q:"Confusion in a respiratory patient may indicate:",o:["Psychiatric disorder","CO2 retention or hypoxia affecting the brain","Medication non-compliance","Hearing loss"],c:[1],e:"Confusion can be a sign of CO2 retention (hypercapnia) or hypoxia affecting the brain. In respiratory patients, altered mental status is a late/ominous sign requiring immediate intervention.",a:"B) CO2 retention or hypoxia",r:"Sec 7: Unexpected Findings"},
{id:354,s:"RE",t:"mc",q:"Clubbing of fingernails indicates:",o:["Iron deficiency","Acute infection","Chronic hypoxia","Liver disease"],c:[2],e:"Clubbing = rounded, spongy nail beds (angle >180°) = CHRONIC hypoxia (COPD, cyanotic heart disease). Develops over time. Different from acute cyanosis.",a:"C) Chronic hypoxia",r:"Sec 7: Clubbing"},
{id:355,s:"RE",t:"mc",q:"Factors that increase respiratory rate include all EXCEPT:",o:["Pain","Fever","Anxiety","Sleep"],c:[3],e:"Smoking, pain, stimulant medications, increased activity, fever, and anxiety all INCREASE RR. Sleep typically DECREASES respiratory rate and depth.",a:"D) Sleep",r:"Sec 7: Factors Affecting RR"},
{id:356,s:"RE",t:"mc",q:"Assess RR for a full 60 seconds if the patient:",o:["Is sleeping","Is healthy and stable","Is ill or has altered respiratory status","Is a young adult"],c:[2],e:"Count for full 60 seconds if the patient is ill or has altered respiratory status for accuracy. Quick 15-sec counts may miss irregularities in compromised patients.",a:"C) Ill or altered respiratory status",r:"Sec 7: RR Assessment"},
{id:357,s:"RE",t:"mc",q:"Bronchial breath sounds are normally heard at:",o:["Peripheral lung fields","Neck and sternum","Bases of lungs","Axillary regions"],c:[1],e:"Bronchial = loud, high-pitched, heard at neck/sternum. Inspiration < expiration. If heard in peripheral lung fields, it's abnormal (indicates consolidation).",a:"B) Neck and sternum",r:"Sec 7: Normal Lung Sounds"},
{id:358,s:"RE",t:"mc",q:"Bronchovesicular sounds are characterized by:",o:["Soft, low-pitched","Moderate intensity, equal inspiration and expiration","Loud with expiration longer than inspiration","High-pitched crowing"],c:[1],e:"Bronchovesicular = moderate intensity and pitch, equal I:E ratio. Heard at middle chest (especially right). Between bronchial and vesicular in characteristics.",a:"B) Moderate, equal I:E",r:"Sec 7: Normal Lung Sounds"},
{id:359,s:"RE",t:"mc",q:"On dark-skinned patients, assess oxygenation at:",o:["Forehead","Cheeks","Nail beds and oral mucosa","Palms of hands only"],c:[2],e:"In dark-skinned patients, cyanosis and pallor are best assessed at nail beds and oral mucosa where melanin pigmentation is less dense. Visual skin assessment alone may miss hypoxia.",a:"C) Nail beds and oral mucosa",r:"Sec 7: NOTE — Dark Skin"},
{id:360,s:"RE",t:"mc",q:"Incentive spirometer and flutter valve both promote:",o:["Airway clearance only","Lung expansion","Heart rate reduction","Sleep quality"],c:[1],e:"Both promote lung expansion. Instruct patient to use 10 times per hour. Turn, Cough, Deep Breathe (TCDB) reduces post-operative pneumonia risk. NCLEX TIP.",a:"B) Lung expansion",r:"Sec 7: NCLEX TIP — IS and Flutter Valve"},
{id:361,s:"RE",t:"mc",q:"Crackles are NOT cleared by:",o:["Coughing","Suctioning","Deep breathing","Any of these — crackles are not cleared by coughing"],c:[3],e:"Crackles are NOT cleared by coughing (distinguishes from rhonchi, which may clear). Crackles are caused by fluid in alveoli or re-expanding collapsed airways — structural, not just mucus.",a:"D) Not cleared by coughing",r:"Sec 7: Crackles"},
{id:362,s:"RE",t:"mc",q:"Rales are described as:",o:["Musical whistling sounds","Small clicking, bubbling, or rattling sounds on inspiration","Dry grating sound","Snoring sounds"],c:[1],e:"Rales = small clicking, bubbling, or rattling sounds on inspiration. Can be fine, medium, or coarse. Similar to crackles — terms often used interchangeably.",a:"B) Clicking/bubbling on inspiration",r:"Sec 7: Rales"},
{id:363,s:"RE",t:"mc",q:"SpO2 normal range for a non-COPD patient is:",o:["80-85%","85-90%","88-92%","95-100%"],c:[3],e:"Normal SpO2: 95-100%. COPD patients: 88-92% (hypoxic drive). Below 90% in non-COPD = hypoxemia requiring intervention. Below 95% warrants monitoring.",a:"D) 95-100%",r:"Sec 7: SpO2"},
{id:364,s:"RE",t:"mc",q:"Tracheal breath sounds are:",o:["Soft and low-pitched","Loud, high-pitched, with equal I:E, heard over trachea","Moderate intensity at middle chest","Musical and whistling"],c:[1],e:"Tracheal = loud, high-pitched, equal inspiration:expiration, directly over the trachea. The loudest of normal breath sounds due to proximity to the airway.",a:"B) Loud, high-pitched, over trachea",r:"Sec 7: Normal Lung Sounds"},
{id:365,s:"RE",t:"mc",q:"Hyperventilation causes all EXCEPT:",o:["Lightheadedness","Numbness/tingling of extremities","Chest pain","Bradycardia"],c:[3],e:"Hyperventilation → respiratory alkalosis → lightheadedness, numbness/tingling, chest pain. It causes TACHYCARDIA (not bradycardia) from sympathetic activation.",a:"D) Bradycardia",r:"Sec 7: Hyperventilation"},
{id:366,s:"RE",t:"mc",q:"Unilateral absent breath sounds is a RED FLAG possibly indicating:",o:["Normal finding","Pneumothorax or complete obstruction","Mild asthma","Anxiety"],c:[1],e:"Absent breath sounds on one side = pneumothorax, complete obstruction, or massive pleural effusion. RED FLAG — report immediately. Also check for tracheal deviation.",a:"B) Pneumothorax or obstruction",r:"Sec 7: RED FLAG"},
{id:367,s:"RE",t:"mc",q:"Decreased tactile fremitus suggests:",o:["Consolidation","Air or fluid in pleural space","Normal lung tissue","Pneumonia"],c:[1],e:"Decreased fremitus = air or fluid BETWEEN the lung and chest wall (pneumothorax, pleural effusion). Air and fluid dampen vibrations. Increased fremitus = solid tissue (consolidation).",a:"B) Air or fluid in pleural space",r:"Sec 7: Fremitus"},
{id:368,s:"RE",t:"mc",q:"A patient with COPD should NOT receive high-flow oxygen because:",o:["Oxygen is toxic to COPD lungs","It can suppress the hypoxic drive causing respiratory depression","It will worsen their cough","High-flow masks are uncomfortable"],c:[1],e:"COPD patients rely on hypoxic drive (low O2) to breathe instead of normal CO2 drive. High-flow O2 removes this stimulus → respiratory depression. Target 88-92%. RED FLAG.",a:"B) Suppresses hypoxic drive",r:"Sec 7: COPD — RED FLAG"},
{id:369,s:"RE",t:"mc",q:"Cyanosis is a ___ sign of hypoxia.",o:["Early","Late","Moderate","Not a sign of"],c:[1],e:"Cyanosis (bluish discoloration) is a LATE sign of hypoxia — tissue must be significantly deoxygenated for visible color change. Early signs: restlessness, anxiety, tachycardia (RAT).",a:"B) Late",r:"Sec 7: Cyanosis"},
{id:370,s:"RE",t:"mc",q:"Pallor in a respiratory assessment may indicate:",o:["Hyperthyroidism","Anemia or poor perfusion","Jaundice","Infection"],c:[1],e:"Pallor = anemia or poor perfusion. Reduced hemoglobin or blood flow causes pale skin/mucous membranes. In dark-skinned patients, check oral mucosa and conjunctiva.",a:"B) Anemia or poor perfusion",r:"Sec 7: Pallor"},
{id:371,s:"RE",t:"mc",q:"Tracheal sounds differ from bronchial sounds in that tracheal sounds have:",o:["Expiration longer than inspiration","Equal inspiration and expiration duration","Inspiration longer than expiration","No audible expiration"],c:[1],e:"Tracheal: equal I:E. Bronchial: inspiration < expiration. Bronchovesicular: equal I:E. Vesicular: inspiration > expiration. I:E ratio helps identify sound types.",a:"B) Equal I:E",r:"Sec 7: Normal Lung Sounds"},
{id:372,s:"RE",t:"mc",q:"Vesicular sounds have inspiration that is ___ than expiration.",o:["Shorter","Equal to","Longer","Not heard during"],c:[2],e:"Vesicular: inspiration LONGER than expiration. Soft, low-pitched, like wind through trees. This is opposite of bronchial (expiration longer). Key distinguishing feature.",a:"C) Longer",r:"Sec 7: Vesicular Sounds"},
{id:373,s:"RE",t:"mc",q:"Fremitus is assessed by having the patient say:",o:["'Ah'","'99'","'E'","Their name"],c:[1],e:"Have patient say '99' — vibrations transmit through lung tissue. Place sides of both hands between shoulder blades. '99' produces optimal vibration frequency for assessment.",a:"B) '99'",r:"Sec 7: Fremitus"},
{id:374,s:"RE",t:"mc",q:"Resonance on percussion over lung fields indicates:",o:["Normal air-filled lung tissue","Fluid or consolidation","Pneumothorax","Solid mass"],c:[0],e:"Resonance = expected percussion sound over normal lungs. Dullness = fluid/consolidation (pneumonia). Hyperresonance = excess air (pneumothorax, emphysema). Flatness = solid tissue.",a:"A) Normal lung",r:"Sec 7 + Sec 2: Percussion"},
{id:375,s:"RE",t:"mc",q:"A patient using accessory muscles to breathe suggests:",o:["Normal breathing pattern","Increased work of breathing","Good respiratory function","Need for incentive spirometer only"],c:[1],e:"Accessory muscle use (SCM, intercostals, abdominal muscles) = increased work of breathing. Indicates respiratory compromise. Assess for tripod positioning and SpO2.",a:"B) Increased work of breathing",r:"Sec 7: Accessory Muscles"},
{id:376,s:"RE",t:"mc",q:"Cheyne-Stokes breathing is associated with:",o:["DKA only","Dying patients, severe HF, brain injury","Anxiety","Healthy sleep patterns"],c:[1],e:"Cheyne-Stokes = gradual waxing/waning with apnea periods. Seen in dying patients, severe heart failure, and brain injury. Ominous sign requiring close monitoring.",a:"B) Dying, severe HF, brain injury",r:"Sec 7: Cheyne-Stokes"},
{id:377,s:"RE",t:"mc",q:"BED in the RAT BED mnemonic stands for:",o:["Breathing, Edema, Dizziness","Bradycardia, Extreme Restlessness, Dyspnea","Blood pressure, Edema, Dehydration","Bradypnea, Elevation, Diaphoresis"],c:[1],e:"BED = LATE signs of hypoxia: Bradycardia, Extreme Restlessness, Dyspnea (severe). Late signs indicate decompensation. Early intervention during RAT phase is critical.",a:"B) Bradycardia, Extreme Restlessness, Dyspnea",r:"Sec 7: RAT BED"},
{id:378,s:"RE",t:"mc",q:"Coarse crackles differ from fine crackles by being:",o:["Higher-pitched and softer","Louder, lower-pitched, bubbling","Musical and whistling","Heard only on expiration"],c:[1],e:"Fine crackles: soft, high-pitched crackling. Coarse crackles: louder, lower-pitched, bubbling/gurgling. Both caused by fluid — coarse suggests more fluid in larger airways.",a:"B) Louder, lower-pitched, bubbling",r:"Sec 7: Crackles"},
{id:379,s:"RE",t:"mc",q:"Stridor requires the nurse to:",o:["Document and continue monitoring","Position upright, call HCP, prepare for emergency airway","Administer bronchodilator PRN","Apply oxygen and recheck in 30 min"],c:[1],e:"Stridor = upper airway obstruction = MEDICAL EMERGENCY. Position upright (improves airway), call HCP immediately, prepare for emergency airway management (possible intubation).",a:"B) Position upright, call HCP, prepare for emergency",r:"Sec 7: Stridor — RED FLAG"},
{id:380,s:"RE",t:"mc",q:"Pleural friction rub is heard on:",o:["Inspiration only","Expiration only","Both inspiration AND expiration","Neither — it is felt, not heard"],c:[2],e:"Pleural friction rub = heard on BOTH inspiration and expiration. Inflamed pleural surfaces rubbing together. Painful to breathe. Dry, grating quality like leather rubbing.",a:"C) Both inspiration and expiration",r:"Sec 7: Pleural Friction Rub"},
{id:381,s:"RE",t:"mc",q:"Kussmaul breathing does NOT have:",o:["Deep respirations","Rapid respirations","Labored respirations","Apneic periods"],c:[3],e:"Kussmaul = deep, rapid, labored WITHOUT apnea. This distinguishes it from Cheyne-Stokes (has apnea) and Biot's (has apnea). Kussmaul = metabolic acidosis compensation.",a:"D) Apneic periods",r:"Sec 7: Kussmaul"},
{id:382,s:"RE",t:"mc",q:"SpO2 below ___ in a non-COPD patient is a RED FLAG.",o:["98%","95%","90%","85%"],c:[2],e:"SpO2 <90% = significant hypoxemia in non-COPD patients. Requires immediate intervention (oxygen therapy, positioning, airway management). Below 95% warrants close monitoring.",a:"C) 90%",r:"Sec 7: RED FLAG — SpO2"},
{id:383,s:"RE",t:"mc",q:"Smoking increases respiratory rate by acting as a:",o:["Bronchodilator","Respiratory depressant","Stimulant to the respiratory center","Mucolytic"],c:[2],e:"Smoking (nicotine) stimulates the CNS including the respiratory center, increasing RR. It also causes chronic airway inflammation, mucus production, and eventual COPD.",a:"C) Stimulant",r:"Sec 7: Factors Affecting RR"},
{id:384,s:"RE",t:"mc",q:"Eupnea is defined as:",o:["Rapid, deep breathing","Normal, even, unlabored breathing","Absence of breathing","Difficult or labored breathing"],c:[1],e:"Eupnea = normal, even, unlabored breathing at 12-20 breaths/min in adults. Apnea = absent breathing. Dyspnea = difficult breathing. Tachypnea = rapid breathing.",a:"B) Normal, even, unlabored",r:"Sec 7: Eupnea"},
{id:385,s:"RE",t:"mc",q:"The nurse assesses tactile fremitus. Expected finding is:",o:["No vibration at all","Moderate, symmetric vibrations bilaterally","Strong vibrations on right, none on left","Vibrations only on expiration"],c:[1],e:"Normal fremitus = moderate, symmetric vibrations bilaterally. Asymmetry indicates pathology: increased = consolidation on that side; decreased = air/fluid on that side.",a:"B) Moderate, symmetric bilaterally",r:"Sec 7: Fremitus"},
{id:386,s:"RE",t:"tf",q:"True or False: Rhonchi are caused by fluid in small airways and are not cleared by coughing.",o:["True","False"],c:[1],e:"False. Rhonchi are in LARGER airways and MAY be cleared by coughing. Crackles are in smaller airways and are NOT cleared by coughing. This distinction is commonly tested.",a:"False",r:"Sec 7: Rhonchi vs Crackles"},
{id:387,s:"RE",t:"mc",q:"Posterior auscultation is essential because:",o:["It's faster than anterior","Most lung tissue is posterior — anterior alone misses pathology","Patients prefer it","It's required by law"],c:[1],e:"The lungs extend significantly posteriorly. Listening only anteriorly can miss significant findings in the posterior lung fields. Always auscultate systematically — anterior, posterior, and lateral.",a:"B) Most lung tissue is posterior",r:"Sec 7: Auscultation Technique"},
{id:388,s:"RE",t:"mc",q:"Dullness on percussion over lung fields indicates:",o:["Normal air-filled tissue","Fluid or consolidation (pneumonia, effusion)","Pneumothorax","Expected finding"],c:[1],e:"Dullness = fluid or solid tissue (pneumonia, pleural effusion, tumor). Replaces normal resonance. Hyperresonance = excess air. Dullness vs resonance helps localize pathology.",a:"B) Fluid or consolidation",r:"Sec 7 + Sec 2: Percussion"},
{id:389,s:"RE",t:"mc",q:"TCDB stands for:",o:["Temperature, Circulation, Deep breathing, Blood pressure","Turn, Cough, Deep Breathe","Treat, Communicate, Document, Begin","Test, Check, Document, Breathe"],c:[1],e:"TCDB = Turn, Cough, Deep Breathe — reduces post-operative pneumonia risk. Used with incentive spirometer. Instruct patients preoperatively. NCLEX TIP.",a:"B) Turn, Cough, Deep Breathe",r:"Sec 7: TCDB"},
{id:390,s:"RE",t:"mc",q:"Hyperresonance on percussion over lung fields suggests:",o:["Normal finding","Consolidation","Excess air (pneumothorax, emphysema)","Pleural effusion"],c:[2],e:"Hyperresonance = excess air in the thorax. Seen in pneumothorax (trapped air) and emphysema (air trapping). Lower in pitch and louder than normal resonance.",a:"C) Excess air",r:"Sec 7 + Sec 2: Percussion"},
// === MUSCULOSKELETAL (391-430) ===
{id:391,s:"MS",t:"mc",q:"Bilateral hand joint swelling with ulnar deviation of fingers is characteristic of:",o:["Osteoarthritis","Rheumatoid arthritis","Gout","Osteoporosis"],c:[1],e:"RA = bilateral, symmetric, with ulnar deviation. OA = asymmetric, weight-bearing joints. Gout = single joint (great toe). Osteoporosis = bone density loss, not joint swelling.",a:"B) RA",r:"Sec 8: Abnormalities"},
{id:392,s:"MS",t:"mc",q:"Post-menopausal woman 2 inches shorter than age 30 — suspect:",o:["Normal aging","Scoliosis","Vertebral compression fractures from osteoporosis","Kyphosis from poor posture"],c:[2],e:"Height loss = vertebral compression fractures from osteoporosis. Assess bone density, calcium/vitamin D intake. Kyphosis may develop secondarily from compression fractures.",a:"C) Compression fractures",r:"Sec 8: Osteoporosis"},
{id:393,s:"MS",t:"mc",q:"Cogwheel rigidity is associated with:",o:["Stroke","Parkinson's disease","ALS","Cerebellar dysfunction"],c:[1],e:"Cogwheel = ratcheting resistance throughout full ROM = Parkinson's hallmark. Lead-pipe = uniform resistance = also Parkinson's. Spasticity (velocity-dependent) = upper motor neuron/stroke.",a:"B) Parkinson's",r:"Sec 8: Rigidity"},
{id:394,s:"MS",t:"mc",q:"Adam's forward bend test screens for:",o:["Kyphosis","Lordosis","Scoliosis","Osteoporosis"],c:[2],e:"Adam's test: bend forward at waist → observe for uneven shoulders/hips and lateral spine curvature = scoliosis. Used in school screenings. Kyphosis = thoracic hunchback. Lordosis = lumbar curve.",a:"C) Scoliosis",r:"Sec 8: Scoliosis"},
{id:395,s:"MS",t:"sata",q:"Five cardinal signs of inflammation include: (SATA)",o:["Redness","Swelling","Pallor","Warmth","Loss of function","Tenderness"],c:[0,1,3,4,5],e:"Five signs: Redness, Swelling, Warmth, Tenderness, Loss of function. Pallor = anemia/poor perfusion, NOT inflammation. Inflammation increases blood flow (redness, warmth).",a:"A, B, D, E, F",r:"Sec 8: Inflammation"},
{id:396,s:"MS",t:"mc",q:"Supination of the forearm means:",o:["Palm face-down","Palm face-up","Bending the wrist","Straightening the elbow"],c:[1],e:"Supination = palm UP ('holding soup'). Pronation = palm DOWN. These are radioulnar joint movements. Mnemonic: SUPination = SUP of soup.",a:"B) Palm up",r:"Sec 8: ROM — Forearm"},
{id:397,s:"MS",t:"mc",q:"Ataxic gait is associated with:",o:["Normal aging","Cerebellar dysfunction or intoxication","Muscle strain","Dehydration"],c:[1],e:"Ataxia = unsteady, wide-based, uncoordinated gait. Cerebellar dysfunction or intoxication (alcohol, drugs). Gait should normally be smooth, steady, symmetrical.",a:"B) Cerebellar dysfunction",r:"Sec 8: Ataxia"},
{id:398,s:"MS",t:"mc",q:"Osteoporosis dietary recommendation: calcium and vitamin D daily:",o:["Ca 500mg, VitD 400IU","Ca 1000-1200mg, VitD 800IU","Ca 2000mg, VitD 2000IU","Ca 300mg, VitD 200IU"],c:[1],e:"Osteoporosis: Calcium 1000-1200 mg/day + Vitamin D 800 IU/day. VitD supports calcium absorption. Ca-rich foods: milk, yogurt, broccoli, salmon, legumes, egg yolks.",a:"B) Ca 1000-1200, VitD 800",r:"Sec 8: Bone Health"},
{id:399,s:"MS",t:"mc",q:"Kyphosis is:",o:["Lateral spine curvature","Exaggerated thoracic curvature (hunchback)","Exaggerated lumbar curvature","Normal spine alignment"],c:[1],e:"Kyphosis = thoracic hunchback/forward rounding. Scoliosis = lateral curvature. Lordosis = exaggerated lumbar curve. Can develop from osteoporosis, poor posture, or degenerative disease.",a:"B) Exaggerated thoracic curve",r:"Sec 8: Abnormalities"},
{id:400,s:"MS",t:"mc",q:"Club foot (talipes equinovarus) is:",o:["An acquired condition from trauma","A birth defect — foot turns downward and inward","Normal variant in infants","Result of osteoporosis"],c:[1],e:"Club foot = congenital birth defect where foot turns downward and toward the other leg. Requires early treatment (casting, surgery). Not acquired or age-related.",a:"B) Birth defect",r:"Sec 8: Abnormalities"},
{id:401,s:"MS",t:"mc",q:"Active ROM means:",o:["Nurse moves the patient's joints","Patient moves their own joints","ROM measured by X-ray","Automated machine moves joints"],c:[1],e:"Active = patient moves own joints. Passive = nurse/therapist moves patient's joints. Assess both — compare for limitations. Active tests both joint integrity and muscle strength.",a:"B) Patient moves own joints",r:"Sec 8: ROM"},
{id:402,s:"MS",t:"mc",q:"Dorsiflexion of the ankle means:",o:["Toes point downward","Toes point upward","Foot turns inward","Foot turns outward"],c:[1],e:"Dorsiflexion = toes UP. Plantar flexion = toes DOWN (like pressing a gas pedal). Inversion = sole inward. Eversion = sole outward. Know ankle/foot terminology.",a:"B) Toes up",r:"Sec 8: ROM — Ankle"},
{id:403,s:"MS",t:"mc",q:"Inversion of the foot means:",o:["Toes pointing up","Toes pointing down","Sole turns inward","Sole turns outward"],c:[2],e:"Inversion = sole turns inward. Eversion = sole turns outward. These are assessed at the subtalar joint. Important for ankle sprain assessment.",a:"C) Sole inward",r:"Sec 8: ROM — Foot"},
{id:404,s:"MS",t:"mc",q:"Muscle tone is assessed by:",o:["Having the patient lift weights","Assessing resistance to passive ROM","Measuring muscle circumference","Observing gait only"],c:[1],e:"Muscle tone = normal resistance felt when passively moving a joint through its ROM. Increased tone = spasticity/rigidity. Decreased tone = flaccidity. Assess bilaterally and compare.",a:"B) Resistance to passive ROM",r:"Sec 8: Assessment"},
{id:405,s:"MS",t:"mc",q:"A patient with Parkinson's disease would most likely demonstrate:",o:["Fasciculations","Ataxia","Resting tremor and rigidity","Hyperactive reflexes"],c:[2],e:"Parkinson's = resting tremor (pill-rolling) + rigidity (cogwheel/lead-pipe) + bradykinesia + shuffling gait. Fasciculations = ALS. Ataxia = cerebellar. Hyperactive reflexes = UMN.",a:"C) Resting tremor and rigidity",r:"Sec 8: Involuntary Movements"},
{id:406,s:"MS",t:"mc",q:"The nurse observes a patient's gait. Expected findings include:",o:["Wide-based stance","Smooth, steady, symmetric arm swing","Limping and guarding","Shuffling with short steps"],c:[1],e:"Normal gait: smooth, steady, symmetrical, with symmetric arm swing and appropriate base of support. Abnormal: wide-based, limping, shuffling, asymmetric, guarding.",a:"B) Smooth, steady, symmetric",r:"Sec 8: Gait"},
{id:407,s:"MS",t:"mc",q:"Calcium-rich foods include all EXCEPT:",o:["Milk and yogurt","Broccoli and salmon","White bread and pasta","Legumes and egg yolks"],c:[2],e:"Ca-rich: milk, yogurt, broccoli, salmon, legumes, egg yolks, fortified foods. White bread and regular pasta are NOT significant calcium sources.",a:"C) White bread and pasta",r:"Sec 8: Bone Health Nutrition"},
{id:408,s:"MS",t:"mc",q:"Essential tremor occurs with:",o:["Rest","Intentional movement","Sleep","No specific trigger"],c:[1],e:"Essential tremor = intentional/action tremor (during purposeful movement). Resting tremor = Parkinson's. This distinction helps differentiate the two conditions.",a:"B) Intentional movement",r:"Sec 8: Tremors"},
{id:409,s:"MS",t:"mc",q:"ROM assessment of the shoulder includes all EXCEPT:",o:["Flexion/extension","Abduction/adduction","Circumduction","Dorsiflexion"],c:[3],e:"Shoulder: flexion, extension, hyperextension, abduction, adduction, circumduction, internal/external rotation. Dorsiflexion is an ANKLE movement, not shoulder.",a:"D) Dorsiflexion",r:"Sec 8: ROM — Shoulder"},
{id:410,s:"MS",t:"mc",q:"A patient reports recent falls and inability to perform ADLs. This is important for MSK assessment because:",o:["Falls are normal in elderly","It indicates the need to assess mobility, strength, and fall risk","Only orthopedic consult is needed","ADL inability is not an MSK concern"],c:[1],e:"Falls and functional decline require comprehensive MSK assessment: mobility, strength, balance, ROM, and fall risk factors. May indicate weakness, neurological changes, or environmental hazards.",a:"B) Assess mobility, strength, fall risk",r:"Sec 8: Health History"},
{id:411,s:"MS",t:"mc",q:"Pronation of the forearm means:",o:["Palm face-up","Palm face-down","Wrist flexion","Elbow extension"],c:[1],e:"Pronation = palm DOWN. Supination = palm UP. Mnemonic: PRONation = PRONE (face down).",a:"B) Palm down",r:"Sec 8: ROM — Forearm"},
{id:412,s:"MS",t:"mc",q:"Spasticity indicates which type of motor neuron lesion?",o:["Lower motor neuron","Upper motor neuron","Both","Neither"],c:[1],e:"Spasticity = upper motor neuron (stroke, MS). Velocity-dependent increased resistance to passive stretch. Lower motor neuron = flaccidity, fasciculation, atrophy.",a:"B) Upper motor neuron",r:"Sec 8: Spasticity"},
{id:413,s:"MS",t:"mc",q:"Bilateral muscle mass and symmetry should be:",o:["Always unequal in dominant side","Equal bilaterally","Greater on the left","Not assessed in MSK exam"],c:[1],e:"Compare bilateral symmetry of muscle mass. Some dominant-side hypertrophy is normal but should be mild. Significant asymmetry suggests nerve damage, disuse, or pathology.",a:"B) Equal bilaterally",r:"Sec 8: Assessment"},
{id:414,s:"MS",t:"mc",q:"Hyperextension of the neck means:",o:["Bending chin to chest","Tilting head backward beyond neutral","Side-bending the neck","Rotating the neck"],c:[1],e:"Hyperextension = extending beyond neutral/anatomical position (tilting head back). Flexion = chin to chest. Lateral flexion = ear to shoulder. Rotation = turning side to side.",a:"B) Tilting head backward",r:"Sec 8: ROM — Neck"},
{id:415,s:"MS",t:"mc",q:"A gross deformity found on MSK inspection refers to:",o:["Minor bruising","Structural abnormalities visible on inspection","Normal anatomical variants","Skin lesions"],c:[1],e:"Gross deformities = visible structural abnormalities: fractures, dislocations, severe joint changes, angular deformities. Document location, size, and effect on function.",a:"B) Visible structural abnormalities",r:"Sec 8: Assessment"},
{id:416,s:"MS",t:"tf",q:"True or False: Height loss in post-menopausal women is a normal part of aging and requires no further assessment.",o:["True","False"],c:[1],e:"False. Height loss may indicate vertebral compression fractures from osteoporosis. Assess bone density, supplement Ca/VitD, and evaluate fall risk. It warrants investigation, not dismissal.",a:"False",r:"Sec 8: Osteoporosis"},
{id:417,s:"MS",t:"mc",q:"Physical activity assessment is important in MSK history to determine:",o:["Insurance eligibility","Exercise habits, activity level, and risk for MSK injury","Only whether the patient is an athlete","Caloric intake"],c:[1],e:"Exercise and activity history helps assess MSK health, injury risk, bone density maintenance, and functional capacity. Ask about type, frequency, and intensity of physical activity.",a:"B) Exercise habits and MSK risk",r:"Sec 8: Health History"},
{id:418,s:"MS",t:"mc",q:"Scoliosis is detected by observing:",o:["Exaggerated thoracic curve","Lateral curvature with uneven shoulder/hip height","Shortened stature","Wide-based gait"],c:[1],e:"Scoliosis = lateral spine curvature. Look for uneven shoulders, uneven hips, asymmetric waistline, or rib hump when bending forward (Adam's test).",a:"B) Lateral curvature, uneven shoulders/hips",r:"Sec 8: Scoliosis"},
{id:419,s:"MS",t:"mc",q:"Circumduction is a movement that:",o:["Bends a joint","Straightens a joint","Moves a limb in a circular pattern","Rotates internally only"],c:[2],e:"Circumduction = circular movement combining flexion, extension, abduction, and adduction. Available at shoulder and hip joints (ball-and-socket joints).",a:"C) Circular pattern",r:"Sec 8: ROM"},
{id:420,s:"MS",t:"mc",q:"A tic differs from a fasciculation because a tic:",o:["Is always painful","Involves repetitive movement of a muscle group, not just twitching","Only occurs during sleep","Is caused by lower motor neuron disease"],c:[1],e:"Tic = involuntary, repetitive movement of a muscle group (grimaces, winks, shrugs). Fasciculation = continuous rapid twitching of a single muscle at rest. Tics can be neurological or psychogenic.",a:"B) Repetitive muscle group movement",r:"Sec 8: Involuntary Movements"},
{id:421,s:"MS",t:"mc",q:"Vitamin D is recommended with calcium for osteoporosis because:",o:["It tastes better together","Vitamin D supports calcium absorption","Vitamin D directly builds bone","It reduces pain from fractures"],c:[1],e:"Vitamin D enhances intestinal calcium absorption. Without adequate VitD, dietary calcium is poorly absorbed and bone density suffers. Recommended: 800 IU/day with 1000-1200 mg calcium.",a:"B) Supports calcium absorption",r:"Sec 8: Bone Health"},
{id:422,s:"MS",t:"mc",q:"The Romberg test in MSK assessment evaluates:",o:["Joint flexibility","Balance and proprioception","Muscle strength","Pain level"],c:[1],e:"Romberg = balance and proprioception assessment. Positive Romberg (swaying with eyes closed) may indicate proprioceptive deficit or cerebellar dysfunction, both relevant to fall risk.",a:"B) Balance and proprioception",r:"Sec 8: Assessment"},
{id:423,s:"MS",t:"mc",q:"Plantar flexion of the ankle means:",o:["Toes point up","Toes point down (like pressing gas pedal)","Foot turns inward","Foot turns outward"],c:[1],e:"Plantar flexion = toes DOWN (think: stepping on gas PEDAL = PLANTAR flexion). Dorsiflexion = toes up. Common terminology on exams.",a:"B) Toes down",r:"Sec 8: ROM — Ankle"},
{id:424,s:"MS",t:"mc",q:"Assessment of spinal alignment involves observing for:",o:["Only lateral curvature","Normal curvatures and any deformities","Height only","Arm length equality only"],c:[1],e:"Assess all spinal curves: cervical lordosis, thoracic kyphosis, lumbar lordosis. Look for abnormalities: excessive kyphosis, scoliosis, lordosis, or stepoffs suggesting vertebral pathology.",a:"B) Normal curves and deformities",r:"Sec 8: Alignment"},
{id:425,s:"MS",t:"mc",q:"Osteoporosis increases risk for:",o:["Joint inflammation","Fractures","Muscle spasms","Infections"],c:[1],e:"Osteoporosis = decreased bone density → fragile bones → increased fracture risk. Monitor for height loss and kyphosis development. Prevention: Ca, VitD, weight-bearing exercise.",a:"B) Fractures",r:"Sec 8: Osteoporosis"},
{id:426,s:"MS",t:"mc",q:"Eversion of the foot means:",o:["Sole turns inward","Sole turns outward","Foot points up","Foot points down"],c:[1],e:"Eversion = sole turns OUTWARD. Inversion = sole inward. Assessed at subtalar joint. Important for ankle injury assessment (most ankle sprains involve inversion).",a:"B) Sole outward",r:"Sec 8: ROM — Foot"},
{id:427,s:"MS",t:"mc",q:"Which involuntary movement is described as sudden, brief, like hiccups?",o:["Fasciculation","Tremor","Myoclonus","Spasticity"],c:[2],e:"Myoclonus = sudden, brief muscle jerk. Hiccups are a form of myoclonus (diaphragm). Also seen in seizures and sleep onset (hypnic jerks). Brief and non-rhythmic.",a:"C) Myoclonus",r:"Sec 8: Involuntary Movements"},
{id:428,s:"MS",t:"mc",q:"Radial deviation of the wrist is also called:",o:["Adduction","Abduction","Flexion","Extension"],c:[1],e:"Radial deviation = wrist abduction (thumb side). Ulnar deviation = wrist adduction (pinky side). In RA, fingers show ulnar deviation (drift toward pinky side).",a:"B) Abduction",r:"Sec 8: ROM — Wrist"},
{id:429,s:"MS",t:"mc",q:"Fasciculation at rest indicates disease of which neurons?",o:["Upper motor neurons","Lower motor neurons","Sensory neurons","Autonomic neurons"],c:[1],e:"Fasciculation = lower motor neuron disease (ALS, nerve root compression). Spontaneous, rapid twitching at rest. Upper motor neuron = spasticity, hyperreflexia, Babinski.",a:"B) Lower motor neurons",r:"Sec 8: Fasciculation"},
{id:430,s:"MS",t:"mc",q:"When assessing ROM, the nurse should compare:",o:["To a textbook standard only","Bilaterally — right vs left","To the patient's stated normal","Morning vs evening ROM"],c:[1],e:"Always compare bilaterally. Significant asymmetry suggests pathology on the limited side. Also compare to the patient's baseline if available. Document any limitations.",a:"B) Bilaterally",r:"Sec 8: ROM Assessment"},
// === GI/GU (431-465) ===
{id:431,s:"GI",t:"order",q:"Place abdominal assessment techniques in correct order.",o:["Palpation","Auscultation","Percussion","Inspection"],c:[3,1,2,0],e:"Abdomen: Inspect→Auscultate→Percuss→Palpate. Palpation LAST because it stimulates bowel activity, altering auscultation accuracy. 'I Always Palpate Properly.'",a:"Inspection→Auscultation→Percussion→Palpation",r:"Sec 9: Abdominal Order"},
{id:432,s:"GI",t:"mc",q:"Pain worsening when pressure is suddenly released is:",o:["Guarding","Rebound tenderness","Borborygmus","Referred pain"],c:[1],e:"Rebound tenderness = pain on release = peritoneal irritation/peritonitis. RED FLAG — report immediately. Guarding = muscle tensing during palpation. Both are concerning abdominal findings.",a:"B) Rebound tenderness",r:"Sec 9: Unexpected Findings"},
{id:433,s:"GI",t:"mc",q:"Dilated veins radiating from umbilicus (caput medusae) indicate:",o:["Normal vasculature","Heart failure","Liver disease or portal hypertension","Aortic aneurysm"],c:[2],e:"Caput medusae = portal hypertension/liver disease. Blood shunted from portal system through superficial veins. Named after Medusa's snake hair. Always unexpected.",a:"C) Liver disease/portal HTN",r:"Sec 9: Unexpected Findings"},
{id:434,s:"GI",t:"mc",q:"Lower abdominal pain in a female — ask FIRST:",o:["'Nausea or vomiting?'","'When was your last menstrual period?'","'Do you have fever?'","'What did you eat?'"],c:[1],e:"LMP differentiates gynecological from other causes. Pregnancy must be ruled out before diagnostic tests. Critical first question for female lower abdominal pain.",a:"B) Last menstrual period",r:"Sec 9: Female GU"},
{id:435,s:"GI",t:"mc",q:"Left testicle hanging lower than right is:",o:["Unexpected — report","Expected normal variant","Sign of varicocele","Requires ultrasound"],c:[1],e:"Left testicle lower = expected normal variant. Also expected: darker scrotal skin, slightly wrinkled scrotal skin, visible dorsal vein on penile shaft.",a:"B) Expected",r:"Sec 9: Male GU — Expected"},
{id:436,s:"GI",t:"mc",q:"Yellow urethral discharge + dysuria in a male =",o:["Syphilis","Gonorrhea","HPV","Hydrocele"],c:[1],e:"Gonorrhea: yellow discharge from meatus + burning on urination. Syphilis: painless chancre. HPV: genital warts. Always obtain sexual history and educate on safe sex.",a:"B) Gonorrhea",r:"Sec 9: STIs"},
{id:437,s:"GI",t:"mc",q:"Purple striae + central obesity + moon face + thin skin suggest:",o:["Pregnancy","Rapid weight gain","Cushing's syndrome","Liver cirrhosis"],c:[2],e:"Combined findings = Cushing's (excess cortisol). Purple striae alone can mean weight change, but the full constellation points to Cushing's specifically.",a:"C) Cushing's",r:"Sec 9: Purple Striae"},
{id:438,s:"GI",t:"mc",q:"Borborygmus is:",o:["Absent bowel sounds","Hyperactive loud bowel sounds audible without stethoscope","Normal bowel sounds","A type of hernia"],c:[1],e:"Borborygmus = loud, hyperactive bowel sounds heard without a stethoscope. Can indicate diarrhea, early obstruction, or gastroenteritis. Always auscultate before palpating abdomen.",a:"B) Hyperactive loud sounds",r:"Sec 9: Unexpected Findings"},
{id:439,s:"GI",t:"mc",q:"Guarding on abdominal palpation indicates:",o:["Normal muscle tone","Peritoneal irritation","Gas and bloating","Patient is ticklish"],c:[1],e:"Guarding = voluntary or involuntary muscle tensing during palpation = peritoneal irritation. Report immediately. Can be voluntary (anxiety) or involuntary (true peritonitis). Differentiate by approach.",a:"B) Peritoneal irritation",r:"Sec 9: Guarding"},
{id:440,s:"GI",t:"mc",q:"Varicocele feels like:",o:["A solid mass","A bag of worms","A smooth round ball","Nothing palpable"],c:[1],e:"Varicocele = dilated scrotal veins feeling like a 'bag of worms.' Hydrocele = fluid that transilluminates. These are key differentiators in scrotal assessment.",a:"B) Bag of worms",r:"Sec 9: Male GU"},
{id:441,s:"GI",t:"mc",q:"Hydrocele is differentiated from other scrotal masses by:",o:["Pain level","Transillumination with a light source","Size measurement","Color change"],c:[1],e:"Hydrocele = fluid accumulation in scrotum that TRANSILLUMINATES (light passes through fluid). Solid masses do not transilluminate. Key diagnostic technique.",a:"B) Transillumination",r:"Sec 9: Male GU — Hydrocele"},
{id:442,s:"GI",t:"mc",q:"A rash on the abdomen may indicate:",o:["Normal finding","Allergic reaction or dermatological condition","Liver disease","Heart failure"],c:[1],e:"Abdominal rash: allergic reaction (contact dermatitis, drug reaction) or dermatological condition. Assess distribution, characteristics, and timing with new medications/exposures.",a:"B) Allergy or dermatological condition",r:"Sec 9: Unexpected Findings"},
{id:443,s:"GI",t:"mc",q:"Palpation is performed LAST in abdominal assessment because:",o:["It is the most uncomfortable for the patient","It stimulates bowel activity and alters auscultation accuracy","It requires the most skill","The provider prefers this order"],c:[1],e:"Palpation stimulates peristalsis, changing bowel sounds and making auscultation inaccurate. Auscultate FIRST to get baseline bowel sounds before disturbing them.",a:"B) Stimulates bowel activity",r:"Sec 9: Abdominal Order"},
{id:444,s:"GI",t:"mc",q:"Phimosis in an adult male is:",o:["Expected finding","Unretractable or narrowed foreskin — unexpected","Normal if uncircumcised","Sign of STI"],c:[1],e:"Phimosis = unretractable foreskin or narrowed opening in ADULTS = unexpected. It can cause difficulty with hygiene and urination. May require medical/surgical intervention.",a:"B) Unexpected",r:"Sec 9: Male GU"},
{id:445,s:"GI",t:"mc",q:"Expected testicular findings include:",o:["3.5 cm diameter, oval, firm, equal bilaterally","Variable sizes bilaterally","Soft and irregular texture","10 cm diameter"],c:[0],e:"Normal testes: 3.5 cm diameter, oval-shaped, firm, same size bilaterally. Asymmetry in size, shape, or texture requires further evaluation.",a:"A) 3.5 cm, oval, firm, equal",r:"Sec 9: Male GU — Expected"},
{id:446,s:"GI",t:"mc",q:"Syphilis initially presents as:",o:["Yellow discharge with dysuria","Small painless ulcer (chancre)","Genital warts","Vesicular lesions"],c:[1],e:"Primary syphilis: small, PAINLESS ulcer (chancre) on genitals. Key word = painless. Can progress to ulcerated area with yellow serous discharge. Gonorrhea has painful discharge.",a:"B) Painless chancre",r:"Sec 9: STIs — Syphilis"},
{id:447,s:"GI",t:"mc",q:"UTI symptoms include:",o:["Painless urination","Dysuria, frequency, urgency, suprapubic pain","Hematuria only","No symptoms in most cases"],c:[1],e:"UTI: dysuria (burning), frequency, urgency, suprapubic pain. May also have cloudy/foul-smelling urine and hematuria. More common in females due to shorter urethra.",a:"B) Dysuria, frequency, urgency, suprapubic pain",r:"Sec 9: UTI"},
{id:448,s:"GI",t:"mc",q:"Post-menopausal women: which findings are EXPECTED?",o:["Dense pubic hair and moist vaginal membranes","Sparse pubic hair, mons pubis atrophy, dry vaginal membranes","Bleeding from nipple","Abdominal distension"],c:[1],e:"Menopause: sparse pubic hair, mons pubis atrophy, dry vaginal membranes = expected changes from decreased estrogen. Document and compare to baseline.",a:"B) Sparse hair, atrophy, dry membranes",r:"Sec 9: Female GU — Menopause"},
{id:449,s:"GI",t:"mc",q:"Rebound tenderness is a sign of:",o:["Constipation","Peritonitis","Normal bowel function","Gastritis"],c:[1],e:"Rebound tenderness = pain worsening on pressure RELEASE = peritonitis. RED FLAG — notify HCP immediately. Associated with appendicitis, perforated bowel, abdominal trauma.",a:"B) Peritonitis",r:"Sec 9: Rebound Tenderness"},
{id:450,s:"GI",t:"mc",q:"The meatus located on the dorsal (top) surface of the glans is called:",o:["Normal position","Hypospadias","Epispadias","Phimosis"],c:[2],e:"Epispadias = meatus on dorsal (top) surface. Hypospadias = meatus on ventral (bottom) surface. Both are congenital malpositions. Normal meatus is at the tip of the glans.",a:"C) Epispadias",r:"Sec 9: Male GU"},
{id:451,s:"GI",t:"mc",q:"HPV can progress to:",o:["Kidney disease","Cancer","Infertility only","Blindness"],c:[1],e:"HPV (genital warts) can progress to cancer (cervical, anal, oropharyngeal). Vaccine recommended at age 12. Early vaccination provides best protection.",a:"B) Cancer",r:"Sec 9: STIs — HPV"},
{id:452,s:"GI",t:"mc",q:"Unexpected breast findings in females include all EXCEPT:",o:["New nipple inversion","Bleeding from nipple","Excoriation under breast","Nipple inversion present since puberty"],c:[3],e:"Nipple inversion since puberty = expected variation. NEW inversion, bleeding, and excoriation are all unexpected findings requiring evaluation.",a:"D) Since puberty = expected",r:"Sec 9: Female GU — Breast"},
{id:453,s:"GI",t:"mc",q:"Abdominal rigidity (board-like abdomen) is a sign of:",o:["Normal abdominal tone","Serious peritoneal irritation — report immediately","Constipation","Mild gastritis"],c:[1],e:"Abdominal rigidity = involuntary board-like abdomen = serious peritoneal irritation. RED FLAG requiring immediate HCP notification. May indicate peritonitis, perforation, or intra-abdominal hemorrhage.",a:"B) Serious peritoneal irritation",r:"Sec 9: RED FLAG"},
{id:454,s:"GI",t:"tf",q:"True or False: Palpation should be performed before auscultation during abdominal assessment.",o:["True","False"],c:[1],e:"False. In abdominal assessment: Inspect→Auscultate→Percuss→Palpate. Palpation LAST to avoid altering bowel sounds. This is the critical exception to standard assessment order.",a:"False",r:"Sec 9: Abdominal Order"},
{id:455,s:"GI",t:"mc",q:"PSA test: patient must refrain from ejaculation for:",o:["24 hours","48 hours","72 hours","1 week"],c:[1],e:"48 hours before PSA test. Ejaculation can falsely elevate PSA. Also elevated in cancer, infection, and BPH. Important patient teaching before the test.",a:"B) 48 hours",r:"Sec 9 + Sec 3: PSA"},
{id:456,s:"GI",t:"mc",q:"Scrotal skin being darker than the rest of the body is:",o:["Sign of infection","Expected normal finding","Jaundice","Requires biopsy"],c:[1],e:"Darker scrotal skin = expected. Other normals: left testicle lower, slightly wrinkled skin, visible dorsal penile vein. Know expected vs unexpected for male GU assessment.",a:"B) Expected",r:"Sec 9: Male GU — Expected"},
{id:457,s:"GI",t:"mc",q:"A painless scrotal mass that transilluminates is most likely:",o:["Varicocele","Hydrocele","Testicular cancer","Inguinal hernia"],c:[1],e:"Hydrocele = fluid = transilluminates. Varicocele = 'bag of worms.' Testicular cancer = solid, doesn't transilluminate. Transillumination is the key differentiator.",a:"B) Hydrocele",r:"Sec 9: Hydrocele"},
{id:458,s:"GI",t:"mc",q:"Purple striae on the abdomen alone (without other Cushing's signs) may indicate:",o:["Only Cushing's syndrome","Recent weight gain/loss or abdominal distension","Liver disease","Allergic reaction"],c:[1],e:"Purple striae alone can indicate recent weight change or distension. With central obesity + moon face + thin skin = Cushing's. Context determines the interpretation.",a:"B) Weight change or distension",r:"Sec 9: Purple Striae"},
{id:459,s:"GI",t:"mc",q:"Positive rebound tenderness in the right lower quadrant is classically associated with:",o:["Gastritis","Appendicitis","Cholecystitis","Pancreatitis"],c:[1],e:"RLQ rebound tenderness = classic appendicitis (McBurney's point). Peritoneal signs indicate possible rupture risk. Surgical emergency. LLQ = diverticulitis. RUQ = cholecystitis.",a:"B) Appendicitis",r:"Sec 9: Rebound Tenderness"},
{id:460,s:"GI",t:"mc",q:"Discharge from one nare only in a child most likely indicates:",o:["Allergies","URI","Foreign body in the nose","CSF leak"],c:[2],e:"Unilateral discharge from ONE nare, especially in children = foreign body until proven otherwise. Bilateral = infection or allergies. Unilateral watery post-trauma = CSF leak.",a:"C) Foreign body",r:"Sec 9 + Sec 4: Nose"},
{id:461,s:"GI",t:"mc",q:"Gonorrhea differs from syphilis because gonorrhea presents with:",o:["Painless ulcer","Yellow discharge and painful urination","Genital warts","No symptoms"],c:[1],e:"Gonorrhea: PAINFUL — yellow discharge + dysuria. Syphilis: PAINLESS chancre initially. The pain distinction is the key differentiator for these two STIs.",a:"B) Yellow discharge + dysuria",r:"Sec 9: STIs"},
{id:462,s:"GI",t:"mc",q:"Breast self-exam in post-menopausal women should be performed:",o:["4-7 days after menstruation","Same day every month","Not recommended after menopause","Only annually by provider"],c:[1],e:"Post-menopausal women: same day every month (no menstrual cycle to reference). Choose an easy-to-remember date. Pre-menopausal: 4-7 days after onset of period.",a:"B) Same day every month",r:"Sec 9: Female GU"},
{id:463,s:"GI",t:"mc",q:"Excoriation under the breast is:",o:["Normal moisture","An unexpected finding requiring assessment","Always from underwire bra","Expected in elderly"],c:[1],e:"Excoriation under breast = unexpected. May indicate fungal infection (intertriginous candidiasis), contact dermatitis, or poor hygiene. Assess, document, and report.",a:"B) Unexpected — assess",r:"Sec 9: Female GU — Breast"},
{id:464,s:"GI",t:"mc",q:"Hypospadias refers to the urethral meatus located on the:",o:["Dorsal (top) surface of glans","Ventral (bottom) surface of glans","Tip of the glans (normal)","Shaft of the penis"],c:[1],e:"Hypospadias = ventral (undersurface). Epispadias = dorsal (top surface). Both are congenital. Normal = tip of glans. These are commonly tested anatomical terms.",a:"B) Ventral surface",r:"Sec 9: Male GU"},
{id:465,s:"GI",t:"mc",q:"Annual pelvic exam is recommended for:",o:["All women regardless of sexual activity","Sexually active females","Only women over 50","Only women with symptoms"],c:[1],e:"Annual pelvic exam for sexually active females. Pap smear every 3 years. The pelvic exam screens for gynecological abnormalities beyond what the Pap smear detects.",a:"B) Sexually active females",r:"Sec 9: Female GU"},
// === INTEGUMENTARY (466-500) ===
{id:466,s:"IN",t:"mc",q:"A flat, nonpalpable, <1 cm color change on skin (e.g., freckle) is a:",o:["Papule","Macule","Vesicle","Wheal"],c:[1],e:"Macule = flat, nonpalpable, <1 cm, color change only. Examples: freckles, petechiae. Papule = raised. Vesicle = fluid-filled. Wheal = irregularly shaped hive.",a:"B) Macule",r:"Sec 10: Lesion Terminology"},
{id:467,s:"IN",t:"mc",q:"Mole meeting ABCDE criteria — nurse should:",o:["Reassess in 6 months","Apply sunscreen","Report to HCP for dermatology referral","Document as benign"],c:[2],e:"ABCDE criteria (Asymmetry, Border, Color, Diameter >6mm, Evolving) = RED FLAG for melanoma. Immediate referral to dermatology. Never delay assessment.",a:"C) Report for referral",r:"Sec 10: ABCDE"},
{id:468,s:"IN",t:"mc",q:"Skin tenting indicates:",o:["Normal turgor","Dehydration","Fluid overload","Scleroderma"],c:[1],e:"Tenting = skin stays elevated after pinching = dehydration. Normal: skin snaps back immediately. Test forearm or sternum. In elderly, sternum is more reliable.",a:"B) Dehydration",r:"Sec 10: Turgor"},
{id:469,s:"IN",t:"mc",q:"Clubbing (nail angle >180°, spongy nail beds) indicates:",o:["Liver disease","Iron deficiency","Chronic hypoxia","Normal aging"],c:[2],e:"Clubbing = chronic hypoxia (COPD, cyanotic heart disease). Develops over time. Always unexpected. Yellowed nails = expected aging. Clubbing ≠ yellowing.",a:"C) Chronic hypoxia",r:"Sec 10: Clubbing"},
{id:470,s:"IN",t:"mc",q:"Pitting edema 4mm indent, 15-sec recovery is approximately Grade:",o:["1","2","3","4"],c:[1],e:"Grade 1: 2mm, rapid. Grade 2: 4mm, 10-15 sec. Grade 3: 6mm, >1 min. Grade 4: 8mm+, 2+ min. 4mm with 15-sec = Grade 2. Document location and bilateral vs unilateral.",a:"B) Grade 2",r:"Sec 10: Pitting Edema"},
{id:471,s:"IN",t:"mc",q:"Vesicular lesions along a dermatome suggest:",o:["Insect bites","Shingles (herpes zoster) — report and isolate","Contact dermatitis","Eczema"],c:[1],e:"Dermatomal vesicles = shingles. RED FLAG — report to HCP and isolate patient to prevent varicella-zoster transmission to immunocompromised and pregnant individuals.",a:"B) Shingles — isolate",r:"Sec 10: Vesicle + RED FLAG"},
{id:472,s:"IN",t:"mc",q:"Normal capillary refill is:",o:["<2 seconds","<5 seconds","<10 seconds","3-5 seconds"],c:[0],e:"Normal: <2 seconds. Press nail bed until white, release → pink returns in <2 sec. Delayed = poor peripheral perfusion (dehydration, shock, PVD, hypothermia).",a:"A) <2 seconds",r:"Sec 10: Capillary Refill"},
{id:473,s:"IN",t:"mc",q:"Petechiae (tiny reddish-purple spots) require reporting because they may indicate:",o:["Normal finding","Bleeding disorder or meningitis","Allergic reaction","Dehydration"],c:[1],e:"Petechiae = tiny hemorrhages under skin. May indicate bleeding disorder (thrombocytopenia), DIC, or meningococcal meningitis. Always report to HCP.",a:"B) Bleeding disorder or meningitis",r:"Sec 10: Petechiae"},
{id:474,s:"IN",t:"mc",q:"A papule is:",o:["Flat color change","Small, solid, raised area <1 cm","Large fluid-filled blister","Irregularly shaped hive"],c:[1],e:"Papule = small, solid, RAISED, <1 cm from thickened epidermis. Examples: warts, moles. Larger version (>1 cm) = nodule. Even larger (>2 cm) = tumor.",a:"B) Small, solid, raised <1 cm",r:"Sec 10: Lesion Terminology"},
{id:475,s:"IN",t:"mc",q:"A wheal (hive) is caused by:",o:["Trauma","Allergic reactions or insect bites","Viral infection","Bacterial infection"],c:[1],e:"Wheal = superficial, raised, irregularly shaped area from allergic reaction or insect bites. Associated with histamine release. Urticaria = multiple wheals.",a:"B) Allergic reaction or insect bites",r:"Sec 10: Wheal"},
{id:476,s:"IN",t:"mc",q:"A vesicle is a fluid-filled raised lesion <1 cm. A bulla is:",o:["Solid lesion >1 cm","Fluid-filled blister >1 cm","Flat color change >1 cm","Pus-filled lesion"],c:[1],e:"Bulla = large fluid-filled blister >1 cm (e.g., second-degree burns). Vesicle = small fluid-filled <1 cm (chickenpox, shingles). Size distinguishes them.",a:"B) Fluid-filled >1 cm",r:"Sec 10: Bulla"},
{id:477,s:"IN",t:"mc",q:"A pustule contains:",o:["Clear serous fluid","Blood","Pus","Air"],c:[2],e:"Pustule = fluid-filled lesion containing PUS (e.g., acne, infected follicle). Vesicle = clear serous fluid. Ecchymosis = blood under skin. Different fluid contents have different implications.",a:"C) Pus",r:"Sec 10: Pustule"},
{id:478,s:"IN",t:"mc",q:"Atrophy of the skin in elderly is caused by:",o:["Excess collagen","Loss of collagen","Increased melanin","Dehydration"],c:[1],e:"Skin atrophy = thinning from loss of collagen. Common in elderly. Makes skin fragile, prone to tears and bruising. Handle elderly skin gently during assessment and care.",a:"B) Loss of collagen",r:"Sec 10: Atrophy"},
{id:479,s:"IN",t:"mc",q:"Ecchymosis is:",o:["Tiny red spots","Large bruise/discoloration from blood under skin","Raised red area","White scaly patch"],c:[1],e:"Ecchymosis = large bruise from blood leaking under skin. Different from petechiae (tiny spots). Multiple ecchymoses may indicate coagulation disorder, trauma, or abuse.",a:"B) Large bruise",r:"Sec 10: Ecchymosis"},
{id:480,s:"IN",t:"mc",q:"Erythema is:",o:["Bluish discoloration","Yellow discoloration","Redness from dilated capillaries","White patches"],c:[2],e:"Erythema = redness from dilation of superficial capillaries. Causes: inflammation, infection, sunburn, allergic reaction. Assess extent and associated symptoms.",a:"C) Redness",r:"Sec 10: Erythema"},
{id:481,s:"IN",t:"mc",q:"Jaundice causes yellow discoloration of:",o:["Only the sclera","Skin and sclera","Only the skin","Only the palms"],c:[1],e:"Jaundice: yellow skin AND sclera from elevated bilirubin (liver dysfunction). Also check hard palate. Sclera often shows yellowing first due to high elastin content.",a:"B) Skin and sclera",r:"Sec 10: Jaundice"},
{id:482,s:"IN",t:"mc",q:"Pressure ulcer Stage I is:",o:["Non-blanchable redness of intact skin","Partial thickness skin loss","Full thickness skin loss","Bone/muscle exposed"],c:[0],e:"Stage I: non-blanchable erythema, intact skin. Stage II: partial thickness. Stage III: full thickness. Stage IV: bone/muscle exposed. Unstageable: covered by eschar.",a:"A) Non-blanchable redness",r:"Sec 10: Pressure Ulcers"},
{id:483,s:"IN",t:"mc",q:"Stage IV pressure ulcer involves:",o:["Redness only","Partial skin loss","Full thickness loss","Bone or muscle exposed"],c:[3],e:"Stage IV: bone/muscle/tendon exposed. Most severe stage. High infection risk. Requires wound care specialist. Stage III = full thickness (fat visible). Stage IV = deeper structures.",a:"D) Bone/muscle exposed",r:"Sec 10: Pressure Ulcers"},
{id:484,s:"IN",t:"mc",q:"Skin tears are most common in:",o:["Young athletes","Elderly patients with fragile skin","Infants","Middle-aged adults"],c:[1],e:"Skin tears from shear/friction forces = common in elderly due to skin atrophy and collagen loss. Use gentle handling, padded tape, and moisturizers for prevention.",a:"B) Elderly with fragile skin",r:"Sec 10: Skin Tears"},
{id:485,s:"IN",t:"mc",q:"ABCDE stands for:",o:["Airway, Breathing, Circulation, Disability, Exposure","Asymmetry, Border, Color, Diameter (>6mm), Evolving","Assessment, Baseline, Comparison, Documentation, Evaluation","Acute, Bilateral, Chronic, Diffuse, External"],c:[1],e:"ABCDE for skin cancer: Asymmetry, Border (irregular), Color (variation), Diameter (>6mm/pencil eraser), Evolving (any change). Any positive criteria = referral to dermatology.",a:"B) Asymmetry, Border, Color, Diameter, Evolving",r:"Sec 10: ABCDE"},
{id:486,s:"IN",t:"mc",q:"Yellowed nails in a 78-year-old are:",o:["Sign of liver disease","Sign of chronic hypoxia","Expected finding in older adults","Sign of fungal infection"],c:[2],e:"Yellowed nails = expected in older adults. Different from clubbing (chronic hypoxia). Jaundice affects skin/sclera, not typically just nails. Document but no concern needed.",a:"C) Expected in older adults",r:"Sec 10: Nail Assessment"},
{id:487,s:"IN",t:"mc",q:"Alopecia refers to:",o:["Excessive hair growth","Areas of hair loss","Coarse facial hair in females","Normal hair distribution"],c:[1],e:"Alopecia = areas of hair loss. Can be from medical conditions (alopecia areata, thyroid disease), medications (chemotherapy), stress, or traction. Document and assess cause.",a:"B) Hair loss",r:"Sec 10: Hair Assessment"},
{id:488,s:"IN",t:"mc",q:"Normal nails should be:",o:["Rounded and spongy","Smooth, firm, pink, without clubbing","Yellow and thick","Ridged and brittle"],c:[1],e:"Normal nails: smooth, firm, pink, no clubbing. Spongy/rounded = clubbing (chronic hypoxia). Yellowed = may be normal aging. Ridged/brittle = nutritional deficiency or disease.",a:"B) Smooth, firm, pink",r:"Sec 10: Nail Assessment"},
{id:489,s:"IN",t:"mc",q:"A nodule differs from a papule by being:",o:["Flat instead of raised","Larger (>1 cm) and extending into dermis","Fluid-filled","Always malignant"],c:[1],e:"Nodule: larger (>1 cm), firmer papule extending into dermis. Examples: larger warts, cysts. Papule: <1 cm, raised. Size and depth differentiate them.",a:"B) Larger, extends into dermis",r:"Sec 10: Nodule"},
{id:490,s:"IN",t:"mc",q:"A tumor in skin assessment terminology is:",o:["Always cancerous","A solid mass >2 cm","Any abnormal growth","A fluid-filled cavity"],c:[1],e:"In dermatologic terminology, tumor = solid mass >2 cm. It does NOT automatically mean cancer — it's a SIZE descriptor. Can be benign or malignant. Requires evaluation.",a:"B) Solid mass >2 cm",r:"Sec 10: Tumor"},
{id:491,s:"IN",t:"mc",q:"Cyanosis indicates:",o:["Jaundice","Hypoxia or poor perfusion","Infection","Anemia"],c:[1],e:"Cyanosis = blue/gray skin from deoxygenated hemoglobin = hypoxia or poor perfusion. Late sign of respiratory/circulatory compromise. In dark skin, assess oral mucosa.",a:"B) Hypoxia or poor perfusion",r:"Sec 10: Cyanosis"},
{id:492,s:"IN",t:"mc",q:"Unstageable pressure ulcer is one covered by:",o:["New epithelial tissue","Eschar (dead tissue)","Transparent membrane","Pink granulation tissue"],c:[1],e:"Unstageable: wound bed covered by eschar or slough — cannot determine depth/stage until debrided. Must remove dead tissue to accurately stage the wound.",a:"B) Eschar",r:"Sec 10: Pressure Ulcers"},
{id:493,s:"IN",t:"mc",q:"Grade 4 pitting edema has an indentation of:",o:["2 mm","4 mm","6 mm","8 mm+ with 2+ min recovery"],c:[3],e:"Grade 4: very deep (8mm+) with >2 min recovery. Severe edema requiring investigation of cause (HF, renal failure, liver disease, venous insufficiency).",a:"D) 8mm+, >2 min",r:"Sec 10: Pitting Edema"},
{id:494,s:"IN",t:"mc",q:"Pressure ulcer Stage II involves:",o:["Non-blanchable redness","Partial thickness skin loss","Full thickness to subcutaneous tissue","Exposed bone"],c:[1],e:"Stage II: partial thickness skin loss — may present as shallow open ulcer with red/pink wound bed or as intact/ruptured blister. Epidermis and part of dermis damaged.",a:"B) Partial thickness",r:"Sec 10: Pressure Ulcers"},
{id:495,s:"IN",t:"mc",q:"Hair should normally be:",o:["Absent in adults","Evenly distributed, clean, no unexplained alopecia","Present only on the head","Coarse everywhere"],c:[1],e:"Normal hair: evenly distributed, clean, no areas of unexplained hair loss. Head lice = white nits firmly attached. Hirsutism in females = endocrine concern.",a:"B) Evenly distributed, clean",r:"Sec 10: Hair Assessment"},
{id:496,s:"IN",t:"mc",q:"The sternum is a more reliable site for turgor testing in elderly because:",o:["It's easier to reach","Skin on the forearm may tent normally due to lost elasticity","It's more painful and accurate","The sternum has thicker skin"],c:[1],e:"Elderly skin loses elasticity — forearm skin may tent normally even without dehydration. The sternum retains more turgor accuracy in this population. Always consider patient age.",a:"B) Forearm may tent normally in elderly",r:"Sec 10: Turgor"},
{id:497,s:"IN",t:"mc",q:"Chickenpox and shingles are associated with which skin lesion type?",o:["Macule","Papule","Vesicle","Wheal"],c:[2],e:"Vesicle = small serous fluid-filled lesion <1 cm. Both chickenpox and shingles produce vesicular lesions. Shingles follows a dermatome pattern. Report and isolate.",a:"C) Vesicle",r:"Sec 10: Vesicle"},
{id:498,s:"IN",t:"mc",q:"Diameter >6 mm in the ABCDE criteria is approximately the size of a:",o:["Dime","Quarter","Pencil eraser","Thumbnail"],c:[2],e:"6 mm ≈ pencil eraser. Any mole larger than this + other ABCDE criteria = dermatology referral for melanoma screening. Easy visual reference for patients during self-checks.",a:"C) Pencil eraser",r:"Sec 10: ABCDE — Diameter"},
{id:499,s:"IN",t:"mc",q:"Delayed capillary refill (>2 seconds) may indicate all EXCEPT:",o:["Dehydration","Shock","Peripheral vascular disease","Excellent perfusion"],c:[3],e:"Delayed refill: dehydration, shock, PVD, hypothermia. It indicates POOR perfusion, not excellent. Quick, inexpensive bedside assessment of circulatory status.",a:"D) Excellent perfusion",r:"Sec 10: Capillary Refill"},
{id:500,s:"IN",t:"mc",q:"The 'Evolving' criterion in ABCDE refers to:",o:["The mole has been present since birth","Any change in size, shape, color, or new symptom","The mole is symmetrical","The border is smooth"],c:[1],e:"Evolving = any change over time: size, shape, color, or new symptoms (bleeding, itching, crusting). Even a previously stable lesion that begins changing warrants evaluation. Patient self-monitoring is key.",a:"B) Any change in size, shape, color, or symptoms",r:"Sec 10: ABCDE — Evolving"},
];

